import * as Sentry from '@sentry/node';
import { loadEnv } from '@addis/shared';

loadEnv();

// Only init Sentry if DSN is present — typecheck with exactOptionalPropertyTypes
// requires `dsn: string` (not `string | undefined`), so we branch. The same
// applies to `environment`.
if (process.env.SENTRY_DSN) {
  const sentryOpts: Sentry.NodeOptions = {
    dsn: process.env.SENTRY_DSN,
    tracesSampleRate: 0.1,
    sendDefaultPii: false,
    beforeSend(event) {
      return scrubEvent(event as unknown as Record<string, unknown>) as unknown as typeof event;
    },
  };
  if (process.env.NODE_ENV) sentryOpts.environment = process.env.NODE_ENV;
  Sentry.init(sentryOpts);
}

const PII_KEY_RE = /phone|email|password|token/i;

function scrubValue(value: unknown): unknown {
  if (value == null) return value;
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(scrubValue);
  if (typeof value === 'object') {
    const out: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
      if (PII_KEY_RE.test(k)) {
        out[k] = '[REDACTED]';
      } else {
        out[k] = scrubValue(v);
      }
    }
    return out;
  }
  return value;
}

function scrubEvent(event: Record<string, unknown>): Record<string, unknown> | null {
  if (!event || typeof event !== 'object') return event as Record<string, unknown> | null;

  const request = (event.request ?? {}) as Record<string, unknown>;
  if (request.headers && typeof request.headers === 'object') {
    delete (request.headers as Record<string, unknown>).authorization;
    delete (request.headers as Record<string, unknown>).cookie;
  }
  delete request.cookies;
  delete request.body;
  event.request = request;

  for (const key of Object.keys(event)) {
    if (key === 'request') continue;
    event[key] = scrubValue(event[key]);
  }
  return event;
}

import { emailProvider } from '@addis/email';
import { eq } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { notificationLogHelper } from '../lib/notification-log';

export async function handle(
  payload: { userId: string; subject: string; body: string; to?: string; html?: string },
  evt?: typeof schema.outboxEvents.$inferSelect,
) {
  if (evt?.id && await notificationLogHelper.alreadySent(evt.id, 'email')) {
    return;
  }
  let to = payload.to;
  if (!to) {
    const [user] = await db.select({ email: schema.users.email }).from(schema.users).where(eq(schema.users.id, payload.userId) as any);
    if (!user?.email) throw new Error(`User ${payload.userId} has no email address on file`);
    to = user.email;
  }

  const ok = await emailProvider.send({ to, subject: payload.subject, body: payload.body, html: payload.html } as any);
  if (!ok) throw new Error(`Email delivery failed for ${to}`);

  if (evt?.id) {
    try { await notificationLogHelper.recordSent(evt.id, 'email', to); }
    catch (err) { console.error('[email-outbox] recordSent failed (duplicate risk):', (err as Error).message); }
  }
}

import { eq } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { notificationLogHelper } from '../lib/notification-log';

interface ExpoPushTicket {
  status: 'ok' | 'error';
  id?: string;
  message?: string;
  details?: { error?: string };
}

export async function handle(
  payload: { userId: string; title: string; body: string; link?: string },
  evt?: typeof schema.outboxEvents.$inferSelect,
) {

  if (evt?.id && await notificationLogHelper.alreadySent(evt.id, 'push')) {
    return;
  }
  const devices = await db.select().from(schema.devices).where(eq(schema.devices.userId, payload.userId) as any);
  const expoTokens = devices.filter(d => d.platform !== 'web').map(d => d.pushToken);
  if (!expoTokens.length) return;

  const headers: Record<string, string> = { 'Content-Type': 'application/json' };

  const accessToken = process.env.EXPO_ACCESS_TOKEN;
  if (accessToken) {
    headers['Authorization'] = `Bearer ${accessToken}`;
  } else if (process.env.NODE_ENV === 'production') {
    console.warn('[push-outbox] EXPO_ACCESS_TOKEN is unset in production — Expo will rate-limit unauthenticated push');
  }

  const messages = expoTokens.map(to => ({ to, title: payload.title, body: payload.body, data: { link: payload.link } }));
  const response = await fetch('https://exp.host/--/api/v2/push/send', {
    method: 'POST',
    headers,
    body: JSON.stringify(messages),
  });

  if (!response.ok) {
    let errorBody: unknown;
    try { errorBody = await response.text(); } catch {  }
    const err = new Error(
      `Expo push HTTP ${response.status} ${response.statusText}: ${typeof errorBody === 'string' ? errorBody.slice(0, 500) : JSON.stringify(errorBody)}`,
    );
    throw err;
  }

  let tickets: ExpoPushTicket[];
  try {
    tickets = (await response.json()) as ExpoPushTicket[];
  } catch (err) {
    throw new Error(`Expo push returned non-JSON body: ${(err as Error).message}`);
  }

  if (!Array.isArray(tickets)) {

    const maybe = tickets as unknown as { data?: ExpoPushTicket[] };
    if (maybe?.data && Array.isArray(maybe.data)) {
      tickets = maybe.data;
    } else {
      tickets = [tickets as unknown as ExpoPushTicket];
    }
  }

  const failures = tickets
    .map((t, i) => ({ index: i, ticket: t }))
    .filter(({ ticket }) => ticket.status !== 'ok');

  if (failures.length > 0) {
    const details = failures.map(f => {
      const msg = messages[f.index];
      return `ticket[${f.index}] to=${msg?.to ?? 'unknown'} error=${f.ticket.details?.error ?? f.ticket.message ?? 'unknown'}`;
    }).join('; ');
    throw new Error(`Expo push partial failure (${failures.length}/${tickets.length}): ${details}`);
  }

  if (evt?.id && expoTokens.length > 0) {
    try { await notificationLogHelper.recordSent(evt.id, 'push', expoTokens.join(',')); }
    catch (err) { console.error('[push-outbox] recordSent failed (duplicate risk):', (err as Error).message); }
  }

}

import { sql } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { writeAudit } from '@addis/api/modules/admin/audit';

type OutboxEvent = typeof schema.outboxEvents.$inferSelect;

interface AuditPayload {
  action: string;
  actorId?: string | null;
  entityType?: string;
  entityId?: string | null;
  before?: unknown;
  after?: unknown;
  ipAddress?: string | null;
  userAgent?: string | null;
  [k: string]: unknown;
}

export async function handle(payload: AuditPayload, evt?: OutboxEvent) {

  const outboxEventId = evt?.id;
  if (outboxEventId) {
    const existing = await db.execute(sql`
      SELECT 1 FROM audit_logs
      WHERE after @> ${JSON.stringify({ outboxEventId })}::jsonb
      LIMIT 1
    ` as any);
    const rows = existing as unknown as Array<{ '?column?'?: number }>;
    if (Array.isArray(rows) && rows.length > 0) {
      if (process.env.NODE_ENV !== 'test') {
        console.log(`[audit-outbox] skipping duplicate delivery for outboxEventId=${outboxEventId}`);
      }
      return;
    }
  }

  await db.transaction(async (tx) => {
    // exactOptionalPropertyTypes: build the entry conditionally so undefined
    // fields are omitted rather than passed as `undefined`.
    const entry: Parameters<typeof writeAudit>[1] = {
      actorId: payload.actorId ?? null,
      action: payload.action,
      entityType: payload.entityType ?? 'outbox',
      before: payload.before,
      after: { ...(payload.after as Record<string, unknown> | undefined), outboxEventId },
    };
    if (payload.entityId) entry.entityId = payload.entityId;
    if (payload.ipAddress) entry.ipAddress = payload.ipAddress;
    if (payload.userAgent) entry.userAgent = payload.userAgent;
    await writeAudit(tx as unknown as typeof db, entry);
  });

  if (process.env.NODE_ENV !== 'test') {
    console.log(`[audit-outbox] ${payload.action} entityId=${payload.entityId ?? '-'} outboxEventId=${outboxEventId ?? '-'}`);
  }
}

import { smsProvider } from '@addis/sms';
import { eq } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { notificationLogHelper } from '../lib/notification-log';

export async function handle(
  payload: { userId?: string; phone?: string; body: string },
  evt?: typeof schema.outboxEvents.$inferSelect,
) {
  if (evt?.id && await notificationLogHelper.alreadySent(evt.id, 'sms')) {
    return;
  }
  let phone = payload.phone;
  if (!phone && payload.userId) {
    const [u] = await db.select({ phone: schema.users.phone }).from(schema.users).where(eq(schema.users.id, payload.userId) as any);
    phone = u?.phone;
  }
  if (phone) {
    await smsProvider.send(phone, payload.body);

    if (evt?.id) {
      try { await notificationLogHelper.recordSent(evt.id, 'sms', phone); }
      catch (err) { console.error('[sms-outbox] recordSent failed (duplicate risk):', (err as Error).message); }
    }
  }
}

import { engagementService } from '@addis/api/modules/engagement/service';
import { schema } from '@addis/db';

export async function handle(
  payload: { type: string; userId: string; [k: string]: unknown },
  _evt?: typeof schema.outboxEvents.$inferSelect,
) {
  await engagementService.dispatch({
    userId: payload.userId,
    type: payload.type as any,

    data: payload,
  } as any);
}

import { eq } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { s3 } from '@addis/api/infra/s3';
import { fileTypeFromBuffer } from 'file-type';

export async function handle(
  payload: { kind: string; storageKey?: string; [k: string]: unknown },
  _evt?: typeof schema.outboxEvents.$inferSelect,
) {
  switch (payload.kind) {
    case 'clamav_scan': {
      if (!payload.storageKey) throw new Error('clamav_scan payload missing storageKey');

      const [doc] = await db.select().from(schema.contractorDocuments)
        .where(eq(schema.contractorDocuments.storageKey, payload.storageKey));
      if (!doc) {

        return;
      }

      const buffer = await s3.getObject(payload.storageKey);
      if (!buffer) throw new Error(`S3 object not found: ${payload.storageKey}`);

      const sniffed = await fileTypeFromBuffer(buffer);
      if (!sniffed) {

        console.log(`[webhook-outbox] clamav_scan: unknown file type for ${payload.storageKey}`);
        return;
      }

      if (doc.mimeType !== sniffed.mime) {

        await db.update(schema.contractorDocuments)
          .set({ originalFilename: `[SUSPICIOUS: declared ${doc.mimeType}, detected ${sniffed.mime}] ${doc.originalFilename}` })
          .where(eq(schema.contractorDocuments.id, doc.id));
        throw new Error(`MIME mismatch for ${payload.storageKey}: declared=${doc.mimeType} sniffed=${sniffed.mime}`);
      }
      return;
    }
    default:
      throw new Error(`Unknown webhook kind: ${payload.kind}`);
  }
}

import './instrumentation';
import { loadEnv } from '@addis/shared';
import { db, schema } from '@addis/db';
import { eq, sql, count } from 'drizzle-orm';
import { withLock, CRON_JOBS } from '@addis/api/src/cron-jobs';
import { logger } from '@addis/api/infra/logger';
import { outboxDepthGauge } from '@addis/api/modules/health/metrics';

loadEnv();

const WORKER_ID = `worker-${process.pid}-${Date.now()}`;
const workerLogger = logger.child({ component: 'worker', workerId: WORKER_ID });

const HANDLERS: Record<string, (payload: any, evt: any) => Promise<void>> = {
  notification: async (p, evt) => (await import('./handlers/notification')).handle(p, evt),
  sms: async (p, evt) => (await import('./handlers/sms')).handle(p, evt),
  push: async (p, evt) => (await import('./handlers/push')).handle(p, evt),
  email: async (p, evt) => (await import('./handlers/email')).handle(p, evt),
  audit: async (p, evt) => (await import('./handlers/audit')).handle(p, evt),
  webhook: async (p, evt) => (await import('./handlers/webhook')).handle(p, evt),
};

const BACKOFF_SEC = [30, 60, 300, 900, 3600];
const LOCK_TTL_MS = 5 * 60_000;

async function drainOutbox() {

  const claimed = await db.execute(sql`
    UPDATE outbox_events SET status = 'processing', locked_at = now(), locked_by = ${WORKER_ID}, visibility_after = now() + interval '${sql.raw(String(LOCK_TTL_MS / 1000))} seconds'
    WHERE id IN (
      SELECT id FROM outbox_events
      WHERE status = 'pending'
        AND next_attempt_at <= now()
        AND (locked_at IS NULL OR visibility_after < now())
      LIMIT 50
      FOR UPDATE SKIP LOCKED
    )
    RETURNING *
  `);

  const rows = (claimed as any).rows ?? (claimed as any) ?? [];

  try {
    const [depth] = await db.select({ n: count() }).from(schema.outboxEvents)
      .where(eq(schema.outboxEvents.status, 'pending'));
    outboxDepthGauge.set(depth?.n ?? 0);
  } catch {  }

  for (const evt of rows) {
    try {

      const handler = HANDLERS[evt.channel];
      if (!handler) throw new Error(`No handler registered for outbox channel '${evt.channel}'`);
      await handler(evt.payload, evt);
      await db.update(schema.outboxEvents).set({ status: 'delivered' as any, updatedAt: new Date() }).where(eq(schema.outboxEvents.id, evt.id));
    } catch (err) {
      const attempts = evt.attempts + 1;
      if (attempts >= evt.maxAttempts) {
        await db.update(schema.outboxEvents).set({ status: 'dead' as any, attempts, lastError: String(err), updatedAt: new Date() }).where(eq(schema.outboxEvents.id, evt.id));
        const Sentry = await import('@sentry/node');

        Sentry.captureMessage('outbox event dead-lettered', {
          level: 'error',
          extra: { outboxEventId: evt.id, channel: evt.channel, attempts, lastError: String(err) },
        });
        Sentry.captureException(err, { extra: { outboxEventId: evt.id } });
        workerLogger.error({ outboxEventId: evt.id, channel: evt.channel, attempts, err }, 'outbox event dead-lettered');
      } else {
        const backoff = BACKOFF_SEC[Math.min(attempts - 1, BACKOFF_SEC.length - 1)] ?? 3600;
        await db.update(schema.outboxEvents).set({
          status: 'pending' as any, attempts, lastError: String(err),
          nextAttemptAt: new Date(Date.now() + backoff * 1000), updatedAt: new Date(),
          lockedAt: null, lockedBy: null, visibilityAfter: null,
        }).where(eq(schema.outboxEvents.id, evt.id));
      }
    }
  }
}

let draining = false;
let shuttingDown = false;
let drainTimer: NodeJS.Timeout | null = null;
const cronTimers: NodeJS.Timeout[] = [];

async function main() {
  drainTimer = setInterval(async () => {
    if (shuttingDown || draining) return;
    draining = true;
    try {
      await drainOutbox();
    } catch (err) {
      workerLogger.error({ err }, 'drainOutbox failed');
    } finally {
      draining = false;
    }
  }, 5000);

  for (const job of CRON_JOBS) {
    const t = setInterval(() => {
      if (shuttingDown) return;
      withLock(job.name, () => job.run()).catch(err => {
        workerLogger.error({ err, job: job.name }, 'cron job failed');
      });
    }, job.intervalMs);
    cronTimers.push(t);
  }

  workerLogger.info({ cronJobs: CRON_JOBS.length }, 'Addis Ride worker started');

  const shutdown = async (signal: string) => {
    workerLogger.info({ signal }, 'shutting down worker');
    shuttingDown = true;
    if (drainTimer) clearInterval(drainTimer);
    for (const t of cronTimers) clearInterval(t);

    const deadline = Date.now() + 30_000;
    while (draining && Date.now() < deadline) {
      await new Promise(r => setTimeout(r, 200));
    }
    process.exit(0);
  };
  process.on('SIGTERM', () => void shutdown('SIGTERM'));
  process.on('SIGINT', () => void shutdown('SIGINT'));
}
main();

{
  "extends": "../../tsconfig.base.json",
  "compilerOptions": {
    "outDir": "dist",
    "skipLibCheck": true
  },
  "include": ["src/**/*"],
  "exclude": ["node_modules", "dist"]
}

import { View, Text, FlatList, Pressable, ActivityIndicator } from 'react-native';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../../src/lib/api';
import { enqueueOrSend } from '../../src/lib/offline-queue';
import { PendingSyncBadge } from '../../src/components/pending-sync-badge';

export default function OpenSeatsScreen() {
  const qc = useQueryClient();
  const { data, isLoading } = useQuery({
    queryKey: ['seat-releases'],
    queryFn: async () => (await api.GET('/api/v1/seat-releases', { params: { query: { limit: 20 } } })).data,
  });

  const claim = useMutation({
    mutationFn: (seatReleaseId: string) =>
      enqueueOrSend({ method: 'POST', path: '/api/v1/seat-claims', body: { seatReleaseId, paymentMethod: 'telebirr' } }),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['seat-releases'] }),
  });

  if (isLoading) return <View className="flex-1 items-center justify-center"><ActivityIndicator /></View>;

  return (
    <View className="flex-1 bg-background px-5 pt-16">
      <Text className="text-xl font-semibold text-foreground mb-2">Open seats</Text>
      <PendingSyncBadge />
      <FlatList
        data={data ?? []}
        keyExtractor={(item: any) => item.id}
        contentContainerStyle={{ gap: 12, paddingVertical: 12 }}
        ListEmptyComponent={<Text className="text-muted-foreground text-center mt-12">No open seats right now.</Text>}
        renderItem={({ item }: any) => (
          <View className="rounded-2xl border border-border bg-card p-4 flex-row justify-between items-center">
            <View>
              <Text className="font-medium text-foreground">{item.routeName}</Text>
              <Text className="text-sm text-muted-foreground">{item.releaseDate} · {item.window}</Text>
            </View>
            <Pressable onPress={() => claim.mutate(item.id)} className="bg-foreground rounded-full px-4 py-2">
              <Text className="text-background text-sm font-medium">Claim</Text>
            </Pressable>
          </View>
        )}
      />
    </View>
  );
}

import { View, Text, ScrollView, Pressable, RefreshControl } from 'react-native';
import { useQuery } from '@tanstack/react-query';
import { router } from 'expo-router';
import { useState } from 'react';
import { api } from '../../src/lib/api';

export default function RiderDashboardScreen() {
  const { data, refetch } = useQuery({
    queryKey: ['rider-dashboard'],
    queryFn: async () => (await api.GET('/api/v1/dashboard/rider')).data,
  });
  const [refreshing, setRefreshing] = useState(false);

  return (
    <ScrollView
      className="flex-1 bg-background"
      refreshControl={<RefreshControl refreshing={refreshing} onRefresh={async () => { setRefreshing(true); await refetch(); setRefreshing(false); }} />}
    >
      <View className="px-5 pt-16">
        <Text className="text-2xl font-semibold text-foreground leading-tight">
          Every commute starts{'\n'}with a confirmed seat.
        </Text>
      </View>

      {(data as any)?.activeSubscription ? (
        <View className="mx-5 mt-6 rounded-3xl border border-border bg-card p-4">
          <View className="flex-row justify-between items-center">
            <Text className="text-sm text-muted-foreground">Active plan</Text>
            <View className="bg-primary/10 rounded-full px-2 py-1">
              <Text className="text-xs text-primary font-medium">{(data as any).activeSubscription.status}</Text>
            </View>
          </View>
          <Text className="text-lg font-semibold text-foreground mt-1">{(data as any).activeSubscription.plan.name}</Text>
          <Pressable
            onPress={() => router.push(`/(rider)/live-trip?subscriptionId=${(data as any).activeSubscription.id}`)}
            className="mt-3 bg-foreground rounded-full py-3 items-center"
          >
            <Text className="text-background font-medium">Track today's shuttle</Text>
          </Pressable>
        </View>
      ) : (
        <Pressable onPress={() => router.push('/(rider)/plans')} className="mx-5 mt-6 rounded-3xl border border-dashed border-border p-6 items-center">
          <Text className="font-medium text-foreground">No active subscription</Text>
          <Text className="text-sm text-muted-foreground text-center mt-1">Browse plans to reserve your daily seat</Text>
        </Pressable>
      )}
    </ScrollView>
  );
}

import { View, Text, Switch, useWindowDimensions } from 'react-native';
import { useSettingsStore } from '../../src/lib/settings-store';

export default function SettingsScreen() {
  const { width } = useWindowDimensions();
  const isTablet = width >= 768;
  const { biometricUnlock, setBiometricUnlock, locale, setLocale, theme, setTheme } = useSettingsStore();

  return (
    <View className={`flex-1 bg-background pt-16 ${isTablet ? 'flex-row px-16 gap-12' : 'px-5'}`}>
      <View className={isTablet ? 'w-64' : ''}>
        <Text className="text-xl font-semibold text-foreground mb-6">Settings</Text>
      </View>
      <View className="flex-1 gap-4">
        <Row label="Biometric unlock" value={<Switch value={biometricUnlock} onValueChange={setBiometricUnlock} />} />
        <Row label="Language" value={<Text onPress={() => setLocale(locale === 'en' ? 'am' : 'en')} className="text-accent">{locale === 'en' ? 'English' : 'አማርኛ'}</Text>} />
        <Row label="Theme" value={<Text onPress={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="text-accent">{theme === 'dark' ? 'Dark' : 'Light'}</Text>} />
      </View>
    </View>
  );
}

function Row({ label, value }: { label: string; value: React.ReactNode }) {
  return (
    <View className="flex-row items-center justify-between border-b border-border py-3">
      <Text className="text-foreground">{label}</Text>
      {value}
    </View>
  );
}

import { useEffect, useRef, useState } from 'react';
import { View, Text, Pressable, Linking } from 'react-native';
import MapViewBase, { Marker, Polyline } from 'react-native-maps';

const MapView = MapViewBase as any;
import { useLocalSearchParams } from 'expo-router';
import { useQuery } from '@tanstack/react-query';
import { api } from '../../src/lib/api';
import { useAuthStore } from '../../src/lib/auth-store';

const POLL_INTERVAL_MS = 5_000;

type ShuttlePosition = { lat: number; lng: number };

async function fetchShuttlePosition(url: string, token: string, signal: AbortSignal): Promise<ShuttlePosition | null> {
  const res = await fetch(url, {
    method: 'GET',
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: 'text/event-stream, application/json',
    },
    signal,
  });
  if (!res.ok) {
    throw new Error(`shuttle-positions stream returned ${res.status}`);
  }

  const text = await res.text();
  const dataLine = text
    .split('\n')
    .map((l) => l.trim())
    .filter((l) => l.startsWith('data:'))
    .map((l) => l.slice(5).trim())
    .filter(Boolean)
    .pop();
  const raw = dataLine ?? text.trim();
  if (!raw) return null;
  try {
    return JSON.parse(raw) as ShuttlePosition;
  } catch {
    return null;
  }
}

export default function LiveTripScreen() {
  const { subscriptionId } = useLocalSearchParams<{ subscriptionId: string }>();
  const [position, setPosition] = useState<{ lat: number; lng: number } | null>(null);
  const [streamError, setStreamError] = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const { data: trip } = useQuery({
    queryKey: ['active-trip', subscriptionId],
    queryFn: async () => (await api.GET('/api/v1/dashboard/rider/active-trip', { params: { query: { subscriptionId } } })).data,
  });

  const shuttleId = (trip as any)?.shuttleId;

  useEffect(() => {
    if (!shuttleId) return;
    const token = useAuthStore.getState().accessToken;
    if (!token) {
      setStreamError('You must be logged in to track the shuttle.');
      return;
    }
    const url = `${process.env.EXPO_PUBLIC_API_URL}/api/v1/shuttle-positions/stream?shuttleIds=${shuttleId}`;

    let cancelled = false;
    const loop = async () => {
      while (!cancelled) {
        const ctrl = new AbortController();
        abortRef.current = ctrl;
        try {
          const next = await fetchShuttlePosition(url, token, ctrl.signal);
          if (cancelled) return;
          if (next) {
            setPosition(next);
            setStreamError(null);
          }
        } catch (err) {
          if (cancelled) return;
          setStreamError(
            'Live location is unavailable right now. Retrying every 5s…',
          );

        }
        await new Promise((r) => setTimeout(r, POLL_INTERVAL_MS));
      }
    };
    loop();
    return () => {
      cancelled = true;
      abortRef.current?.abort();
    };
  }, [shuttleId]);

  if (!trip) return <View className="flex-1 items-center justify-center"><Text>Loading…</Text></View>;
  const t = trip as any;

  return (
    <View className="flex-1">
      <MapView style={{ flex: 1 }} initialRegion={{ latitude: 9.02, longitude: 38.75, latitudeDelta: 0.05, longitudeDelta: 0.05 }}>
        {t.polyline && <Polyline coordinates={t.polyline.map(([lat, lng]: number[]) => ({ latitude: lat, longitude: lng }))} strokeColor="#10b981" strokeWidth={4} />}
        {position && <Marker coordinate={{ latitude: position.lat, longitude: position.lng }} title={t.plateNumber} />}
      </MapView>

      {streamError && (
        <View className="absolute top-10 inset-x-4 bg-destructive/10 border border-destructive rounded-xl px-4 py-2">
          <Text className="text-destructive text-sm">{streamError}</Text>
        </View>
      )}

      <View className="absolute bottom-0 inset-x-0 bg-card rounded-t-3xl p-4 border-t border-border">
        <View className="flex-row justify-between mb-3">
          <Text className="text-muted-foreground text-sm">Arriving in</Text>
          <Text className="font-semibold text-lg">{t.etaMinutes} min</Text>
        </View>
        <View className="flex-row items-center gap-3">
          <View className="flex-1">
            <Text className="font-medium">{t.contractorName}</Text>
            <Text className="text-xs text-muted-foreground">{t.plateNumber} · ★ {t.contractorRating}</Text>
          </View>
          <Pressable onPress={() => Linking.openURL(`tel:${t.contractorPhone}`)} className="h-10 w-10 rounded-full bg-foreground items-center justify-center">
            <Text className="text-background">📞</Text>
          </Pressable>
        </View>
      </View>
    </View>
  );
}

import { useEffect, useRef, useState } from 'react';
import { View, Text, Pressable } from 'react-native';
import * as Location from 'expo-location';
import * as BackgroundFetch from 'expo-background-fetch';
import * as TaskManager from 'expo-task-manager';
import * as SecureStore from 'expo-secure-store';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { api } from '../../src/lib/api';

const GPS_TASK = 'addisride-gps-report';
const ACTIVE_SHUTTLE_KEY = 'addisride.activeShuttleId';

const TICK_COUNT_KEY = 'addisride.gpsTickCount';
const REVALIDATE_EVERY_N_TICKS = 6;

const MAX_UPLOAD_RETRIES = 3;

async function getActiveShuttleId() {
  return SecureStore.getItemAsync(ACTIVE_SHUTTLE_KEY);
}

async function getTickCount(): Promise<number> {
  const raw = await AsyncStorage.getItem(TICK_COUNT_KEY);
  return raw ? parseInt(raw, 10) || 0 : 0;
}

async function setTickCount(n: number): Promise<void> {
  await AsyncStorage.setItem(TICK_COUNT_KEY, String(n));
}

async function shuttleIdStillValid(shuttleId: string): Promise<boolean> {
  try {

    const res = await (api as any).GET('/api/v1/trips', {}) as any;
    if (res.error || !res.data) {

      if (res.response?.status === 403) {
        await SecureStore.deleteItemAsync(ACTIVE_SHUTTLE_KEY);
      }
      return false;
    }
    const trips: Array<{ shuttleId?: string; status?: string }> = (res.data?.data ?? res.data ?? []) as any;
    const stillActive = trips.some(
      (t) => t.shuttleId === shuttleId && t.status === 'in_transit',
    );
    if (!stillActive) {
      await SecureStore.deleteItemAsync(ACTIVE_SHUTTLE_KEY);
    }
    return stillActive;
  } catch {

    return true;
  }
}

async function uploadWithRetry(body: {
  shuttleId: string; lat: number; lng: number; heading?: number; speed?: number;
}): Promise<boolean> {
  for (let attempt = 0; attempt < MAX_UPLOAD_RETRIES; attempt++) {
    const res = await api.POST('/api/v1/shuttle-positions', { body } as any) as any;
    if (!res.error) return true;

    const status = res.response?.status ?? 0;
    if (status >= 400 && status < 500 && status !== 408 && status !== 429) return false;
    if (attempt < MAX_UPLOAD_RETRIES - 1) {
      const backoffMs = 1000 * Math.pow(2, attempt);
      await new Promise((r) => setTimeout(r, backoffMs));
    }
  }
  return false;
}

TaskManager.defineTask(GPS_TASK, async () => {
  const shuttleId = await getActiveShuttleId();
  if (!shuttleId) return BackgroundFetch.BackgroundFetchResult.NoData;

  const tick = (await getTickCount()) + 1;
  await setTickCount(tick);
  if (tick % REVALIDATE_EVERY_N_TICKS === 0) {
    const valid = await shuttleIdStillValid(shuttleId);
    if (!valid) {
      return BackgroundFetch.BackgroundFetchResult.NoData;
    }
  }

  let loc;
  try {
    loc = await Location.getCurrentPositionAsync({});
  } catch {
    return BackgroundFetch.BackgroundFetchResult.Failed;
  }

  const body: { shuttleId: string; lat: number; lng: number; heading?: number; speed?: number } = {
    shuttleId,
    lat: loc.coords.latitude,
    lng: loc.coords.longitude,
  };
  if (loc.coords.heading != null) body.heading = loc.coords.heading;
  if (loc.coords.speed != null) body.speed = loc.coords.speed;
  const uploaded = await uploadWithRetry(body);

  return uploaded
    ? BackgroundFetch.BackgroundFetchResult.NewData
    : BackgroundFetch.BackgroundFetchResult.Failed;
});

export async function setActiveShuttleId(shuttleId: string): Promise<void> {
  await SecureStore.setItemAsync(ACTIVE_SHUTTLE_KEY, shuttleId);
  await setTickCount(0);
}
export async function clearActiveShuttleId(): Promise<void> {
  await SecureStore.deleteItemAsync(ACTIVE_SHUTTLE_KEY);
  await setTickCount(0);
}

export default function ContractorGpsTrackerScreen() {
  const registered = useRef(false);

  const [invalidated, setInvalidated] = useState(false);

  useEffect(() => {
    (async () => {
      const fg = await Location.requestForegroundPermissionsAsync();
      if (fg.status !== 'granted' || registered.current) return;

      const bg = await Location.requestBackgroundPermissionsAsync();
      if (bg.status !== 'granted') return;
      await BackgroundFetch.registerTaskAsync(GPS_TASK, { minimumInterval: 10, stopOnTerminate: false, startOnBoot: true });
      registered.current = true;
    })();

    let cancelled = false;
    const poll = async () => {
      while (!cancelled) {
        const sid = await getActiveShuttleId();
        if (!sid) { setInvalidated(true); return; }
        const valid = await shuttleIdStillValid(sid);
        if (cancelled) return;
        if (!valid) { setInvalidated(true); return; }
        await new Promise((r) => setTimeout(r, 60_000));
      }
    };
    poll();
    return () => { cancelled = true; };
  }, []);

  return (
    <View className="flex-1 items-center justify-center px-6">
      {invalidated ? (
        <>
          <Text className="text-lg font-semibold">Trip ended</Text>
          <Text className="text-sm text-muted-foreground mt-1 text-center">
            This trip is no longer active. Start a new trip to resume live tracking.
          </Text>
          <Pressable
            className="mt-8 px-6 py-3 rounded-xl bg-foreground"
            onPress={async () => {
              const { router } = await import('expo-router');
              await clearActiveShuttleId();
              router.replace('/(contractor)/start-trip');
            }}
          >
            <Text className="text-background font-medium">Start a new trip</Text>
          </Pressable>
        </>
      ) : (
        <>
          <Text className="text-lg font-semibold">Trip in progress</Text>
          <Text className="text-sm text-muted-foreground mt-1 text-center">Your location is being shared with riders on this trip every 10 seconds.</Text>

          <Pressable
            className="mt-8 px-6 py-3 rounded-xl bg-destructive"
            onPress={async () => {
              const { router } = await import('expo-router');
              await clearActiveShuttleId();
              await BackgroundFetch.unregisterTaskAsync(GPS_TASK).catch(() => {});
              router.replace('/(contractor)/start-trip');
            }}
          >
            <Text className="text-destructive-foreground font-medium">End Trip</Text>
          </Pressable>
        </>
      )}
    </View>
  );
}

import { View, Text, Pressable, ActivityIndicator } from 'react-native';
import { router } from 'expo-router';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../../src/lib/api';
import { setActiveShuttleId } from './gps-tracker';

export default function ContractorStartTripScreen() {
  const qc = useQueryClient();
  const { data: profile } = useQuery({
    queryKey: ['contractor-dashboard'],
    queryFn: async () => (await api.GET('/api/v1/dashboard/contractor')).data,
  });

  const startTrip = useMutation({
    mutationFn: async (input: { shuttleId: string; routeId: string; window: 'morning' | 'evening' }) =>
      api.POST('/api/v1/trips', { body: input } as any),
    onSuccess: async (_res, variables) => {

      await setActiveShuttleId(variables.shuttleId);
      qc.invalidateQueries({ queryKey: ['contractor-dashboard'] });
      router.push('/(contractor)/gps-tracker');
    },
  });

  const d = profile as any;
  const shuttleId = d?.shuttleId;
  const routeId = d?.routeId;
  const canStart = shuttleId && routeId && d?.verificationStatus === 'verified';

  if (!d) return <View className="flex-1 items-center justify-center"><ActivityIndicator /></View>;

  return (
    <View className="flex-1 items-center justify-center px-6">
      <Text className="text-xl font-semibold mb-4">Start Trip</Text>
      {!canStart && (
        <Text className="text-sm text-muted-foreground text-center mb-4">
          {d?.verificationStatus !== 'verified'
            ? 'Your account is pending verification. You cannot start trips until an admin approves your documents.'
            : 'No shuttle or route assigned. Contact support.'}
        </Text>
      )}
      <Pressable
        disabled={!canStart || startTrip.isPending}
        onPress={() => startTrip.mutate({ shuttleId, routeId, window: 'morning' })}
        className={`px-6 py-3 rounded-xl ${canStart && !startTrip.isPending ? 'bg-primary' : 'bg-muted'}`}
      >
        <Text className="text-primary-foreground font-medium">
          {startTrip.isPending ? 'Starting...' : 'Start Morning Trip'}
        </Text>
      </Pressable>
      {startTrip.error && (
        <Text className="text-sm text-destructive mt-2">
          {(startTrip.error as any)?.message ?? 'Failed to start trip'}
        </Text>
      )}
    </View>
  );
}

import 'react-native-get-random-values';

import { useEffect, useState } from 'react';
import { Stack } from 'expo-router';
import { AppState, Modal } from 'react-native';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { I18nProvider } from '@addis/i18n';
import { useAuthStore } from '../src/lib/auth-store';
import { useSettingsStore } from '../src/lib/settings-store';
import { subscribeToConnectivity, subscribeToAuthFlush, onAuthRequiredForFlush } from '../src/lib/offline-queue';
import { registerPushToken } from '../src/lib/push';
import * as Notifications from 'expo-notifications';
import * as Localization from 'expo-localization';
import BiometricGateScreen from './(auth)/biometric-gate';

Notifications.setNotificationHandler({
  handleNotification: async () => ({ shouldShowAlert: true, shouldPlaySound: true, shouldSetBadge: true }),
});

export default function RootLayout() {
  const [ready, setReady] = useState(false);
  const hydrateAuth = useAuthStore((s) => s.hydrate);
  const hydrateSettings = useSettingsStore((s) => s.hydrate);
  const isGateSatisfied = useAuthStore((s) => s.isGateSatisfied);
  const setGateSatisfied = useAuthStore((s) => s.setGateSatisfied);

  const [gateNonce, setGateNonce] = useState(0);
  const [queryClient] = useState(() => new QueryClient({ defaultOptions: { queries: { staleTime: 30_000 } } }));

  useEffect(() => {
    Promise.all([hydrateAuth(), hydrateSettings()]).then(() => setReady(true));
    const unsubscribe = subscribeToConnectivity();

    const unsubAuthFlush = subscribeToAuthFlush(useAuthStore.subscribe);
    const unsubAuthRequired = onAuthRequiredForFlush(() => {

      useAuthStore.getState().clearAuth().catch(() => {});
      setGateSatisfied(false);
      setGateNonce((n) => n + 1);
    });
    registerPushToken().catch(() => {});
    return () => { unsubscribe(); unsubAuthFlush(); unsubAuthRequired(); };
  }, [setGateSatisfied]);

  useEffect(() => {
    let lastBackgroundedAt: number | null = null;
    const sub = AppState.addEventListener('change', (state) => {
      if (state === 'background') {
        lastBackgroundedAt = Date.now();
        return;
      }
      if (state !== 'active') return;
      if (lastBackgroundedAt === null) return;
      const backgroundDuration = Date.now() - lastBackgroundedAt;
      lastBackgroundedAt = null;
      if (backgroundDuration < 30_000) return;
      const { accessToken } = useAuthStore.getState();
      const { biometricUnlock } = useSettingsStore.getState();
      if (accessToken && biometricUnlock) {

        setGateSatisfied(false);
        setGateNonce((n) => n + 1);
      }
    });
    return () => sub.remove();
  }, [setGateSatisfied]);

  if (!ready) return null;
  const locale = useSettingsStore.getState().locale ?? (Localization.getLocales()[0]?.languageCode === 'am' ? 'am' : 'en');

  return (
    <QueryClientProvider client={queryClient}>
      <I18nProvider initialLocale={locale}>
        <Stack screenOptions={{ headerShown: false }} initialRouteName="(auth)/login" />
        {}
        <Modal
          visible={!isGateSatisfied}
          animationType="slide"
          presentationStyle="fullScreen"
          onRequestClose={() => {  }}
        >
          <BiometricGateScreen key={gateNonce} />
        </Modal>
      </I18nProvider>
    </QueryClientProvider>
  );
}

import { useState } from 'react';
import { View, Text, TextInput, Pressable, ActivityIndicator, ScrollView } from 'react-native';
import { router } from 'expo-router';
import { api } from '../../src/lib/api';

const STEPS = ['Account', 'Commute', 'Review'];

export default function SignupScreen() {
  const [step, setStep] = useState(0);
  const [form, setForm] = useState({ name: '', phone: '+251', password: '', homeArea: '', workArea: '', tosAccepted: false });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const submit = async () => {
    setLoading(true); setError(null);
    const { error: apiError } = await api.POST('/api/v1/auth/register', {
      body: { kind: 'rider', name: form.name, phone: form.phone, password: form.password, homeArea: form.homeArea, workArea: form.workArea },
    });
    setLoading(false);
    if (apiError) { setError('Could not create account. Check your details.'); return; }
    router.replace('/(auth)/login');
  };

  return (
    <ScrollView className="flex-1 bg-background px-6 pt-16">
      <View className="flex-row mb-8">
        {STEPS.map((s, i) => (
          <View key={s} className={`flex-1 h-1 rounded-full mx-1 ${i <= step ? 'bg-primary' : 'bg-border'}`} />
        ))}
      </View>

      {step === 0 && (
        <View className="gap-3">
          <Field label="Full name" value={form.name} onChangeText={(v) => setForm((f) => ({ ...f, name: v }))} />
          <Field label="Phone number" value={form.phone} onChangeText={(v) => setForm((f) => ({ ...f, phone: v }))} keyboardType="phone-pad" />
          <Field label="Password" value={form.password} onChangeText={(v) => setForm((f) => ({ ...f, password: v }))} secureTextEntry />
        </View>
      )}
      {step === 1 && (
        <View className="gap-3">
          <Field label="Home area" value={form.homeArea} onChangeText={(v) => setForm((f) => ({ ...f, homeArea: v }))} />
          <Field label="Work area" value={form.workArea} onChangeText={(v) => setForm((f) => ({ ...f, workArea: v }))} />
        </View>
      )}
      {step === 2 && (
        <View className="gap-3">
          <View className="bg-secondary rounded-xl p-4">
            <Text className="text-foreground">{form.name} · {form.phone}</Text>
            <Text className="text-muted-foreground text-sm mt-1">{form.homeArea} → {form.workArea}</Text>
          </View>
          <Pressable onPress={() => setForm((f) => ({ ...f, tosAccepted: !f.tosAccepted }))} className="flex-row items-center gap-2">
            <View className={`h-5 w-5 rounded border ${form.tosAccepted ? 'bg-primary border-primary' : 'border-border'}`} />
            <Text className="text-sm text-foreground flex-1">I agree to the Terms of Service and Privacy Policy</Text>
          </Pressable>
          {error && <Text className="text-destructive text-sm">{error}</Text>}
        </View>
      )}

      <View className="flex-row gap-3 mt-8 mb-8">
        {step > 0 && (
          <Pressable onPress={() => setStep((s) => s - 1)} className="flex-1 h-12 rounded-xl border border-border items-center justify-center">
            <Text className="text-foreground">Back</Text>
          </Pressable>
        )}
        <Pressable
          onPress={() => (step < 2 ? setStep((s) => s + 1) : submit())}
          disabled={step === 2 && (!form.tosAccepted || loading)}
          className="flex-1 h-12 rounded-xl bg-foreground items-center justify-center disabled:opacity-40"
        >
          {loading ? <ActivityIndicator color="#fff" /> : <Text className="text-background font-medium">{step < 2 ? 'Continue' : 'Create account'}</Text>}
        </Pressable>
      </View>
    </ScrollView>
  );
}

function Field(props: { label: string } & React.ComponentProps<typeof TextInput>) {
  return (
    <View>
      <Text className="text-sm font-medium mb-1 text-foreground">{props.label}</Text>
      <TextInput {...props} className="h-12 rounded-xl border border-border px-3 text-foreground" accessibilityLabel={props.label} />
    </View>
  );
}

import { useState } from 'react';
import { View, Text, TextInput, Pressable, ActivityIndicator } from 'react-native';
import { router } from 'expo-router';
import { api } from '../../src/lib/api';
import { useAuthStore } from '../../src/lib/auth-store';

type Stage = 'credentials' | 'twoFa' | 'locked';

export default function LoginScreen() {
  const [phone, setPhone] = useState('+251');
  const [password, setPassword] = useState('');
  const [code, setCode] = useState('');
  const [stage, setStage] = useState<Stage>('credentials');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const setAuth = useAuthStore((s) => s.setAuth);

  const submitCredentials = async () => {
    setLoading(true); setError(null);
    const res = await api.POST('/api/v1/auth/token', { body: { phone, password } }) as any;
    setLoading(false);
    if (res.error) {
      const errCode = res.error?.error?.code ?? res.error?.code;
      const status = res.response?.status;
      if (status === 423 || errCode === 'ACCOUNT_LOCKED') {
        setStage('locked');
        return;
      }
      if (errCode === 'TWO_FA_REQUIRED') {
        setStage('twoFa');
        setError(null);
        return;
      }
      setError('Invalid phone number or password');
      return;
    }
    await setAuth(res.data.accessToken, res.data.user.role);
    router.replace('/(rider)/dashboard');
  };

  const submitTwoFa = async () => {
    setLoading(true); setError(null);
    const res = await api.POST('/api/v1/auth/token', { body: { phone, password, code: code.trim() } }) as any;
    setLoading(false);
    if (res.error) {
      const errCode = res.error?.error?.code ?? res.error?.code;
      const status = res.response?.status;
      if (status === 423 || errCode === 'ACCOUNT_LOCKED') {
        setStage('locked');
        return;
      }

      setError('Incorrect code — please try again.');
      return;
    }
    await setAuth(res.data.accessToken, res.data.user.role);
    router.replace('/(rider)/dashboard');
  };

  if (stage === 'locked') {
    return (
      <View className="flex-1 justify-center px-6 bg-background">
        <Text className="text-2xl font-semibold text-center mb-4 text-foreground">Account locked</Text>
        <Text className="text-sm text-muted-foreground text-center mb-8">
          For your security, your account has been temporarily locked after too many failed sign-in attempts. Please try again later or contact support.
        </Text>
        <Pressable
          onPress={() => {
            setStage('credentials');
            setPassword('');
            setCode('');
            setError(null);
          }}
          className="h-12 rounded-xl bg-foreground items-center justify-center"
        >
          <Text className="text-background font-medium">Back to sign in</Text>
        </Pressable>
      </View>
    );
  }

  return (
    <View className="flex-1 justify-center px-6 bg-background">
      <Text className="text-2xl font-semibold text-center mb-8 text-foreground">
        {stage === 'twoFa' ? 'Enter verification code' : 'Welcome back'}
      </Text>

      {stage === 'credentials' && (
        <>
          <Text className="text-sm font-medium mb-1 text-foreground">Phone number</Text>
          <TextInput
            value={phone} onChangeText={setPhone} keyboardType="phone-pad"
            className="h-12 rounded-xl border border-border px-3 mb-4 text-foreground"
            accessibilityLabel="Phone number"
          />
          <Text className="text-sm font-medium mb-1 text-foreground">Password</Text>
          <TextInput
            value={password} onChangeText={setPassword} secureTextEntry
            className="h-12 rounded-xl border border-border px-3 mb-2 text-foreground"
            accessibilityLabel="Password"
          />
        </>
      )}

      {stage === 'twoFa' && (
        <>
          <Text className="text-sm text-muted-foreground text-center mb-6">
            We sent a 6-digit code to your authenticator app. Enter it below to continue.
          </Text>
          <TextInput
            value={code}
            onChangeText={(v) => setCode(v.replace(/[^0-9]/g, '').slice(0, 6))}
            keyboardType="number-pad"
            textContentType="oneTimeCode"
            className="h-14 rounded-xl border border-border px-3 mb-2 text-center text-xl tracking-widest text-foreground"
            accessibilityLabel="Two-factor authentication code"
            autoFocus
          />
        </>
      )}

      {error && <Text className="text-destructive text-sm mb-2">{error}</Text>}

      <Pressable
        onPress={stage === 'twoFa' ? submitTwoFa : submitCredentials}
        disabled={loading || (stage === 'twoFa' && code.length !== 6)}
        className="h-12 rounded-xl bg-foreground items-center justify-center mt-4"
      >
        {loading ? <ActivityIndicator color="#fff" /> : <Text className="text-background font-medium">{stage === 'twoFa' ? 'Verify' : 'Log in'}</Text>}
      </Pressable>

      {stage === 'twoFa' && (
        <Pressable
          onPress={() => { setStage('credentials'); setCode(''); setError(null); }}
          className="mt-4"
        >
          <Text className="text-center text-accent text-sm">Use a different account</Text>
        </Pressable>
      )}

      {stage === 'credentials' && (
        <Pressable onPress={() => router.push('/(auth)/signup')} className="mt-4">
          <Text className="text-center text-accent text-sm">Create an account</Text>
        </Pressable>
      )}
    </View>
  );
}

import { useEffect, useState } from 'react';
import { View, Text, Pressable, ActivityIndicator } from 'react-native';
import * as LocalAuthentication from 'expo-local-authentication';
import { router, usePathname } from 'expo-router';
import { useAuthStore } from '../../src/lib/auth-store';
import { useSettingsStore } from '../../src/lib/settings-store';

export default function BiometricGateScreen() {
  const [status, setStatus] = useState<'checking' | 'prompt' | 'failed'>('checking');
  const accessToken = useAuthStore((s) => s.accessToken);
  const setGateSatisfied = useAuthStore((s) => s.setGateSatisfied);
  const clearAuth = useAuthStore((s) => s.clearAuth);
  const biometricEnabled = useSettingsStore((s) => s.biometricUnlock);
  const pathname = usePathname();

  const satisfy = () => {
    setGateSatisfied(true);
    const { accessToken } = useAuthStore.getState();
    if (accessToken && pathname.startsWith('/(auth)')) {
      router.replace('/(rider)/dashboard');
    }
  };

  useEffect(() => {
    (async () => {

      if (!accessToken) { satisfy(); return; }

      if (!biometricEnabled) { satisfy(); return; }

      const hasHardware = await LocalAuthentication.hasHardwareAsync();
      const enrolled = await LocalAuthentication.isEnrolledAsync();
      if (!hasHardware || !enrolled) { satisfy(); return; }

      setStatus('prompt');
      const result = await LocalAuthentication.authenticateAsync({
        promptMessage: 'Unlock Addis Ride', fallbackLabel: 'Use passcode', cancelLabel: 'Cancel',
      });
      if (result.success) satisfy();
      else setStatus('failed');
    })();

  }, [accessToken, biometricEnabled]);

  if (status === 'checking') return <View className="flex-1 items-center justify-center bg-background"><ActivityIndicator /></View>;

  return (
    <View className="flex-1 items-center justify-center px-6 bg-background">
      <Text className="text-lg font-semibold mb-2 text-foreground">Unlock required</Text>
      <Text className="text-sm text-muted-foreground text-center mb-6">Authenticate with Face ID / fingerprint to continue.</Text>
      <Pressable
        onPress={async () => {
          const result = await LocalAuthentication.authenticateAsync({ promptMessage: 'Unlock Addis Ride' });
          if (result.success) satisfy();
        }}
        className="bg-foreground rounded-full px-6 py-3"
      >
        <Text className="text-background font-medium">Try again</Text>
      </Pressable>
      <Pressable onPress={async () => { await clearAuth(); router.replace('/(auth)/login'); }} className="mt-4">
        <Text className="text-destructive text-sm">Log out instead</Text>
      </Pressable>
    </View>
  );
}

import type { ComponentType } from 'react';

type LooselyTypedComponent = ComponentType<any>;

declare module 'react-native-maps' {
