'use client';
import { useEffect, useState } from 'react';
import { useSearchParams } from 'next/navigation';
import { useRouter } from 'next/navigation';
import { CheckCircle2, Loader2 } from 'lucide-react';
import { Button } from '@addis/ui';

export default function CheckoutCompletePage() {
  const params = useSearchParams();
  const router = useRouter();
  const [status, setStatus] = useState<'processing' | 'success' | 'failed'>('processing');
  const merchOrderId = params.get('merch_order_id') ?? params.get('out_request_no');

  useEffect(() => {
    let attempts = 0;
    const maxAttempts = 15;
    const interval = setInterval(async () => {
      attempts++;
      try {

        const res = await fetch('/api/v1/dashboard/rider', { credentials: 'include' });
        if (res.ok) {
          const json = await res.json();
          if (json?.data?.activeSubscription) {
            setStatus('success');
            clearInterval(interval);
            return;
          }
        }
      } catch {

      }
      if (attempts >= maxAttempts) {
        clearInterval(interval);

      }
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="min-h-screen flex items-center justify-center px-6">
      <div className="max-w-sm text-center space-y-4">
        {status === 'processing' && (
          <>
            <Loader2 className="h-12 w-12 text-primary animate-spin mx-auto" />
            <h1 className="text-xl font-semibold">Processing your payment…</h1>
            <p className="text-sm text-muted-foreground">
              We're confirming your payment with Telebirr. This usually takes a few seconds.
              {merchOrderId && <><br />Reference: <span className="font-mono">{merchOrderId}</span></>}
            </p>
          </>
        )}
        {status === 'success' && (
          <>
            <CheckCircle2 className="h-12 w-12 text-success mx-auto" />
            <h1 className="text-xl font-semibold">Payment successful!</h1>
            <p className="text-sm text-muted-foreground">
              Your subscription is now active. You can track your shuttle from the dashboard.
            </p>
            <Button className="w-full" onClick={() => router.push('/dashboard/rider')}>
              Go to dashboard
            </Button>
          </>
        )}
        {status === 'failed' && (
          <>
            <h1 className="text-xl font-semibold">Payment not confirmed yet</h1>
            <p className="text-sm text-muted-foreground">
              We couldn't confirm your payment in time. If you completed the Telebirr checkout,
              your subscription will activate once the webhook arrives — check your dashboard in a minute.
            </p>
            <Button variant="outline" className="w-full" onClick={() => router.push('/dashboard/rider')}>
              Go to dashboard
            </Button>
          </>
        )}
      </div>
    </div>
  );
}

'use client';
import { useEffect, useMemo, useState } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { CreditCard, Landmark } from 'lucide-react';
import { Button, Card, CardContent } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { useToast } from '@addis/ui';
import { isAllowedCheckoutUrl } from '@/lib/checkout-allowlist';

const NONCE_STORAGE_KEY = 'addisride.checkout.nonce';

function getOrCreateNonce(): string {
  if (typeof window === 'undefined') return 'ssr-placeholder';
  try {
    const existing = window.sessionStorage.getItem(NONCE_STORAGE_KEY);
    if (existing) return existing;
    const fresh = crypto.randomUUID();
    window.sessionStorage.setItem(NONCE_STORAGE_KEY, fresh);
    return fresh;
  } catch {

    return crypto.randomUUID();
  }
}

function clearNonce() {
  if (typeof window === 'undefined') return;
  try { window.sessionStorage.removeItem(NONCE_STORAGE_KEY); } catch {  }
}

export default function CheckoutPage() {
  const params = useSearchParams();
  const router = useRouter();
  const client = useApiClient();
  const { push } = useToast();
  const [method, setMethod] = useState<'telebirr' | 'cbe'>('telebirr');
  const [loading, setLoading] = useState(false);

  const planId = params.get('planId');
  const routeId = params.get('routeId');

  const [nonce] = useState(() => getOrCreateNonce());

  const idempotencyKey = useMemo(() => {
    if (!planId || !routeId) return null;
    return `checkout:${planId}:${routeId}:${nonce}`;
  }, [planId, routeId, nonce]);

  useEffect(() => {
    if (params.get('checkout_done') === '1') {
      clearNonce();
    }
  }, [params]);

  const submit = async () => {
    if (!planId || !routeId || !idempotencyKey) {
      push({ title: 'Missing plan or route — please go back and try again', variant: 'error' });
      return;
    }
    setLoading(true);
    const { data, error } = await client.POST('/api/v1/subscriptions', {
      headers: { 'Idempotency-Key': idempotencyKey },
      body: { planId, routeId, paymentMethod: method },
    });
    setLoading(false);
    if (error) { push({ title: (error as any)?.error?.message ?? (error as any)?.message ?? 'Could not start checkout', variant: 'error' }); return; }

    clearNonce();

    const checkout = (data as any).meta?.checkout;
    if (checkout?.status === 'checkout') {

      if (!isAllowedCheckoutUrl(checkout.checkoutUrl)) {
        push({ title: 'Invalid checkout URL returned by payment provider', variant: 'error' });
        return;
      }
      window.location.href = checkout.checkoutUrl;
    } else if (checkout?.status === 'manual') {
      router.push(`/checkout/cbe-instructions?ref=${checkout.instructions.reference}&amount=${checkout.instructions.amount}`);
    }
  };

  return (
    <div className="min-h-screen px-6 py-10 max-w-md mx-auto">
      <h1 className="text-xl font-semibold mb-6">Choose payment method</h1>
      <div className="space-y-3">
        <Card
          className={method === 'telebirr' ? 'border-primary' : ''}
          onClick={() => setMethod('telebirr')}
          role="button"
          tabIndex={0}
          onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setMethod('telebirr'); } }}
        >
          <CardContent className="flex items-center gap-3 cursor-pointer">
            <CreditCard className="h-5 w-5 text-primary" />
            <div><p className="font-medium">telebirr</p><p className="text-xs text-muted-foreground">Instant, mobile money</p></div>
          </CardContent>
        </Card>
        <Card
          className={method === 'cbe' ? 'border-primary' : ''}
          onClick={() => setMethod('cbe')}
          role="button"
          tabIndex={0}
          onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setMethod('cbe'); } }}
        >
          <CardContent className="flex items-center gap-3 cursor-pointer">
            <Landmark className="h-5 w-5 text-primary" />
            <div><p className="font-medium">CBE Birr</p><p className="text-xs text-muted-foreground">Manual bank transfer</p></div>
          </CardContent>
        </Card>
      </div>
      <Button className="w-full mt-8" loading={loading} onClick={submit} disabled={!planId || !routeId}>Continue</Button>
    </div>
  );
}

'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button, Card, CardContent, Badge } from '@addis/ui';
import { useToast } from '@addis/ui';
import { useFormatMoney } from '@addis/i18n';
import { Check } from 'lucide-react';

export type PlanPickerPlan = {
  id: string;
  name: string;
  description?: string;
  durationDays: number;
  ridesIncluded: number;
  priceETB: string;
  isPopular?: boolean;
  isTrial?: boolean;
};
export type PlanPickerRoute = {
  id: string;
  name: string;
  origin?: string;
  destination?: string;
  durationMin?: number;
  fare: string;
};

export function PlanPickerClient({
  plans,
  routes,
  initialPlanId = null,
  initialRouteId = null,
}: {
  plans: PlanPickerPlan[];
  routes: PlanPickerRoute[];
  initialPlanId?: string | null;
  initialRouteId?: string | null;
}) {
  const router = useRouter();
  const money = useFormatMoney();
  const { push } = useToast();
  const [selectedPlan, setSelectedPlan] = useState<string | null>(initialPlanId);
  const [selectedRoute, setSelectedRoute] = useState<string | null>(initialRouteId);

  const continueToCheckout = () => {
    if (!selectedPlan || !selectedRoute) {
      push({ title: 'Please select a plan and a route', variant: 'error' });
      return;
    }
    router.push(`/checkout?planId=${selectedPlan}&routeId=${selectedRoute}`);
  };

  return (
    <div className="px-5 py-10 max-w-3xl mx-auto">
      <h1 className="text-xl font-semibold mb-6">Choose a plan</h1>

      <div className="grid sm:grid-cols-3 gap-4 mb-8">
        {plans.map((p) => (
          <Card
            key={p.id}
            role="button"
            tabIndex={0}
            onClick={() => setSelectedPlan(p.id)}
            onKeyDown={(e) => e.key === 'Enter' && setSelectedPlan(p.id)}
            className={`cursor-pointer transition-colors ${selectedPlan === p.id ? 'border-primary ring-2 ring-primary/20' : 'hover:border-primary'}`}
          >
            <CardContent className="space-y-2">
              <div className="flex items-center justify-between">
                <p className="font-medium">{p.name}</p>
                {p.isPopular && <Badge>Popular</Badge>}
              </div>
              <p className="text-2xl font-semibold">{money(p.priceETB)}</p>
              <p className="text-sm text-muted-foreground">
                {p.durationDays} days · {p.ridesIncluded === -1 ? 'Unlimited' : `${p.ridesIncluded} rides`}
              </p>
              {p.isTrial && <Badge variant="warning">Trial</Badge>}
              {selectedPlan === p.id && (
                <div className="flex items-center gap-1 text-sm text-primary">
                  <Check className="h-4 w-4" /> Selected
                </div>
              )}
            </CardContent>
          </Card>
        ))}
      </div>

      <h2 className="font-semibold mb-3">Pick your route</h2>
      <div className="space-y-2 mb-8">
        {routes.map((r) => (
          <Card
            key={r.id}
            role="button"
            tabIndex={0}
            onClick={() => setSelectedRoute(r.id)}
            onKeyDown={(e) => e.key === 'Enter' && setSelectedRoute(r.id)}
            className={`cursor-pointer transition-colors ${selectedRoute === r.id ? 'border-primary ring-2 ring-primary/20' : 'hover:border-primary'}`}
          >
            <CardContent className="flex items-center justify-between">
              <div>
                <p className="font-medium">{r.name}</p>
                {r.origin && r.destination && (
                  <p className="text-sm text-muted-foreground">{r.origin} → {r.destination}</p>
                )}
              </div>
              <div className="text-right">
                {r.durationMin != null && (
                  <p className="text-sm text-muted-foreground">{r.durationMin} min</p>
                )}
                <p className="font-semibold">{money(r.fare)}</p>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      <Button
        className="w-full"
        disabled={!selectedPlan || !selectedRoute}
        onClick={continueToCheckout}
      >
        Continue to payment
      </Button>
    </div>
  );
}

import { describe, it, expect, vi } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import { PlanPickerClient } from './plan-picker-client';

vi.mock('next/navigation', () => ({ useRouter: () => ({ push: vi.fn() }) }));
vi.mock('@addis/i18n', () => ({ useFormatMoney: () => (n: string) => `ETB ${n}` }));

vi.mock('@addis/ui', async (importOriginal) => {
