    expect(screen.getByText('Popular')).toBeInTheDocument();
  });
});

'use client';
import { useState, useEffect } from 'react';
import { useSearchParams } from 'next/navigation';
import { Button, Card, CardContent } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { PlanPickerClient } from './plan-picker-client';

export default function PlansPage() {
  return <PlansClient />;
}

function PlansClient() {
  const params = useSearchParams();
  const client = useApiClient();
  const [selectedPlan] = useState<string | null>(params.get('planId'));
  const [selectedRoute] = useState<string | null>(params.get('routeId'));

  const [plans, setPlans] = useState<any[] | null>(null);
  const [routes, setRoutes] = useState<any[] | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const [{ data: planData }, { data: routeData }] = await Promise.all([
          client.GET('/api/v1/plans'),
          client.GET('/api/v1/routes', { params: { query: { limit: 50 } } }),
        ]);
        if (cancelled) return;
        setPlans(planData ?? []);
        setRoutes(routeData ?? []);
        setLoading(false);
      } catch {
        if (!cancelled) { setError(true); setLoading(false); }
      }
    })();
    return () => { cancelled = true; };
  }, [client]);

  if (loading) {
    return (
      <div className="px-5 py-10 max-w-3xl mx-auto">
        <h1 className="text-xl font-semibold mb-6">Choose a plan</h1>
        <div className="grid sm:grid-cols-3 gap-4">
          {[1, 2, 3].map((i) => (
            <Card key={i}><CardContent className="h-48 animate-pulse bg-secondary/50" /></Card>
          ))}
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="px-5 py-10 max-w-3xl mx-auto text-center">
        <h1 className="text-xl font-semibold mb-4">Couldn&apos;t load plans</h1>
        <p className="text-muted-foreground mb-6">Something went wrong. Please try again.</p>
        <Button onClick={() => { setError(false); setLoading(true); setPlans(null); setRoutes(null); }}>
          Retry
        </Button>
      </div>
    );
  }

  return (
    <PlanPickerClient
      plans={plans ?? []}
      routes={routes ?? []}
      initialPlanId={selectedPlan}
      initialRouteId={selectedRoute}
    />
  );
}

'use client';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useSearchParams, useRouter } from 'next/navigation';
import { Button, Input, Label, FieldError } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';

const Schema = z.object({ corporateCode: z.string().min(2), employeeId: z.string().min(1) });

export default function CorporateOnboardPage() {
  const params = useSearchParams();
  const router = useRouter();
  const client = useApiClient();
  const { register, handleSubmit, formState: { errors, isSubmitting } } =
    useForm<z.infer<typeof Schema>>({ resolver: zodResolver(Schema), defaultValues: { corporateCode: params.get('corp') ?? '', employeeId: '' } });

  const onSubmit = async (data: z.infer<typeof Schema>) => {
    const { error } = await client.POST('/api/v1/corporate/onboard', { body: data });
    if (!error) router.push('/corporate/me?pending=1');
  };

  return (
    <div className="min-h-screen px-6 py-10 max-w-sm mx-auto">
      <h1 className="text-xl font-semibold mb-2">Link your employer</h1>
      <p className="text-sm text-muted-foreground mb-6">Your subsidy will apply once your employer approves this request.</p>
      <form onSubmit={handleSubmit(onSubmit)} noValidate className="space-y-4">
        <div><Label>Company code</Label><Input {...register('corporateCode')} aria-invalid={!!errors.corporateCode} /><FieldError>{errors.corporateCode?.message}</FieldError></div>
        <div><Label>Employee ID</Label><Input {...register('employeeId')} aria-invalid={!!errors.employeeId} /><FieldError>{errors.employeeId?.message}</FieldError></div>
        <Button type="submit" className="w-full" loading={isSubmitting}>Request link</Button>
      </form>
    </div>
  );
}

