/* app/globals.css — minimal global styles.
   The design tokens (colors, spacing, radius) live in @addis/ui/tokens.css
   which is imported by the root layout. This file only needs to set up
   box-sizing, smooth scrolling, and a few base element styles. */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
}

body {
  margin: 0;
  min-height: 100vh;
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

a {
  color: inherit;
  text-decoration: none;
}

button {
  font: inherit;
  cursor: pointer;
}

input,
textarea,
select {
  font: inherit;
}

img,
svg,
video {
  display: block;
  max-width: 100%;
}

/* Respect users who prefer reduced motion. */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

'use client';
import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useRouter } from 'next/navigation';
import { Stepper, Button, Input, Label, FieldError, PhoneInput, useToast } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';

const Schema = z.object({
  name: z.string().min(2, 'Enter your full name'),
  phone: z.string().regex(/^\+251(9|7)\d{8}$/, 'Enter a valid Ethiopian phone number'),
  password: z.string().min(10, 'At least 10 characters'),
  homeArea: z.string().min(2, 'Required'),
  workArea: z.string().min(2, 'Required'),
  tosAccepted: z.literal(true, { errorMap: () => ({ message: 'You must accept the Terms of Service' }) }),
});
type FormValues = z.infer<typeof Schema>;
const STEPS = ['Account', 'Commute', 'Review'];

function describeSignupError(err: any): string {
  const code = err?.error?.code ?? err?.code;
  const message: string | undefined = err?.error?.message ?? err?.message;
  const status: number | undefined = err?.response?.status;
  if (status === 409 || code === 'CONFLICT') {
    return 'This phone number is already registered. Try logging in instead.';
  }
  if (status === 400 || code === 'BAD_REQUEST') {
    if (message && /breach/i.test(message)) {
      return 'This password has appeared in a known data breach. Please choose a different one.';
    }
    return message ?? 'Some details are invalid. Please review and try again.';
  }
  if (status && status >= 500) {
    return 'Something went wrong on our end. Please try again in a moment.';
  }
  return message ?? 'Could not create your account. Please try again.';
}

export default function RiderSignupPage() {
  const [step, setStep] = useState(0);
  const router = useRouter();
  const client = useApiClient();
  const { push: pushToast } = useToast();

  const [serverError, setServerError] = useState<string | null>(null);
  const { register, handleSubmit, trigger, setValue, watch, formState: { errors, isSubmitting } } =
    useForm<FormValues>({ resolver: zodResolver(Schema), defaultValues: { phone: '+251' } });

  const stepFields: (keyof FormValues)[][] = [['name', 'phone', 'password'], ['homeArea', 'workArea'], ['tosAccepted']];

  const next = async () => { if (await trigger(stepFields[step])) { setServerError(null); setStep((s) => Math.min(s + 1, STEPS.length - 1)); } };
  const back = () => { setServerError(null); setStep((s) => Math.max(s - 1, 0)); };

  const onSubmit = async (data: FormValues) => {
    setServerError(null);
    const { error } = await client.POST('/api/v1/auth/register', {
      body: { kind: 'rider', name: data.name, phone: data.phone, password: data.password, homeArea: data.homeArea, workArea: data.workArea },
    });
    if (error) {

      const msg = describeSignupError(error);
      setServerError(msg);
      pushToast({ title: msg, variant: 'error' });
      return;
    }
    router.push('/login?registered=1');
  };

  return (
    <div className="min-h-screen px-6 py-10 max-w-md mx-auto">
      <Stepper steps={STEPS} current={step} />
      <form onSubmit={handleSubmit(onSubmit)} noValidate className="space-y-4">
        {step === 0 && (
          <>
            <div><Label>Full name</Label><Input {...register('name')} aria-invalid={!!errors.name} /><FieldError>{errors.name?.message}</FieldError></div>
            <PhoneInput value={watch('phone')} onChange={(v) => setValue('phone', v)} error={errors.phone?.message} />
            <div><Label>Password</Label><Input type="password" {...register('password')} aria-invalid={!!errors.password} /><FieldError>{errors.password?.message}</FieldError></div>
          </>
        )}
        {step === 1 && (
          <>
            <div><Label>Home area</Label><Input {...register('homeArea')} aria-invalid={!!errors.homeArea} /><FieldError>{errors.homeArea?.message}</FieldError></div>
            <div><Label>Work area</Label><Input {...register('workArea')} aria-invalid={!!errors.workArea} /><FieldError>{errors.workArea?.message}</FieldError></div>
          </>
        )}
        {step === 2 && (
          <>
            <div className="rounded-xl bg-secondary p-4 text-sm space-y-1">
              <p><strong>{watch('name')}</strong> · {watch('phone')}</p>
              <p>{watch('homeArea')} → {watch('workArea')}</p>
            </div>
            <label className="flex items-start gap-2 text-sm">
              <input type="checkbox" className="mt-1" {...register('tosAccepted')} />
              I agree to the <a href="/legal/terms" className="text-accent underline">Terms of Service</a> and <a href="/legal/privacy" className="text-accent underline">Privacy Policy</a>
            </label>
            <FieldError>{errors.tosAccepted?.message as string}</FieldError>
          </>
        )}

        {}
        {serverError && (
          <p role="alert" aria-live="assertive" className="text-sm text-destructive">
            {serverError}
          </p>
        )}

        <div className="flex gap-3 pt-2">
          {step > 0 && <Button type="button" variant="outline" onClick={back}>Back</Button>}
          {step < STEPS.length - 1
            ? <Button type="button" className="flex-1" onClick={next}>Continue</Button>
            : <Button type="submit" className="flex-1" loading={isSubmitting}>Create account</Button>}
        </div>
      </form>
    </div>
  );
}

'use client';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useRouter } from 'next/navigation';
import { Button, Input, Label, FieldError, PhoneInput } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';

const Schema = z.object({
  corpName: z.string().min(2),
  corpCode: z.string().min(2).max(12).regex(/^[A-Z0-9-]+$/, 'Uppercase letters, numbers, hyphens only'),
  contactEmail: z.string().email(),
  contactPhone: z.string().regex(/^\+251(9|7)\d{8}$/),
  adminName: z.string().min(2),
  adminPassword: z.string().min(10),
  subsidyPercent: z.coerce.number().min(0).max(100),
  monthlySeatAllowance: z.coerce.number().int().positive(),
});
type FormValues = z.infer<typeof Schema>;

export default function CorporateSignupPage() {
  const router = useRouter();
  const client = useApiClient();
  const { register, handleSubmit, setValue, watch, formState: { errors, isSubmitting } } =
    useForm<FormValues>({ resolver: zodResolver(Schema), defaultValues: { contactPhone: '+251', subsidyPercent: 50, monthlySeatAllowance: 20 } });

  const onSubmit = async (data: FormValues) => {
    const { error } = await client.POST('/api/v1/corporate/signup', { body: data });
    if (!error) router.push('/login?registered=1&role=corporate_admin');
  };

  return (
    <div className="min-h-screen px-6 py-10 max-w-md mx-auto">
      <h1 className="text-xl font-semibold mb-6">Register your company</h1>
      <form onSubmit={handleSubmit(onSubmit)} noValidate className="space-y-4">
        <div><Label>Company name</Label><Input {...register('corpName')} aria-invalid={!!errors.corpName} /><FieldError>{errors.corpName?.message}</FieldError></div>
        <div><Label>Company code (public, e.g. ETH-TEL)</Label><Input {...register('corpCode')} aria-invalid={!!errors.corpCode} /><FieldError>{errors.corpCode?.message}</FieldError></div>
        <div><Label>Contact email</Label><Input type="email" {...register('contactEmail')} aria-invalid={!!errors.contactEmail} /><FieldError>{errors.contactEmail?.message}</FieldError></div>
        <PhoneInput label="Contact phone" value={watch('contactPhone')} onChange={(v) => setValue('contactPhone', v)} error={errors.contactPhone?.message} />
        <div><Label>Admin full name</Label><Input {...register('adminName')} aria-invalid={!!errors.adminName} /><FieldError>{errors.adminName?.message}</FieldError></div>
        <div><Label>Admin password</Label><Input type="password" {...register('adminPassword')} aria-invalid={!!errors.adminPassword} /><FieldError>{errors.adminPassword?.message}</FieldError></div>
        <div className="grid grid-cols-2 gap-3">
          <div><Label>Subsidy %</Label><Input type="number" min={0} max={100} {...register('subsidyPercent')} /></div>
          <div><Label>Monthly seat allowance</Label><Input type="number" min={1} {...register('monthlySeatAllowance')} /></div>
        </div>
        <Button type="submit" className="w-full" loading={isSubmitting}>Register company</Button>
      </form>
    </div>
  );
}

'use client';
import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useRouter } from 'next/navigation';
import { Stepper, Button, Input, Label, FieldError, PhoneInput, FileDropzone } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';

const Schema = z.object({
  name: z.string().min(2, 'Enter your full name'),
  phone: z.string().regex(/^\+251(9|7)\d{8}$/, 'Enter a valid Ethiopian phone number'),
  password: z.string().min(10, 'At least 10 characters'),
  licenseNumber: z.string().min(3, 'Required'),
  experienceYears: z.coerce.number().int().min(0),
  tosAccepted: z.literal(true, { errorMap: () => ({ message: 'You must accept the Terms of Service' }) }),
});
type FormValues = z.infer<typeof Schema>;
const STEPS = ['Account', 'License', 'Documents', 'Review'];

export default function ContractorSignupPage() {
  const [step, setStep] = useState(0);
  const [pendingFiles, setPendingFiles] = useState<Record<string, File>>({});
  const router = useRouter();
  const client = useApiClient();
  const { register, handleSubmit, trigger, setValue, watch, formState: { errors, isSubmitting } } =
    useForm<FormValues>({ resolver: zodResolver(Schema), defaultValues: { phone: '+251', experienceYears: 0 } });

  const stepFields: (keyof FormValues)[][] = [['name', 'phone', 'password'], ['licenseNumber', 'experienceYears'], [], ['tosAccepted']];
  const next = async () => { if (await trigger(stepFields[step])) setStep((s) => Math.min(s + 1, STEPS.length - 1)); };
  const back = () => setStep((s) => Math.max(s - 1, 0));

  const onSubmit = async (data: FormValues) => {
    const { data: res, error } = await client.POST('/api/v1/auth/register', {
      body: { kind: 'contractor', name: data.name, phone: data.phone, password: data.password, licenseNumber: data.licenseNumber, experienceYears: data.experienceYears },
    });
    if (error) return;

    const token = (res as any)?.accessToken;
    if (token && Object.keys(pendingFiles).length > 0) {
      for (const [type, file] of Object.entries(pendingFiles)) {
        const form = new FormData();
        form.append('type', type); form.append('file', file);
        const r = await fetch('/api/v1/contractors/documents', {
          method: 'POST', body: form, headers: { Authorization: `Bearer ${token}` },
        });
        if (!r.ok) {

          console.warn(`Failed to upload ${type} during signup (HTTP ${r.status}) — please upload via the contractor dashboard after logging in.`);
        }
      }
    }
    router.push('/login?registered=1&role=contractor');
  };

  return (
    <div className="min-h-screen px-6 py-10 max-w-md mx-auto">
      <Stepper steps={STEPS} current={step} />
      <form onSubmit={handleSubmit(onSubmit)} noValidate className="space-y-4">
        {step === 0 && (
          <>
            <div><Label>Full name</Label><Input {...register('name')} aria-invalid={!!errors.name} /><FieldError>{errors.name?.message}</FieldError></div>
            <PhoneInput value={watch('phone')} onChange={(v) => setValue('phone', v)} error={errors.phone?.message} />
            <div><Label>Password</Label><Input type="password" {...register('password')} aria-invalid={!!errors.password} /><FieldError>{errors.password?.message}</FieldError></div>
          </>
        )}
        {step === 1 && (
          <>
            <div><Label>Driving license number</Label><Input {...register('licenseNumber')} aria-invalid={!!errors.licenseNumber} /><FieldError>{errors.licenseNumber?.message}</FieldError></div>
            <div><Label>Years of experience</Label><Input type="number" min={0} {...register('experienceYears')} /><FieldError>{errors.experienceYears?.message}</FieldError></div>
          </>
        )}
        {step === 2 && (
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">You can also upload these later from your dashboard.</p>
            <FileDropzone label="Vehicle registration" onFile={(f) => setPendingFiles((p) => ({ ...p, registration: f }))} />
            <FileDropzone label="Insurance certificate" onFile={(f) => setPendingFiles((p) => ({ ...p, insurance: f }))} />
            <FileDropzone label="Inspection certificate" onFile={(f) => setPendingFiles((p) => ({ ...p, inspection: f }))} />
          </div>
        )}
        {step === 3 && (
          <>
            <div className="rounded-xl bg-secondary p-4 text-sm space-y-1">
              <p><strong>{watch('name')}</strong> · {watch('phone')}</p>
              <p>License: {watch('licenseNumber')} · {watch('experienceYears')} yrs experience</p>
              <p>{Object.keys(pendingFiles).length} document(s) ready to upload</p>
            </div>
            <label className="flex items-start gap-2 text-sm">
              <input type="checkbox" className="mt-1" {...register('tosAccepted')} />
              I agree to the <a href="/legal/terms" className="text-accent underline">Terms of Service</a>
            </label>
            <FieldError>{errors.tosAccepted?.message as string}</FieldError>
          </>
        )}

        <div className="flex gap-3 pt-2">
          {step > 0 && <Button type="button" variant="outline" onClick={back}>Back</Button>}
          {step < STEPS.length - 1
            ? <Button type="button" className="flex-1" onClick={next}>Continue</Button>
            : <Button type="submit" className="flex-1" loading={isSubmitting}>Create account</Button>}
        </div>
      </form>
    </div>
  );
}

import type { Metadata } from 'next';
import { cookies, headers } from 'next/headers';
import { Providers } from './providers';
import '@addis/ui/tokens.css';
import './globals.css';

export const metadata: Metadata = { title: 'Addis Ride', description: 'Subscription commuting for Addis Ababa' };

export default async function RootLayout({ children }: { children: React.ReactNode }) {
  const cookieStore = await cookies();
  const theme = cookieStore.get('addis-ride-theme')?.value ?? 'dark';
  const locale = cookieStore.get('addis-ride-locale')?.value
    ?? ((await headers()).get('accept-language')?.startsWith('am') ? 'am' : 'en');

  return (
    <html lang={locale} data-theme={theme} suppressHydrationWarning>
      <body>
        <Providers initialLocale={locale as 'en' | 'am'} initialTheme={theme as 'dark' | 'light'}>
          {children}
        </Providers>
      </body>
    </html>
  );
}

import { redirect } from 'next/navigation';
import { auth } from '@/auth';

export default async function RiderDashboardLayout({ children }: { children: React.ReactNode }) {
  const session = await auth();
  if (!session) redirect('/login?next=/dashboard/rider');
  const role = (session as any)?.role;
  if (role === 'contractor') redirect('/dashboard/contractor');
  if (role === 'corporate_admin') redirect('/dashboard/corporate');
  if (role === 'platform_admin') redirect('/admin');
  if (role !== 'rider') {
    return (
      <div className="flex min-h-screen items-center justify-center px-6">
        <div className="text-center max-w-sm">
          <h1 className="text-xl font-semibold mb-2">Access denied</h1>
          <p className="text-sm text-muted-foreground">Your account does not have access to the rider dashboard.</p>
        </div>
      </div>
    );
  }
  return <>{children}</>;
}

'use client';
import { useEffect } from 'react';
import * as Sentry from '@sentry/nextjs';
import { Button } from '@addis/ui';
import { AlertTriangle } from 'lucide-react';

export default function Error({ error, reset }: { error: Error & { digest?: string }; reset: () => void }) {
  useEffect(() => { Sentry.captureException(error); }, [error]);
  return (
    <div className="flex flex-col items-center justify-center py-24 text-center px-6">
      <AlertTriangle className="h-8 w-8 text-destructive mb-3" />
      <p className="font-semibold">Something went wrong</p>
      <p className="text-sm text-muted-foreground mt-1">{error.digest ? `Reference: ${error.digest}` : 'Please try again.'}</p>
      <Button className="mt-4" onClick={reset}>Try again</Button>
    </div>
  );
}

'use client';
import { useQuery } from '@tanstack/react-query';
import Link from 'next/link';
import { Bus, Bell, MapPin, ArrowRight } from 'lucide-react';
import { Button, Card, CardContent, Skeleton, Badge } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';

export default function RiderDashboardPage() {
  const client = useApiClient();

  const { data, isLoading } = useQuery({
    queryKey: ['rider-dashboard'],
    queryFn: async () => (await client.GET('/api/v1/dashboard/rider')).data,
  });

  const d = data as
    | {
        activeSubscription?: {
          id: string;
          status: string;
          ridesUsed: number;
          plan: { name: string; ridesIncluded: number };
          route: { name: string; id: string } | null;
          endDate: string;
        } | null;
        unreadNotifications: number;
      }
    | undefined;

  return (
    <div className="px-5 py-6 max-w-2xl mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-semibold leading-tight">Every commute starts with a confirmed seat.</h1>
        <p className="text-sm text-muted-foreground mt-1">Welcome back. Manage your subscription, track shuttles, and ride.</p>
      </div>

      {isLoading ? (
        <Card><CardContent className="space-y-3">
          <Skeleton className="h-4 w-32" />
          <Skeleton className="h-6 w-48" />
          <Skeleton className="h-10 w-full rounded-full" />
        </CardContent></Card>
      ) : d?.activeSubscription ? (
        <Card>
          <CardContent className="space-y-3">
            <div className="flex items-center justify-between">
              <p className="text-sm text-muted-foreground">Active plan</p>
              <Badge variant="success">{d.activeSubscription.status.replace('_', ' ')}</Badge>
            </div>
            <p className="text-lg font-semibold">{d.activeSubscription.plan.name}</p>
            <p className="text-sm text-muted-foreground flex items-center gap-1">
              <MapPin className="h-3 w-3" /> {d.activeSubscription.route?.name ?? '—'}
            </p>
            <p className="text-sm">
              {d.activeSubscription.ridesUsed} /{' '}
              {d.activeSubscription.plan.ridesIncluded === -1
                ? '∞'
                : d.activeSubscription.plan.ridesIncluded}{' '}
              rides used
            </p>
            <Link href={`/dashboard/rider/active-trip?subscriptionId=${d.activeSubscription.id}`}>
              <Button className="w-full">
                <Bus className="h-4 w-4" /> Track today's shuttle
              </Button>
            </Link>
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardContent className="space-y-3 text-center">
            <p className="font-medium">No active subscription</p>
            <p className="text-sm text-muted-foreground">Browse plans to reserve your daily seat.</p>
            <Link href="/plans">
              <Button className="w-full">
                See plans <ArrowRight className="h-4 w-4" />
              </Button>
            </Link>
          </CardContent>
        </Card>
      )}

      <div className="grid grid-cols-2 gap-3">
        <Link href="/open-seats">
          <Card className="h-full hover:border-primary transition-colors cursor-pointer">
            <CardContent className="space-y-1">
              <Bus className="h-5 w-5 text-primary" />
              <p className="font-medium text-sm">Open seats</p>
              <p className="text-xs text-muted-foreground">Claim a released seat for today.</p>
            </CardContent>
          </Card>
        </Link>
        <Link href="/notifications">
          <Card className="h-full hover:border-primary transition-colors cursor-pointer">
            <CardContent className="space-y-1">
              <Bell className="h-5 w-5 text-primary" />
              <p className="font-medium text-sm">Notifications</p>
              <p className="text-xs text-muted-foreground">
                {d?.unreadNotifications ? `${d.unreadNotifications} unread` : 'No unread'}
              </p>
            </CardContent>
          </Card>
        </Link>
      </div>
    </div>
  );
}

