export default async function ContractorDashboardLayout({ children }: { children: React.ReactNode }) {
  const session = await auth();
  if (!session) redirect('/login?next=/dashboard/contractor');
  const role = (session as any)?.role;
  if (role !== 'contractor') {
    return (
      <div className="flex min-h-screen items-center justify-center px-6">
        <div className="text-center max-w-sm">
          <h1 className="text-xl font-semibold mb-2">Access denied</h1>
          <p className="text-sm text-muted-foreground">
            The contractor dashboard is only available to verified contractor accounts.
          </p>
        </div>
      </div>
    );
  }
  return <>{children}</>;
}

'use client';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { FileDropzone, Card, CardContent, Badge } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';

const DOC_TYPES = [
  { key: 'registration', label: 'Vehicle registration' },
  { key: 'insurance', label: 'Insurance certificate' },
  { key: 'inspection', label: 'Inspection certificate' },
] as const;

export default function ContractorDocumentsPage() {
  const client = useApiClient();
  const qc = useQueryClient();
  const { data: docs } = useQuery({ queryKey: ['contractor-docs'], queryFn: async () => (await client.GET('/api/v1/contractors/documents')).data });

  const upload = useMutation({
    mutationFn: async ({ type, file }: { type: string; file: File }) => {
      const form = new FormData();
      form.append('type', type); form.append('file', file);
      return fetch('/api/v1/contractors/documents', { method: 'POST', body: form });
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['contractor-docs'] }),
  });

  const uploadedTypes = new Set((docs ?? []).map((d: any) => d.type));

  return (
    <div className="px-5 py-6 max-w-md mx-auto space-y-6">
      <h1 className="text-xl font-semibold">Verification documents</h1>
      {DOC_TYPES.map((dt) => (
        <div key={dt.key}>
          {uploadedTypes.has(dt.key) ? (
            <Card><CardContent className="flex items-center justify-between">
              <span className="text-sm">{dt.label}</span>
              <Badge variant="success">Uploaded</Badge>
            </CardContent></Card>
          ) : (
            <FileDropzone label={dt.label} onFile={(file) => upload.mutate({ type: dt.key, file })} />
          )}
        </div>
      ))}
    </div>
  );
}

'use client';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Card, CardContent, Button, StatTile, useToast } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { useFormatMoney } from '@addis/i18n';

export default function ContractorDashboardPage() {
  const client = useApiClient();
  const qc = useQueryClient();
  const { push } = useToast();
  const money = useFormatMoney();
  const { data } = useQuery({ queryKey: ['contractor-dashboard'], queryFn: async () => (await client.GET('/api/v1/dashboard/contractor')).data });

  const startTrip = useMutation({

    mutationFn: async (input: { shuttleId: string; routeId: string; window: 'morning' | 'evening' }) =>
      client.POST('/api/v1/trips', { body: input } as any),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['contractor-dashboard'] });
      push({ title: 'Trip started' });
    },
    onError: (err: any) => {
      push({ title: err?.message ?? 'Could not start trip', variant: 'error' });
    },
  });

  const d = data as any;
  const shuttleId = d?.shuttleId;
  const routeId = d?.routeId;
  const canStart = shuttleId && routeId && d?.verificationStatus === 'verified';

  return (
    <div className="px-5 py-6 max-w-2xl mx-auto space-y-6">
      <h1 className="text-xl font-semibold">Contractor dashboard</h1>

      <div className="grid grid-cols-3 gap-3">
        <StatTile label="Verification" value={d?.verificationStatus ?? '—'} />
        <StatTile label="Rating" value={`★ ${d?.rating ?? '5.0'}`} />
        <StatTile label="This month" value={money(d?.earningsThisMonth ?? 0)} />
      </div>

      {d?.verificationStatus !== 'verified' ? (
        <Card><CardContent>
          <p className="font-medium">Verification required</p>
          <p className="text-sm text-muted-foreground">Upload your documents to start running trips.</p>
          <a href="/dashboard/contractor/documents" className="text-accent text-sm">Upload documents →</a>
        </CardContent></Card>
      ) : (
        <Card><CardContent>
          <p className="font-medium mb-2">Start today's trip</p>
          {!canStart && (
            <p className="text-sm text-muted-foreground mb-2">No shuttle/route assigned. Contact your platform admin.</p>
          )}
          <div className="flex gap-2">
            <Button
              onClick={() => startTrip.mutate({ shuttleId, routeId, window: 'morning' })}
              disabled={!canStart || startTrip.isPending}
              loading={startTrip.isPending}
            >
              Start morning trip
            </Button>
            <Button
              variant="outline"
              onClick={() => startTrip.mutate({ shuttleId, routeId, window: 'evening' })}
              disabled={!canStart || startTrip.isPending}
            >
              Start evening trip
            </Button>
          </div>
        </CardContent></Card>
      )}
    </div>
  );
}

