'use client';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Bell, BellOff } from 'lucide-react';
import { EmptyState, Card, CardContent } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { cn } from '@addis/ui';

export default function NotificationsPage() {
  const client = useApiClient();
  const qc = useQueryClient();
  const { data, isLoading } = useQuery({ queryKey: ['notifications'], queryFn: async () => (await client.GET('/api/v1/notifications')).data });
  const markRead = useMutation({
    // FE-005: the API ignores the body and sets readAt server-side — don't
    // send a body at all (was sending { readAt: ... } which was misleading).
    mutationFn: (id: string) => client.PATCH('/api/v1/notifications/{id}', { params: { path: { id } } }),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['notifications'] }),
  });

  if (!isLoading && !data?.length) return <EmptyState icon={BellOff} title="No notifications" description="You're all caught up." />;

  return (
    <div className="px-5 py-6 max-w-2xl mx-auto space-y-2">
      <h1 className="text-xl font-semibold mb-4">Notifications</h1>
      {(data ?? []).map((n: any) => (
        <Card key={n.id} onClick={() => !n.readAt && markRead.mutate(n.id)}
          className={cn('cursor-pointer', !n.readAt && 'border-primary')}>
          <CardContent className="flex gap-3">
            <Bell className={cn('h-4 w-4 mt-0.5', !n.readAt ? 'text-primary' : 'text-muted-foreground')} />
            <div>
              <p className="font-medium text-sm">{n.title}</p>
              <p className="text-xs text-muted-foreground">{n.body}</p>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

'use client';
import { useEffect } from 'react';
import * as Sentry from '@sentry/nextjs';
import { Button } from '@addis/ui';
import { AlertTriangle } from 'lucide-react';

export default function GlobalError({ error, reset }: { error: Error & { digest?: string }; reset: () => void }) {
  useEffect(() => {
    Sentry.captureException(error);
  }, [error]);

  return (
    <html>
      <body>
        <div className="min-h-screen flex items-center justify-center px-6">
          <div className="text-center max-w-sm space-y-4">
            <AlertTriangle className="h-10 w-10 text-destructive mx-auto" />
            <h1 className="text-xl font-semibold">Something went wrong</h1>
            <p className="text-sm text-muted-foreground">
              {error.digest
                ? `Reference: ${error.digest}`
                : 'An unexpected error occurred. Please try again.'}
            </p>
            <Button onClick={reset}>Try again</Button>
          </div>
        </div>
      </body>
    </html>
  );
}

'use client';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useState } from 'react';
import { Button, DataTable, Badge, type Column } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { useToast } from '@addis/ui';

type Contractor = { id: string; licenseNumber: string; verificationStatus: string; experienceYears: number };

export default function AdminContractorsPage() {
  const client = useApiClient();
  const qc = useQueryClient();
  const { push } = useToast();
  const [rejectingId, setRejectingId] = useState<string | null>(null);
  const [reason, setReason] = useState('');

  const { data, isLoading } = useQuery({ queryKey: ['admin-contractors-pending'], queryFn: async () => (await client.GET('/api/v1/admin/contractors/pending')).data });

  const verify = useMutation({
    mutationFn: (id: string) => client.POST('/api/v1/admin/contractors/{id}/verify', { params: { path: { id } } }),
    onSuccess: () => { qc.invalidateQueries({ queryKey: ['admin-contractors-pending'] }); push({ title: 'Contractor verified', variant: 'success' }); },
  });
  const reject = useMutation({
    mutationFn: () => client.POST('/api/v1/admin/contractors/{id}/reject', { params: { path: { id: rejectingId! } }, body: { reason } }),
    onSuccess: () => { setRejectingId(null); setReason(''); qc.invalidateQueries({ queryKey: ['admin-contractors-pending'] }); },
  });

  const columns: Column<Contractor>[] = [
    { key: 'licenseNumber', header: 'License #' },
    { key: 'experienceYears', header: 'Experience (yrs)' },
    { key: 'verificationStatus', header: 'Status', render: (c) => <Badge variant="warning">{c.verificationStatus}</Badge> },
    {
      key: 'id', header: 'Actions',
      render: (c) => (
        <div className="flex gap-2">
          {/* FE-008: the previous "View docs" link pointed to /admin/contractors/${c.id}
              which doesn't exist. Removed — admins use the API directly to view
              documents, or the verify/reject flow below which already requires
              reviewing the documents out-of-band. */}
          <Button
            size="sm"
            loading={verify.isPending && verify.variables === c.id}
            onClick={() => {

              if (window.confirm(`Verify contractor ${c.licenseNumber}? Make sure you've reviewed their documents.`)) {
                verify.mutate(c.id);
              }
            }}
          >
            Verify
          </Button>
          <Button size="sm" variant="outline" onClick={() => setRejectingId(c.id)}>Reject</Button>
        </div>
      ),
    },
  ];

  return (
    <div className="space-y-4">
      <h1 className="text-xl font-semibold">Pending contractor verifications</h1>
      <DataTable columns={columns} rows={(data ?? []) as Contractor[]} loading={isLoading} />

      {rejectingId && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-6" role="dialog" aria-modal>
          <div className="bg-card rounded-2xl p-6 w-full max-w-sm space-y-3">
            <p className="font-semibold">Reject contractor</p>
            <textarea className="w-full rounded-xl border border-border p-3 text-sm" rows={3} placeholder="Reason for rejection…" value={reason} onChange={(e) => setReason(e.target.value)} />
            <div className="flex justify-end gap-2">
              <Button variant="outline" onClick={() => setRejectingId(null)}>Cancel</Button>
              <Button variant="destructive" disabled={reason.length < 3} loading={reject.isPending} onClick={() => reject.mutate()}>Reject</Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Card, CardContent, Badge, Button } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { useFormatMoney } from '@addis/i18n';

export default function AdminPlansPage() {
  const client = useApiClient();
  const qc = useQueryClient();
  const money = useFormatMoney();
  const { data } = useQuery({ queryKey: ['admin-plans'], queryFn: async () => (await client.GET('/api/v1/plans')).data });
  const toggle = useMutation({
    mutationFn: ({ id, isActive }: { id: string; isActive: boolean }) => client.PATCH('/api/v1/admin/plans/{id}', { params: { path: { id } }, body: { isActive } }),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['admin-plans'] }),
  });

  return (
    <div className="space-y-4">
      <h1 className="text-xl font-semibold">Plans</h1>
      <div className="grid sm:grid-cols-3 gap-4">
        {(data ?? []).map((p: any) => (
          <Card key={p.id}>
            <CardContent className="space-y-2">
              <div className="flex items-center justify-between">
                <p className="font-medium">{p.name}</p>
                {p.isPopular && <Badge>Popular</Badge>}
              </div>
              <p className="text-2xl font-semibold">{money(p.priceETB)}</p>
              <p className="text-sm text-muted-foreground">{p.durationDays} days · {p.ridesIncluded === -1 ? 'Unlimited' : `${p.ridesIncluded} rides`}</p>
              <Button size="sm" variant="outline" onClick={() => toggle.mutate({ id: p.id, isActive: !p.isActive })}>
                {p.isActive ? 'Deactivate' : 'Activate'}
              </Button>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
}

'use client';
import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { DataTable, Badge, Button, type Column } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { useFormatMoney } from '@addis/i18n';

type PaymentRow = { id: string; riderId: string; amount: string; method: string; status: string; reference: string; createdAt: string };
const STATUS_VARIANT: Record<string, any> = { completed: 'success', pending: 'warning', failed: 'destructive', refunded: 'secondary', partially_refunded: 'secondary' };

export default function AdminPaymentsPage() {
  const client = useApiClient();
  const qc = useQueryClient();
  const money = useFormatMoney();
  const [statusFilter, setStatusFilter] = useState<string>('');
  const { data, isLoading } = useQuery({
    queryKey: ['admin-payments', statusFilter],
    queryFn: async () => (await client.GET('/api/v1/admin/payments', { params: { query: { limit: 50, status: statusFilter || undefined } } })).data,
  });
  const verifyCbe = useMutation({

    mutationFn: (input: { id: string; verifiedAmount: string; reason: string }) =>
      client.POST('/api/v1/admin/payments/{id}/verify', {
        params: { path: { id: input.id } },
        headers: { 'Idempotency-Key': `cbe-verify:${input.id}` },
        body: { verifiedAmount: input.verifiedAmount, reason: input.reason },
      } as any),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['admin-payments'] }),
  });

  const columns: Column<PaymentRow>[] = [
    { key: 'reference', header: 'Reference' },
    { key: 'amount', header: 'Amount', render: (p) => money(p.amount) },
    { key: 'method', header: 'Method', render: (p) => <Badge variant="secondary">{p.method}</Badge> },
    { key: 'status', header: 'Status', render: (p) => <Badge variant={STATUS_VARIANT[p.status]}>{p.status}</Badge> },
    { key: 'createdAt', header: 'Date', render: (p) => new Date(p.createdAt).toLocaleDateString() },
    { key: 'id', header: 'Actions', render: (p) => p.method === 'cbe' && p.status === 'pending'
      ? <Button size="sm"
          loading={verifyCbe.isPending && verifyCbe.variables?.id === p.id}
          onClick={() => {

            const verifiedAmount = window.prompt(
              `Manually verify payment ${p.reference}\n\nExpected: ETB ${p.amount}\n\nEnter the verified amount (ETB) the bank confirmed:`,
              p.amount,
            );
            if (verifiedAmount === null) return;
            const reason = window.prompt('Reason (required, audited):', 'Manual bank transfer confirmation');
            if (!reason) return;
            verifyCbe.mutate({ id: p.id, verifiedAmount, reason });
          }}>
          Verify manually
        </Button> : null },
  ];

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">Payments</h1>
        <select className="rounded-xl border border-border bg-card px-3 py-2 text-sm" value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
          <option value="">All statuses</option>
          {['pending', 'completed', 'failed', 'refunded', 'partially_refunded'].map((s) => <option key={s} value={s}>{s}</option>)}
        </select>
      </div>
      <DataTable columns={columns} rows={(data ?? []) as PaymentRow[]} loading={isLoading} />
    </div>
  );
}

import Link from 'next/link';
import { redirect } from 'next/navigation';
import { LayoutDashboard, Users, Route, Bus, ShieldCheck, CreditCard, Ticket, HelpCircle, FileClock } from 'lucide-react';
import { auth } from '../../auth';

const NAV = [
  { href: '/admin', label: 'Dashboard', icon: LayoutDashboard },
  { href: '/admin/users', label: 'Users', icon: Users },
  { href: '/admin/routes', label: 'Routes', icon: Route },
  { href: '/admin/shuttles', label: 'Shuttles', icon: Bus },
  { href: '/admin/contractors', label: 'Contractors', icon: ShieldCheck },
  { href: '/admin/payments', label: 'Payments', icon: CreditCard },
  { href: '/admin/tickets', label: 'Tickets', icon: Ticket },
  { href: '/admin/faq', label: 'FAQ', icon: HelpCircle },
  { href: '/admin/audit-logs', label: 'Audit log', icon: FileClock },
];

export default async function AdminLayout({ children }: { children: React.ReactNode }) {

  const session = await auth();
  if (!session) {
    redirect('/login?next=/admin');
  }
  const role = (session as any).role;
  if (role !== 'platform_admin') {
    redirect('/dashboard/' + (role ?? 'rider'));
  }

  return (
    <div className="flex min-h-screen">
      <aside className="w-56 border-r border-border p-4 hidden md:block">
        <p className="font-semibold mb-6 px-2">Addis Ride Admin</p>
        <nav className="space-y-1">
          {NAV.map(({ href, label, icon: Icon }) => (
            <Link key={href} href={href} className="flex items-center gap-2 px-2 py-2 rounded-lg text-sm hover:bg-secondary">
              <Icon className="h-4 w-4" /> {label}
            </Link>
          ))}
        </nav>
      </aside>
      <main className="flex-1 p-6">{children}</main>
    </div>
  );
}

'use client';
import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Plus, Trash2 } from 'lucide-react';
import { Button, Card, CardContent, Input, Label } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';

export default function AdminFaqPage() {
  const client = useApiClient();
  const qc = useQueryClient();
  const [form, setForm] = useState({ category: 'general', question: '', answer: '' });
  const [showForm, setShowForm] = useState(false);

  const { data } = useQuery({ queryKey: ['admin-faq'], queryFn: async () => (await client.GET('/api/v1/faq')).data });
  const create = useMutation({
    mutationFn: () => client.POST('/api/v1/admin/faq', { body: form }),
    onSuccess: () => { qc.invalidateQueries({ queryKey: ['admin-faq'] }); setShowForm(false); setForm({ category: 'general', question: '', answer: '' }); },
  });
  const remove = useMutation({
    mutationFn: (id: string) => client.DELETE('/api/v1/admin/faq/{id}', { params: { path: { id } } }),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['admin-faq'] }),
  });

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">FAQ</h1>
        <Button size="sm" onClick={() => setShowForm((s) => !s)}><Plus className="h-4 w-4" />New article</Button>
      </div>
      {showForm && (
        <div className="rounded-2xl border border-border p-4 space-y-3">
          <div><Label>Category</Label>
            <select className="w-full rounded-xl border border-border bg-card p-2" value={form.category} onChange={(e) => setForm((f) => ({ ...f, category: e.target.value }))}>
              {['billing', 'routes', 'shuttle', 'account', 'corporate', 'general'].map((c) => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div><Label>Question</Label><Input value={form.question} onChange={(e) => setForm((f) => ({ ...f, question: e.target.value }))} /></div>
          <div><Label>Answer</Label><textarea className="w-full rounded-xl border border-border bg-card p-3 text-sm" rows={3} value={form.answer} onChange={(e) => setForm((f) => ({ ...f, answer: e.target.value }))} /></div>
          <div className="flex justify-end gap-2">
            <Button variant="outline" onClick={() => setShowForm(false)}>Cancel</Button>
            <Button loading={create.isPending} onClick={() => create.mutate()}>Save</Button>
          </div>
        </div>
      )}
      <div className="space-y-2">
        {(data ?? []).map((a: any) => (
          <Card key={a.id}><CardContent className="flex items-start justify-between">
            <div><p className="font-medium">{a.question}</p><p className="text-sm text-muted-foreground">{a.answer}</p></div>
            <button
              onClick={() => {

                if (window.confirm(`Delete FAQ article "${a.question}"?`)) {
                  remove.mutate(a.id);
                }
              }}
              aria-label="Delete"
            >
              <Trash2 className="h-4 w-4 text-destructive" />
            </button>
          </CardContent></Card>
        ))}
      </div>
    </div>
  );
}

