'use client';
import { useState } from 'react';
import { Download } from 'lucide-react';
import { Button, useToast } from '@addis/ui';

export default function AccountExportPage() {
  const [loading, setLoading] = useState(false);
  const { push } = useToast();

  const download = async (format: 'json' | 'csv') => {
    setLoading(true);
    try {
      const res = await fetch(`/api/v1/account/export?format=${format}`);

      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        push({ title: err?.error?.message ?? `Export failed (HTTP ${res.status})`, variant: 'error' });
        return;
      }
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `addis-ride-export-${format}.zip`;
      a.click();
      URL.revokeObjectURL(url);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="px-6 py-16 max-w-md mx-auto text-center space-y-4">
      <Download className="h-8 w-8 mx-auto text-primary" />
      <h1 className="font-semibold text-lg">Export your data</h1>
      <p className="text-sm text-muted-foreground">
        Download a full copy of your profile, subscriptions, payments, rides, and support tickets — per Ethiopia&apos;s Data Protection Proclamation.
      </p>
      <div className="flex gap-3 justify-center">
        <Button loading={loading} onClick={() => download('json')}>Download JSON</Button>
        <Button variant="outline" loading={loading} onClick={() => download('csv')}>Download CSV</Button>
      </div>
    </div>
  );
}

'use client';
import { useState } from 'react';
import { AlertTriangle } from 'lucide-react';
import { Button, Input, Label, FieldError, useToast } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { ACCOUNT_DELETION_GRACE_DAYS } from '@addis/shared';

export default function DeleteAccountPage() {
  const client = useApiClient();
  const { push } = useToast();
  const [confirmed, setConfirmed] = useState(false);
  const [password, setPassword] = useState('');
  const [requested, setRequested] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const submit = async () => {

    if (!password) {
      setError('Password is required to confirm deletion');
      return;
    }
    setLoading(true);
    setError(null);
    try {

      const { error: apiError } = await client.POST('/api/v1/account/delete', {
        body: { password },
      });
      if (apiError) {
        const msg = (apiError as any)?.error?.message ?? (apiError as any)?.message ?? 'Password incorrect';
        setError(msg);
        push({ title: 'Deletion failed', variant: 'error' });
        return;
      }
      setRequested(true);
    } catch (e) {
      setError('Network error — please try again');
    } finally {
      setLoading(false);
    }
  };

  if (requested) {
    return (
      <div className="px-6 py-16 text-center max-w-md mx-auto">
        <p className="font-semibold">Deletion requested</p>
        <p className="text-sm text-muted-foreground mt-2">
          Your account is scheduled for permanent anonymization in {ACCOUNT_DELETION_GRACE_DAYS} days. To cancel,
          contact support within that window — you will not be able to log in to self-cancel.
        </p>
      </div>
    );
  }

  return (
    <div className="px-6 py-16 max-w-md mx-auto">
      <AlertTriangle className="h-8 w-8 text-destructive mx-auto mb-3" />
      <h1 className="font-semibold text-lg text-center">Delete your account?</h1>
      <p className="text-sm text-muted-foreground mt-2 text-center">
        This starts a {ACCOUNT_DELETION_GRACE_DAYS}-day grace period during which your account is deactivated.
        You cannot log in during this time. To cancel, contact support. Payment records are
        retained 7 years per Ethiopian tax law, anonymized.
      </p>
      <div className="mt-6 space-y-3">
        <div>
          <Label htmlFor="password">Enter your password to confirm</Label>
          <Input
            id="password"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            autoComplete="current-password"
          />
        </div>
        <label className="flex items-center gap-2 text-sm">
          <input type="checkbox" checked={confirmed} onChange={(e) => setConfirmed(e.target.checked)} />
          I understand this cannot be undone after the grace period.
        </label>
        {error && <FieldError>{error}</FieldError>}
        <Button
          variant="destructive"
          className="w-full"
          disabled={!confirmed || !password || loading}
          loading={loading}
          onClick={submit}
        >
          Request deletion
        </Button>
      </div>
    </div>
  );
}

'use client';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useQuery } from '@tanstack/react-query';
import { useEffect } from 'react';
import { Button, Input, Label, LocaleSwitcher } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { useTheme } from '../theme-provider';
import { useToast } from '@addis/ui';

// FE-007: explicit Zod schema for the account form. The previous code used
// useForm() with no schema, dynamically registering fields — risky if the
// `me` response contained extra fields (phone, role) that the user could
// accidentally submit. The server uses .strict() so it would reject them,
// but the client now sends only the three editable fields.
const AccountSchema = z.object({
  name: z.string().min(2).max(200).optional(),
  homeArea: z.string().min(2).max(200).optional(),
  workArea: z.string().min(2).max(200).optional(),
}).strict();
type AccountForm = z.infer<typeof AccountSchema>;

export default function AccountPage() {
  const client = useApiClient();
  const { theme, toggle } = useTheme();
  const { push } = useToast();
  const { data: me } = useQuery({ queryKey: ['me'], queryFn: async () => (await client.GET('/api/v1/account')).data });
  const { register, handleSubmit, reset, formState: { isSubmitting, isDirty } } = useForm<AccountForm>({
    resolver: zodResolver(AccountSchema),
  });

  useEffect(() => {
    if (me) {
      // Only populate the editable fields — don't copy phone/role/etc.
      const editable = (me as any)?.data ?? me;
      reset({ name: editable?.name, homeArea: editable?.profile?.homeArea, workArea: editable?.profile?.workArea });
    }
  }, [me, reset]);

  const onSubmit = async (data: AccountForm) => {
    const { error } = await client.PATCH('/api/v1/account', { body: data });
    push(error ? { title: 'Update failed', variant: 'error' } : { title: 'Profile updated', variant: 'success' });
  };

  return (
    <div className="px-5 py-6 max-w-md mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">Account</h1>
        <div className="flex items-center gap-2">
          <LocaleSwitcher />
          <Button variant="outline" size="sm" onClick={toggle}>{theme === 'dark' ? 'Light' : 'Dark'} mode</Button>
        </div>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
        <div><Label>Full name</Label><Input {...register('name')} /></div>
        <div><Label>Home area</Label><Input {...register('homeArea')} /></div>
        <div><Label>Work area</Label><Input {...register('workArea')} /></div>
        <Button type="submit" disabled={!isDirty} loading={isSubmitting}>Save changes</Button>
      </form>

      <div className="border-t border-border pt-4 space-y-2">
        <a href="/account/export" className="block text-sm text-accent">Export my data</a>
        <a href="/account/delete" className="block text-sm text-destructive">Delete my account</a>
      </div>
    </div>
  );
}

'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { signOut } from 'next-auth/react';
import { Button } from '@addis/ui';
import { useApiClient } from '@/lib/sdk';
import { useToast } from '@addis/ui';
import { CURRENT_TOS_VERSION } from '@addis/shared';

export default function TosAcceptPage() {
  const client = useApiClient();
  const router = useRouter();
  const { push } = useToast();
  const [loading, setLoading] = useState(false);

  const accept = async () => {
    setLoading(true);
    // API-001: /api/v1/tos is not yet in the generated OpenAPI schema (the
    // route uses .post() instead of .openapi()). Cast to bypass the typed
    // client until the route is migrated. The server validates the body.
    const { error } = await (client.POST as any)('/api/v1/tos', { body: { version: CURRENT_TOS_VERSION } });
    setLoading(false);
    if (error) {
      push({ title: error?.message ?? 'Could not accept terms — please try again', variant: 'error' });
      return;
    }

    router.push('/dashboard/rider');
  };

  const decline = async () => {

    await signOut({ callbackUrl: '/login?reason=tos_declined' });
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-6">
      <div className="max-w-md text-center space-y-4">
        <h1 className="text-xl font-semibold">Our Terms of Service have been updated</h1>
        <p className="text-sm text-muted-foreground">
          Please review the updated <a href="/legal/terms" target="_blank" rel="noopener" className="text-accent underline">Terms of Service</a> and
          {' '}<a href="/legal/privacy" target="_blank" rel="noopener" className="text-accent underline">Privacy Policy</a> to continue using Addis Ride.
        </p>
        <div className="flex gap-3 justify-center pt-4">
          <Button onClick={accept} loading={loading}>I accept the updated terms</Button>
          <Button variant="outline" onClick={decline} disabled={loading}>Decline and log out</Button>
        </div>
        <p className="text-xs text-muted-foreground pt-2">
          Declining logs you out. Your account remains intact; you can return to accept the terms at any time.
        </p>
      </div>
    </div>
  );
}

'use client';
import { Suspense } from 'react';
import { useSearchParams } from 'next/navigation';

// FE-004: Next.js 15+ requires client components using useSearchParams to be
// wrapped in <Suspense> — otherwise the page deopts to client-side rendering
// and may fail with DynamicServerError in static generation. Wrap the inner
// component in Suspense.

function TelebirrStubInner() {
  if (process.env.NEXT_PUBLIC_TELEBIRR_ENV === 'production' || process.env.NODE_ENV === 'production') {
    return (
      <div className="min-h-screen flex items-center justify-center px-6">
        <p className="text-muted-foreground">This page is not available in production.</p>
      </div>
    );
  }
  const params = useSearchParams();
  const merchOrderId = params.get('merch_order_id') ?? params.get('out_request_no') ?? '';
  const amount = params.get('total_amount') ?? '';

  return (
    <div className="min-h-screen flex items-center justify-center px-6">
      <div className="max-w-sm w-full space-y-4">
        <h1 className="text-xl font-semibold text-center">Telebirr Checkout (Test Stub)</h1>
        <div className="rounded-lg border border-border p-4 space-y-2">
          <p className="text-sm"><span className="text-muted-foreground">Order:</span> <span className="font-mono">{merchOrderId}</span></p>
          <p className="text-sm"><span className="text-muted-foreground">Amount:</span> ETB {amount}</p>
        </div>
        <button
          className="w-full bg-primary text-primary-foreground rounded-lg py-3 font-medium"
          onClick={async () => {

            await fetch('/api/v1/webhooks/telebirr/notify', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                merch_order_id: merchOrderId,
                trade_status: 'Success',
                total_amount: amount,
                timestamp: Date.now(),
              }),
            });
            window.location.href = `/checkout/complete?merch_order_id=${merchOrderId}`;
          }}
        >
          Confirm Payment
        </button>
        <p className="text-xs text-muted-foreground text-center">
          This is a test stub. In production, you would be redirected to the real Telebirr H5 checkout.
        </p>
      </div>
    </div>
  );
}

export default function TelebirrStubPage() {
  return (
    <Suspense fallback={<div className="min-h-screen flex items-center justify-center"><p className="text-muted-foreground">Loading…</p></div>}>
      <TelebirrStubInner />
    </Suspense>
  );
}

'use client';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { signIn } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import { useState } from 'react';
import { Button, Input, Label, FieldError, PhoneInput } from '@addis/ui';

const LoginSchema = z.object({
  phone: z.string().regex(/^\+251(9|7)\d{8}$/, 'Enter a valid Ethiopian phone number'),
  password: z.string().min(1, 'Password is required'),
});
type LoginForm = z.infer<typeof LoginSchema>;

export default function LoginPage() {
  const router = useRouter();
  const [serverError, setServerError] = useState<string | null>(null);
  const { register, handleSubmit, setValue, watch, formState: { errors, isSubmitting } } =
    useForm<LoginForm>({ resolver: zodResolver(LoginSchema), defaultValues: { phone: '+251' } });

  const onSubmit = async (data: LoginForm) => {
    setServerError(null);
    const res = await signIn('credentials', { ...data, redirect: false });
    if (res?.error) { setServerError('Invalid phone number or password'); return; }

    try {
      const meRes = await fetch('/api/v1/auth/me', { credentials: 'include' });
      if (meRes.ok) {
        const me = (await meRes.json())?.data;
        const role = me?.role ?? 'rider';
        const dest = role === 'platform_admin' ? '/admin'
          : role === 'corporate_admin' ? '/dashboard/corporate'
          : role === 'contractor' ? '/dashboard/contractor'
          : '/dashboard/rider';
        router.push(dest);
        return;
      }
    } catch {  }
    router.push('/dashboard/rider');
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-6">
      <form onSubmit={handleSubmit(onSubmit)} className="w-full max-w-sm space-y-4" noValidate>
        <h1 className="text-2xl font-semibold text-center mb-2">Welcome back</h1>

        <PhoneInput value={watch('phone')} onChange={(v) => setValue('phone', v)} error={errors.phone?.message} />

        <div>
          <Label htmlFor="password">Password</Label>
          <Input id="password" type="password" aria-invalid={!!errors.password} {...register('password')} />
          <FieldError>{errors.password?.message}</FieldError>
        </div>

        {serverError && <p role="alert" className="text-sm text-destructive text-center">{serverError}</p>}

        <Button type="submit" className="w-full" loading={isSubmitting}>Log in</Button>

        <div className="flex justify-between text-sm">
          <a href="/forgot-password" className="text-accent">Forgot password?</a>
          <a href="/signup/rider" className="text-accent">Create account</a>
        </div>
      </form>
    </div>
  );
}

