export default config;

import NextAuth from 'next-auth';
import Credentials from 'next-auth/providers/credentials';
import { identityService } from '@addis/api/modules/identity/service';
import { TwoFactorRequiredError } from '@addis/shared';

export const { handlers, auth, signIn, signOut } = NextAuth({
  session: { strategy: 'jwt', maxAge: 30 * 24 * 3600 },
  providers: [
    Credentials({
      credentials: { phone: {}, password: {}, code: {} },
      async authorize(creds, req) {

        const xff = req.headers.get('x-forwarded-for');
        let ip: string | undefined;
        if (xff) {
          const parts = xff.split(',').map(s => s.trim()).filter(Boolean);
          if (parts.length > 0) ip = parts[parts.length - 1] ?? undefined;
        }
        const ua = req.headers.get('user-agent') ?? undefined;
        try {
          const code = (creds.code as string | undefined)?.trim() || undefined;
          const { user, accessToken } = await identityService.login(
            creds.phone as string,
            creds.password as string,
            ua,
            ip,
            code,
          );

          return { id: user.id, role: user.role, phone: user.phone, accessToken };
        } catch (err) {
          if (err instanceof TwoFactorRequiredError) {

            throw new Error('TwoFactorRequired');
          }
          return null;
        }
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user }) {
      if (user) { token.accessToken = (user as any).accessToken; token.role = (user as any).role; }
      return token;
    },
    async session({ session, token }) {
      (session as any).accessToken = token.accessToken;
      (session as any).role = token.role;
      return session;
    },
  },
  cookies: {
    sessionToken: { name: '__Secure-session-token', options: { httpOnly: true, sameSite: 'lax', secure: true, path: '/' } },
  },
});

export async function register() {
  const { loadEnv } = await import('@addis/shared');
  loadEnv();

  if (process.env.NEXT_RUNTIME === 'nodejs' && process.env.SENTRY_DSN) {
    const Sentry = await import('@sentry/nextjs');
    const sentryOpts: Parameters<typeof Sentry.init>[0] = {
      tracesSampleRate: 0.1,
      release: process.env.VERCEL_GIT_COMMIT_SHA ?? 'dev',
      sendDefaultPii: false,
      beforeSend(event: Parameters<NonNullable<Parameters<typeof Sentry.init>[0]['beforeSend']>>[0]) {
        return scrubEvent(event as unknown as Record<string, unknown>) as unknown as typeof event;
      },
    };
    sentryOpts.dsn = process.env.SENTRY_DSN;
    if (process.env.NODE_ENV) sentryOpts.environment = process.env.NODE_ENV;
    Sentry.init(sentryOpts);
  }
}

const PII_KEY_RE = /phone|email|password|token/i;

function scrubValue(value: unknown): unknown {
  if (value == null) return value;
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(scrubValue);
  if (typeof value === 'object') {
    const out: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
      if (PII_KEY_RE.test(k)) {
        out[k] = '[REDACTED]';
      } else {
        out[k] = scrubValue(v);
      }
    }
    return out;
  }
  return value;
}

function scrubEvent(event: Record<string, unknown>): Record<string, unknown> | null {
  if (!event || typeof event !== 'object') return event as Record<string, unknown> | null;

  const request = (event.request ?? {}) as Record<string, unknown>;
  if (request.headers && typeof request.headers === 'object') {
    const headers = request.headers as Record<string, unknown>;
    delete headers.authorization;
    delete headers.cookie;
    delete headers['x-api-key'];
  }
  delete request.cookies;
  delete request.body;
  event.request = request;

  for (const key of Object.keys(event)) {
    if (key === 'request') continue;
    event[key] = scrubValue(event[key]);
  }
  return event;
}

