# FIX (INFRA-005): The previous Caddyfile used `import addisride.et` inside
# the staging site block. Caddy's `import` directive imports a FILE or a
# named snippet `(name) { ... }` — NOT a site-address label. With the old
# config, Caddy looked for a file named `addisride.et` in the Caddyfile's
# directory, failed to find it, and errored at startup (or silently skipped
# the staging site). Staging was unreachable. The fix defines the shared
# config as a named snippet and imports it from both site blocks.
#
# FIX (INFRA-006): Added a baseline Content-Security-Policy at the proxy
# layer as defense in depth. The app sets a tighter per-route CSP via
# Next.js middleware, but if middleware is ever bypassed (static assets,
# direct API JSON, a future non-Next route), the proxy-layer CSP still
# applies.

(common) {
  encode gzip zstd

  # Limit request body size — defends against DoS via huge uploads. 20MB
  # accommodates contractor document uploads (10MB cap per file) with
  # headroom.
  request_body {
    max_size 20MB
  }

  # Reasonable timeouts — a hung client shouldn't hold a connection forever.
  timeouts {
    read_body 30s
    read_header 10s
    write 60s
    idle 120s
  }

  header {
    Strict-Transport-Security "max-age=63072000; includeSubDomains; preload"
    X-Content-Type-Options "nosniff"
    X-Frame-Options "DENY"
    Referrer-Policy "strict-origin-when-cross-origin"
    Permissions-Policy "camera=(), microphone=(), geolocation=(self), payment=()"
    # Baseline CSP — the app layer tightens this per-route via Next.js middleware.
    Content-Security-Policy "default-src 'self'; frame-ancestors 'none'; base-uri 'self'; object-src 'none'; form-action 'self'"
  }
}

addisride.et {
  import common

  reverse_proxy web:3000 {
    # Caddy replaces X-Forwarded-For with {remote_host}. The app's clientIp()
    # reads the rightmost entry — correct for single-hop and multi-hop alike.
    header_up X-Real-IP {remote_host}
    header_up X-Forwarded-For {remote_host}
  }

  # www -> apex redirect
  @www host www.addisride.et
  redir @www https://addisride.et{uri} permanent
}

# Staging domain — same config, different cert (auto).
staging.addisride.et {
  import common

  reverse_proxy web:3000 {
    header_up X-Real-IP {remote_host}
    header_up X-Forwarded-For {remote_host}
  }
}

import http from 'k6/http';
import { check, sleep } from 'k6';

export const options = {
  scenarios: {
    subscribe_flow: {
      executor: 'ramping-vus',
      startVUs: 0,
      stages: [{ duration: '2m', target: 200 }, { duration: '5m', target: 1000 }, { duration: '2m', target: 0 }],
    },
  },
  thresholds: {
    http_req_duration: ['p(95)<800'],
    http_req_failed: ['rate<0.01'],
  },
};

const BASE = __ENV.K6_TARGET_URL ?? 'http://localhost:3000';

export default function () {
  const loginRes = http.post(`${BASE}/api/v1/auth/token`, JSON.stringify({
    phone: `+2519${String(10000000 + Math.floor(Math.random() * 89999999))}`, password: 'demo12345',
  }), { headers: { 'Content-Type': 'application/json' } });

  check(loginRes, { 'login reachable': (r) => r.status === 200 || r.status === 401 });
  if (loginRes.status !== 200) { sleep(1); return; }

  const token = JSON.parse(loginRes.body).accessToken;
  const subRes = http.post(`${BASE}/api/v1/subscriptions`, JSON.stringify({
    planId: 'seed-plan-monthly', routeId: 'seed-route-bole', paymentMethod: 'telebirr',
  }), { headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json', 'Idempotency-Key': crypto.randomUUID() } });

  check(subRes, { 'subscription created or conflict (expected)': (r) => [201, 409].includes(r.status) });
  sleep(1);
}

