name: CI on: pull_request: push: { branches: [main] }
jobs: build-test: runs-on: ubuntu-latest services: postgres: image: postgres:16 env: { POSTGRES_DB: addisride_test, POSTGRES_USER: test, POSTGRES_PASSWORD: test } ports: ["5432:5432"] options: >- --health-cmd pg_isready --health-interval 5s --health-timeout 5s --health-retries 10 redis: image: redis:7-alpine ports: ["6379:6379"]
steps: - uses: actions/checkout@v4
# Cache bun install — the previous workflow reinstalled all deps on # every run. Now we cache by lockfile hash. - uses: oven-sh/setup-bun@v2 with: { bun-version: 1.3.14 } - name: Cache bun install uses: actions/cache@v4 with: path: | ~/.bun/install/cache node_modules **/node_modules # FIX (INFRA-001): cache key off the committed bun.lock (not the # gitignored bun.lockb that was previously absent on runners). key: ${{ runner.os }}-bun-${{ hashFiles('bun.lock', '**/package.json') }} restore-keys: ${{ runner.os }}-bun-
- name: Install dependencies run: bun install --frozen-lockfile
- name: Lint + dependency graph check run: bun run lint
- name: Typecheck run: bun run typecheck
- name: Run migrations (test DB) run: bun run db:migrate env: { DATABASE_URL: postgres://test:test@localhost:5432/addisride_test }
- name: Unit + integration tests run: bun run test env: DATABASE_URL: postgres://test:test@localhost:5432/addisride_test REDIS_URL: redis://localhost:6379 NODE_ENV: test # CI secret — at least 32 chars, mixed case + digits + symbols. NEXTAUTH_SECRET: ci-secret-32-chars-or-more-aaaa CRON_SECRET: ci-cron-secret-32-chars-or-more-bbbb NEXTAUTH_URL: http://localhost:3000 TELEBIRR_ENV: testbed TELEBIRR_NOTIFY_URL: http://localhost:3000/api/v1/webhooks/telebirr/notify TELEBIRR_REDIRECT_URL: http://localhost:3000/checkout/complete S3_ENDPOINT: http://localhost:9000 S3_BUCKET: test S3_ACCESS_KEY_ID: test S3_SECRET_ACCESS_KEY: test
- name: Enforce coverage gate (80% lines + branches) # FOLLOW-UP 5 (TEST-011): run the new test:coverage script that enforces # the 80% thresholds declared in vitest.config.ts. Previously the # coverage:check script ran vitest from the repo root without the # per-package configs, so thresholds were never enforced. run: bun run test:coverage
- name: Build all apps run: bun run build
- name: Generate OpenAPI + SDK, fail on drift run: | bun run openapi:gen bun run sdk:gen git diff --exit-code packages/api/openapi.json packages/sdk/src/schema.d.ts
- name: Upload coverage uses: actions/upload-artifact@v4 with: { name: coverage, path: coverage/ }
# Generate a Software Bill of Materials — required by the incident # response plan for knowing exactly which dependency versions are # deployed. - name: Generate SBOM (CycloneDX) run: | npx --yes @cyclonedx/cyclonedx-cli \ --component-name addis-ride \ --component-version ${GITHUB_SHA::7} \ --spec-version 1.5 \ --output-format json \ --output-file sbom.json - uses: actions/upload-artifact@v4 with: { name: sbom, path: sbom.json }
e2e-web: needs: build-test # Run E2E on PRs too, not just main — the previous `if: github.ref == # 'refs/heads/main'` meant PRs could merge with broken E2E. if: github.event_name == 'pull_request' || github.ref == 'refs/heads/main' runs-on: ubuntu-latest steps: - uses: actions/checkout@v4 - uses: oven-sh/setup-bun@v2 with: { bun-version: 1.3.14 } - run: bun install --frozen-lockfile - run: bunx playwright install --with-deps chromium - run: bun run build --filter=web - run: bunx playwright test env: { E2E_BASE_URL: http://localhost:3000, TELEBIRR_ENV: testbed }
security: runs-on: ubuntu-latest steps: - uses: actions/checkout@v4
# FIX (OPS-012 + INFRA-001): The previous "audit" step had three compounding bugs: # 1. `bun pm ls --all --production > /dev/null` lists packages and # discards the output — it does NO audit. # 2. `better-npm-audit` reads package-lock.json (npm's lockfile), # but this repo uses bun.lock — the tool finds nothing to audit. # 3. `|| true` and `continue-on-error: true` double-ensured the # step always succeeded. The CI badge was green even if every # dependency had a critical CVE. # We now use `osv-scanner` which reads bun.lock directly and # reports known vulnerabilities from the OSV database. The step # FAILS on HIGH or CRITICAL severity (no more `|| true`). - name: Audit dependencies (production) — fail on HIGH/CRITICAL CVEs run: | npx --yes @google/osv-scanner --lockfile=bun.lock --severity=HIGH - name: Audit dependencies (all) — warn on MEDIUM run: | npx --yes @google/osv-scanner --lockfile=bun.lock --severity=MODERATE continue-on-error: true # medium/low are warnings, not blockers
- name: Dependency review (on PRs) if: github.event_name == 'pull_request' uses: actions/dependency-review-action@v4 with: fail-on-severity: high
- name: Semgrep scan (SAST) uses: semgrep/semgrep-action@v1 with: config: >- p/owasp-top-ten p/typescript p/react
- name: Run secret scanning uses: gitleaks/gitleaks-action@v2 env: GITHUB_TOKEN: ${{ secrets.GITHUB_TOKEN }}
deploy-staging: needs: [build-test, e2e-web, security] if: github.ref == 'refs/heads/main' runs-on: ubuntu-latest environment: staging steps: - uses: actions/checkout@v4 - name: Deploy to Vercel (staging) # REAL deploy — the previous step was `echo "vercel deploy ..."`, # printing the command but never executing it. run: npx --yes vercel deploy --token=$VERCEL_TOKEN --scope=addis-ride --env=staging --yes env: { VERCEL_TOKEN: ${{ secrets.VERCEL_TOKEN }} } - name: Upload Sentry release uses: getsentry/action-release@v1 env: SENTRY_AUTH_TOKEN: ${{ secrets.SENTRY_AUTH_TOKEN }} SENTRY_ORG: addis-ride SENTRY_PROJECT: web with: { environment: staging }
deploy-production: needs: deploy-staging if: startsWith(github.ref, 'refs/tags/v') runs-on: ubuntu-latest environment: name: production url: https://addisride.et steps: - uses: actions/checkout@v4 - name: Deploy to production # REAL deploy — was `echo "vercel deploy ..."` before. run: npx --yes vercel deploy --prod --token=$VERCEL_TOKEN --scope=addis-ride --yes env: { VERCEL_TOKEN: ${{ secrets.VERCEL_TOKEN }} } - name: Upload Sentry release (production) uses: getsentry/action-release@v1 env: SENTRY_AUTH_TOKEN: ${{ secrets.SENTRY_AUTH_TOKEN }} SENTRY_ORG: addis-ride SENTRY_PROJECT: web with: { environment: production }

name: Weekly checks on: schedule: [{ cron: '0 3 * * 1' }] # Monday 03:00 UTC workflow_dispatch: {}
jobs: load-test: runs-on: ubuntu-latest steps: - uses: actions/checkout@v4 - uses: grafana/setup-k6-action@v1 - run: k6 run infra/k6/payment-flow.js env: { K6_TARGET_URL: https://staging.addisride.et }
dependency-audit: runs-on: ubuntu-latest steps: - uses: actions/checkout@v4 - uses: oven-sh/setup-bun@v2 with: { bun-version: 1.1.42 } - run: bun install --frozen-lockfile # FIX (INFRA-001): audit-ci reads package-lock.json by default; point it # at the committed bun.lock instead so it actually has something to scan. - run: bunx audit-ci --moderate --lockfile-directory=.
dast: runs-on: ubuntu-latest steps: - name: OWASP ZAP baseline scan uses: zaproxy/action-baseline@v0.12.0 with: { target: 'https://staging.addisride.et' }

-- FIX: The composite PK on telebirr_notify_events included received_at, which is set -- to a fresh timestamp per-insert — replays in different milliseconds would get -- different PK values and bypass dedup entirely. This drops received_at from the -- PK, keeping only (merch_order_id, out_request_no), which matches Telebirr's -- own dedup semantics. -- -- received_at remains on the row (default now()) for audit, but is no longer -- part of the uniqueness constraint.
-- Deduplicate: if the same (merch_order_id, out_request_no) exists with -- different received_at values (from the buggy PK), keep only the earliest row. DELETE FROM telebirr_notify_events t1 USING telebirr_notify_events t2 WHERE t1.ctid < t2.ctid AND t1.merch_order_id = t2.merch_order_id AND t1.out_request_no = t2.out_request_no;
ALTER TABLE telebirr_notify_events DROP CONSTRAINT telebirr_notify_events_pkey;
ALTER TABLE telebirr_notify_events ADD CONSTRAINT telebirr_notify_events_pkey PRIMARY KEY (merch_order_id, out_request_no);

-- FOLLOW-UP 3 (INFRA-009): Durable notification_log table for SMS/email/push idempotency. -- -- The worker's SMS/email/push handlers retry on failure (via the outbox) but -- had no idempotency: an outbox retry after a partial failure re-sent the -- message. This table records every successfully-sent message, keyed by the -- outbox event id + channel, so handlers can skip re-sends. -- -- Retention: 90 days (matches the outbox retention). Old rows are pruned by -- the cleanup-old-outbox-events cron (extended in this migration to also -- prune notification_log).
CREATE TABLE IF NOT EXISTS notification_log ( id text PRIMARY KEY, outbox_event_id text NOT NULL, channel text NOT NULL CHECK (channel IN ('sms', 'email', 'push')), -- The provider's message id (e.g. Africa's Talking message_id, Expo ticket, -- SMTP Message-Id). Used for delivery-receipt correlation. provider_message_id text, -- The recipient (phone for SMS, email for email, Expo token for push). -- Stored for forensic lookup ("did we send to this number in the last 90d?"). recipient text NOT NULL, sent_at timestamptz NOT NULL DEFAULT now(), -- Unique on (outbox_event_id, channel) so the same outbox event can't -- produce two log rows for the same channel — the handler's idempotency check. CONSTRAINT notification_log_outbox_channel_uniq UNIQUE (outbox_event_id, channel) );
CREATE INDEX IF NOT EXISTS notification_log_recipient_sent_at_index ON notification_log (recipient, sent_at DESC); CREATE INDEX IF NOT EXISTS notification_log_sent_at_index ON notification_log (sent_at);

-- DB-015: adminService.listUsers uses ilike with leading wildcard (%query%).
-- A btree index on phone can't serve a leading-wildcard LIKE. pg_trgm GIN
-- indexes support trigram-based fast ILIKE on text columns.
CREATE EXTENSION IF NOT EXISTS pg_trgm;
CREATE INDEX IF NOT EXISTS users_phone_trgm ON users USING gin (phone gin_trgm_ops);
CREATE INDEX IF NOT EXISTS users_name_trgm ON users USING gin (name gin_trgm_ops);
CREATE INDEX IF NOT EXISTS users_email_trgm ON users USING gin (email gin_trgm_ops);

-- FOLLOW-UP 2 (PAY-002): Composite PK for telebirrNotifyEvents + state-machine override. -- -- The original schema had `merchOrderId` as the sole primary key, with the webhook -- handler doing `INSERT ... ON CONFLICT DO NOTHING RETURNING` and treating -- `inserted.length === 0` as "already processed". Telebirr can send out-of-order -- or supplementary notifications for the same order — e.g., a 'failed' on timeout -- followed by a 'settled' when the payment actually completes. The second -- notification was silently dropped, leaving the payment in the wrong state. -- -- This migration: -- 1. Drops the old single-column PK. -- 2. Adds a composite PK on (merch_order_id, out_request_no, received_at) so -- each distinct Telebirr notification is recorded (outRequestNo is unique -- per Telebirr notification; received_at disambiguates same-ms duplicates). -- 3. Leaves a non-unique index on merch_order_id for the existing -- "find latest status for this order" queries.
-- Make out_request_no NOT NULL first (it was nullable; composite PK requires non-null). UPDATE telebirr_notify_events SET out_request_no = merch_order_id WHERE out_request_no IS NULL; ALTER TABLE telebirr_notify_events ALTER COLUMN out_request_no SET NOT NULL;
-- Drop the old single-column PK constraint. ALTER TABLE telebirr_notify_events DROP CONSTRAINT telebirr_notify_events_pkey;
-- Add composite PK. ALTER TABLE telebirr_notify_events ADD CONSTRAINT telebirr_notify_events_pkey PRIMARY KEY (merch_order_id, out_request_no, received_at);
-- Index for "find latest notification for this merchOrderId" queries. CREATE INDEX IF NOT EXISTS telebirr_notify_events_merch_order_id_index ON telebirr_notify_events (merch_order_id, received_at DESC);

-- CRITICAL REVIEW ROUND 2 — DB fixes (DB-001, DB-002, DB-005, DB-006, DB-007). -- -- This migration addresses findings from the second-round critical review: -- * DB-001: 0006's telebirr_notify_events dedup used ctid comparison which -- is non-deterministic — may keep the wrong (failed) row when the second -- notification was Success. Re-dedup deterministically by received_at -- DESC + trade_status priority (Success > Fail > anything else). This -- is a no-op if 0006 already ran cleanly; it cleans up any bad state. -- * DB-002: add a trigger preventing hard-DELETE on users with dependent -- rows. Soft-delete + anonymize is the policy; hard-delete is a bug. -- * DB-005: prevent trial plans from having rides_included = -1 (unlimited -- trials) via a CHECK constraint. -- * DB-006: add a trigger enforcing trips.seats_booked <= shuttles.capacity -- (defense in depth — the app uses CAS, but a direct SQL UPDATE should -- also be blocked). -- * DB-007: drop the unused password_reset_tokens table. Password reset -- uses otp_codes with purpose='password_reset'; the password_reset_tokens -- table is dead schema.
-- ============================================================================ -- DB-001: deterministic re-dedup of telebirr_notify_events -- ============================================================================ -- Only run if there are still duplicate rows (0006 may have left some if the -- ctid-based dedup kept the wrong row). Use a window function to keep the -- row with the latest received_at, breaking ties by trade_status priority. DO $$ BEGIN IF EXISTS ( SELECT 1 FROM ( SELECT merch_order_id, out_request_no, count(*) AS n FROM telebirr_notify_events GROUP BY merch_order_id, out_request_no HAVING count(*) > 1 ) s ) THEN DELETE FROM telebirr_notify_events WHERE (merch_order_id, out_request_no, received_at) IN ( SELECT merch_order_id, out_request_no, received_at FROM ( SELECT merch_order_id, out_request_no, received_at, ROW_NUMBER() OVER ( PARTITION BY merch_order_id, out_request_no ORDER BY received_at DESC, CASE trade_status WHEN 'Success' THEN 1 WHEN 'Fail' THEN 2 ELSE 3 END ) AS rn FROM telebirr_notify_events ) t WHERE t.rn > 1 ); END IF; END $$;
-- ============================================================================ -- DB-002: prevent hard-DELETE on users with dependent rows -- ============================================================================ -- The policy is soft-delete (set deleted_at, is_active=false) + anonymize -- after 30 days. Hard DELETE fails with FK violations on payments, rides, -- subscriptions, etc. — surfacing as 500 errors with no useful message. -- This trigger raises a clear exception explaining the policy.
CREATE OR REPLACE FUNCTION prevent_user_hard_delete() RETURNS trigger AS $$ DECLARE blocker text; BEGIN -- Check each dependent table; raise on the first one that has rows. IF EXISTS (SELECT 1 FROM subscriptions WHERE rider_id = OLD.id) THEN blocker := 'subscriptions'; ELSIF EXISTS (SELECT 1 FROM payments WHERE rider_id = OLD.id) THEN blocker := 'payments'; ELSIF EXISTS (SELECT 1 FROM seat_releases WHERE rider_id = OLD.id) THEN blocker := 'seat_releases'; ELSIF EXISTS (SELECT 1 FROM seat_claims WHERE rider_id = OLD.id) THEN blocker := 'seat_claims'; ELSIF EXISTS (SELECT 1 FROM rides WHERE rider_id = OLD.id) THEN blocker := 'rides'; ELSIF EXISTS (SELECT 1 FROM contractor_profiles WHERE user_id = OLD.id) THEN blocker := 'contractor_profiles'; ELSIF EXISTS (SELECT 1 FROM corporates WHERE admin_user_id = OLD.id) THEN blocker := 'corporates (admin)'; ELSIF EXISTS (SELECT 1 FROM corporate_members WHERE user_id = OLD.id AND deleted_at IS NULL) THEN blocker := 'corporate_members'; ELSIF EXISTS (SELECT 1 FROM support_tickets WHERE user_id = OLD.id) THEN blocker := 'support_tickets'; END IF;
IF blocker IS NOT NULL THEN RAISE EXCEPTION 'Hard DELETE on users is blocked — user % has dependent rows in %. Use soft-delete (set deleted_at, is_active=false) and let retention-cleanup anonymize after 30 days.', OLD.id, blocker; END IF; RETURN OLD; END; $$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS users_prevent_hard_delete ON users; CREATE TRIGGER users_prevent_hard_delete BEFORE DELETE ON users FOR EACH ROW EXECUTE FUNCTION prevent_user_hard_delete();
-- ============================================================================ -- DB-005: prevent unlimited trial plans -- ============================================================================ -- A trial plan with rides_included = -1 (unlimited) would let a user ride -- unlimited for the trial duration (e.g. 14 days). The hasUsedTrial check -- prevents re-use, but a misconfigured trial plan is still a money leak. ALTER TABLE subscription_plans DROP CONSTRAINT IF EXISTS no_unlimited_trial; ALTER TABLE subscription_plans ADD CONSTRAINT no_unlimited_trial CHECK (NOT (is_trial = true AND rides_included = -1));
-- ============================================================================ -- DB-006: enforce trips.seats_booked <= shuttles.capacity via trigger -- ============================================================================ -- The app uses a CAS UPDATE (WHERE seats_booked < capacity) to atomically -- increment seats_booked, which is correct. But the DB has no constraint -- enforcing seats_booked <= capacity — a direct SQL UPDATE (e.g. a migration -- bug, a manual fix, a future code path) could overbook. This trigger is -- defense in depth.
CREATE OR REPLACE FUNCTION check_trips_seats_booked() RETURNS trigger AS $$ DECLARE shuttle_capacity integer; BEGIN SELECT capacity INTO shuttle_capacity FROM shuttles WHERE id = NEW.shuttle_id; IF shuttle_capacity IS NULL THEN RAISE EXCEPTION 'Shuttle % not found for trip %', NEW.shuttle_id, NEW.id; END IF; IF NEW.seats_booked > shuttle_capacity THEN RAISE EXCEPTION 'Trip % would overbook shuttle %: seats_booked=% exceeds capacity=%', NEW.id, NEW.shuttle_id, NEW.seats_booked, shuttle_capacity; END IF; RETURN NEW; END; $$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trips_seats_booked_check ON trips; CREATE TRIGGER trips_seats_booked_check BEFORE INSERT OR UPDATE OF seats_booked ON trips FOR EACH ROW EXECUTE FUNCTION check_trips_seats_booked();
-- ============================================================================ -- DB-007: drop the unused password_reset_tokens table -- ============================================================================ -- The password-reset flow uses otp_codes with purpose='password_reset'. -- password_reset_tokens is dead schema — no code writes to it. The -- retention-cleanup cron deletes from it (always 0 rows). Drop it. DROP TABLE IF EXISTS password_reset_tokens CASCADE;

-- CRITICAL REVIEW (DB-001/002/004/009/010/011, SEC-003, INFRA-007):
--
-- Re-installs the append-only trigger function (idempotent), adds 9 CHECK
-- constraints and 12 indexes declared in schema.ts but missing from
-- migration 0000, plus 4 additional indexes required by hot paths.

-- 1. Audit append-only trigger with retention-purge escape hatch
-- (Re-declared here in case 0001 was missed — idempotent.)
CREATE OR REPLACE FUNCTION block_audit_mutation() RETURNS trigger AS $$
DECLARE
    purge_flag text;
BEGIN
    purge_flag := current_setting('app.audit_retention_purge', true);
    IF TG_OP = 'DELETE' AND purge_flag = 'on' THEN
        RETURN OLD;
    END IF;
    RAISE EXCEPTION 'audit_logs is append-only — % not allowed (purge_flag=%)', TG_OP, purge_flag;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS audit_logs_no_update ON audit_logs;
CREATE TRIGGER audit_logs_no_update BEFORE UPDATE ON audit_logs
    FOR EACH ROW EXECUTE FUNCTION block_audit_mutation();
DROP TRIGGER IF EXISTS audit_logs_no_delete ON audit_logs;
CREATE TRIGGER audit_logs_no_delete BEFORE DELETE ON audit_logs
    FOR EACH ROW EXECUTE FUNCTION block_audit_mutation();

-- 2. Missing CHECK constraints
ALTER TABLE shuttles ADD CONSTRAINT IF NOT EXISTS capacity_positive CHECK (capacity > 0 AND capacity <= 100);
ALTER TABLE shuttles ADD CONSTRAINT IF NOT EXISTS year_valid CHECK (year BETWEEN 1990 AND EXTRACT(YEAR FROM now()) + 1);
ALTER TABLE subscription_plans ADD CONSTRAINT IF NOT EXISTS rides_included_valid CHECK (rides_included = -1 OR rides_included > 0);
ALTER TABLE subscription_plans ADD CONSTRAINT IF NOT EXISTS duration_days_positive CHECK (duration_days > 0);
ALTER TABLE subscription_plans ADD CONSTRAINT IF NOT EXISTS price_etb_nonneg CHECK (price_etb >= 0);
ALTER TABLE subscriptions ADD CONSTRAINT IF NOT EXISTS sub_end_after_start CHECK (end_date > start_date);
ALTER TABLE subscriptions ADD CONSTRAINT IF NOT EXISTS sub_rides_used_nonneg CHECK (rides_used >= 0);
ALTER TABLE payments ADD CONSTRAINT IF NOT EXISTS amount_nonneg CHECK (amount >= 0);
ALTER TABLE payments ADD CONSTRAINT IF NOT EXISTS refund_amount_nonneg CHECK (refund_amount >= 0);

-- DB-013: routes / shuttle_positions sanity checks
ALTER TABLE routes ADD CONSTRAINT IF NOT EXISTS distance_km_positive CHECK (distance_km > 0);
ALTER TABLE routes ADD CONSTRAINT IF NOT EXISTS duration_min_positive CHECK (duration_min > 0);
ALTER TABLE routes ADD CONSTRAINT IF NOT EXISTS fare_nonneg CHECK (fare >= 0);
ALTER TABLE shuttle_positions ADD CONSTRAINT IF NOT EXISTS lat_range CHECK (lat BETWEEN -90 AND 90);
ALTER TABLE shuttle_positions ADD CONSTRAINT IF NOT EXISTS lng_range CHECK (lng BETWEEN -180 AND 180);

-- 3. Missing indexes declared in schema.ts
CREATE INDEX IF NOT EXISTS corporate_members_user_id_index ON corporate_members (user_id);
CREATE INDEX IF NOT EXISTS payments_subscription_id_index ON payments (subscription_id);
CREATE INDEX IF NOT EXISTS payments_seat_claim_id_index ON payments (seat_claim_id);
CREATE INDEX IF NOT EXISTS seat_claims_payment_id_index ON seat_claims (payment_id);
CREATE INDEX IF NOT EXISTS rides_subscription_id_index ON rides (subscription_id);
CREATE INDEX IF NOT EXISTS rides_seat_claim_id_index ON rides (seat_claim_id);
CREATE INDEX IF NOT EXISTS support_tickets_subscription_id_index ON support_tickets (subscription_id);
CREATE INDEX IF NOT EXISTS support_tickets_payment_id_index ON support_tickets (payment_id);

-- 4. Additional indexes NOT in schema.ts (DB-004/009/010/011)
CREATE INDEX IF NOT EXISTS refund_retries_payment_id_index ON refund_retries (payment_id);
CREATE INDEX IF NOT EXISTS corporate_members_last_reset_at_index ON corporate_members (last_reset_at);
CREATE INDEX IF NOT EXISTS outbox_events_payload_gin ON outbox_events USING gin (payload jsonb_path_ops);
CREATE UNIQUE INDEX IF NOT EXISTS contractor_documents_contractor_checksum_uniq ON contractor_documents (contractor_id, checksum_sha256);

-- 5. updated_at auto-update trigger (DB-008)
CREATE OR REPLACE FUNCTION bump_updated_at() RETURNS trigger AS $$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DO $$
DECLARE
    t text;
BEGIN
    FOR t IN
        SELECT table_name FROM information_schema.columns
        WHERE column_name = 'updated_at'
          AND table_schema = 'public'
          AND table_name NOT IN ('audit_logs')
        GROUP BY table_name
    LOOP
        EXECUTE format('DROP TRIGGER IF EXISTS %I ON %I;', t || '_bump_updated_at', t);
        EXECUTE format('CREATE TRIGGER %I BEFORE UPDATE ON %I FOR EACH ROW EXECUTE FUNCTION bump_updated_at();', t || '_bump_updated_at', t);
    END LOOP;
END;
$$;

-- FIX (DATA-007 + SEC-003 + INFRA-007): audit_logs was "append-only by convention".
-- The hash chain (prevHash + hash) makes tampering DETECTABLE, but the
-- BEFORE UPDATE/DELETE triggers make it PREVENTED at the DB layer.
--
-- SEC-003 / INFRA-007: the original trigger blocked ALL DELETEs, which meant
-- the archive-old-records cron couldn't prune 7-year-old rows. The trigger
-- now allows DELETE when the session flag `app.audit_retention_purge = 'on'`
-- is set (the cron sets this inside its DELETE transaction). UPDATE is always
-- blocked — there is no legit reason to mutate a tamper-evident row.

CREATE OR REPLACE FUNCTION block_audit_mutation() RETURNS trigger AS $$
DECLARE
    purge_flag text;
BEGIN
    -- Allow DELETE only when the retention cron has set the session flag.
    -- UPDATE is always blocked (no legit reason to mutate a tamper-evident row).
    purge_flag := current_setting('app.audit_retention_purge', true);
    IF TG_OP = 'DELETE' AND purge_flag = 'on' THEN
        RETURN OLD;
    END IF;
    RAISE EXCEPTION 'audit_logs is append-only — % not allowed (purge_flag=%)', TG_OP, purge_flag;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS audit_logs_no_update ON audit_logs;
CREATE TRIGGER audit_logs_no_update BEFORE UPDATE ON audit_logs
    FOR EACH ROW EXECUTE FUNCTION block_audit_mutation();

DROP TRIGGER IF EXISTS audit_logs_no_delete ON audit_logs;
CREATE TRIGGER audit_logs_no_delete BEFORE DELETE ON audit_logs
    FOR EACH ROW EXECUTE FUNCTION block_audit_mutation();

{
  "name": "@addis/db",
  "version": "1.0.0",
  "private": true,
  "type": "module",
  "main": "./src/index.ts",
  "types": "./src/index.ts",
  "exports": {
    ".": { "types": "./src/index.ts", "import": "./src/index.ts" },
    "./schema": { "types": "./src/schema.ts", "import": "./src/schema.ts" },
    "./client": { "types": "./src/client.ts", "import": "./src/client.ts" }
  },
  "scripts": {
    "generate": "drizzle-kit generate",
    "migrate": "drizzle-kit migrate",
    "seed": "bun src/seed.ts"
  },
  "dependencies": {
    "drizzle-orm": "^0.38.0",
    "postgres": "^3.4.0",
    "@addis/shared": "workspace:*",
    "@paralleldrive/cuid2": "^2.0.0"
  },
  "devDependencies": {
    "drizzle-kit": "^0.30.0"
  }
}

import { drizzle } from 'drizzle-orm/postgres-js';
import type { PgTransaction } from 'drizzle-orm/pg-core';
import postgres from 'postgres';
import * as schema from './schema';
import { loadEnv } from '@addis/shared';

const env = loadEnv();

const queryClient = postgres(env.DATABASE_URL, {
  max: env.NODE_ENV === 'production' ? 20 : 5,
  ...(env.NODE_ENV === 'production' ? { ssl: 'require' as const } : {}),
  idle_timeout: 30,
  max_lifetime: 60 * 30,
  prepare: false,
});
export const db = drizzle(queryClient, { schema });

queryClient`SET statement_timeout = '10s'`.catch((err) => {

  console.error('[db] failed to set statement_timeout:', (err as Error).message);
});

export type Db = typeof db;
export type DbOrTx = Db | PgTransaction<any, any, any>;
export * as schema from './schema';

import { createId } from '@paralleldrive/cuid2';
import { sql } from 'drizzle-orm';
import {
  pgTable, pgEnum, text, boolean, integer, real, decimal, jsonb,
  timestamp, date, index, uniqueIndex, check, primaryKey,
} from 'drizzle-orm/pg-core';

export const userRole = pgEnum('user_role', ['rider', 'contractor', 'corporate_admin', 'platform_admin']);
export const verificationStatus = pgEnum('verification_status', ['unverified', 'pending', 'verified', 'rejected']);
export const subscriptionStatus = pgEnum('subscription_status', ['pending_payment', 'active', 'expired', 'cancelled']);
export const paymentStatus = pgEnum('payment_status', ['pending', 'completed', 'failed', 'refunded', 'partially_refunded']);
export const paymentMethod = pgEnum('payment_method', ['telebirr', 'cbe']);
export const refundStatus = pgEnum('refund_status', ['pending', 'processing', 'succeeded', 'failed', 'permanent_failure']);
export const tripStatus = pgEnum('trip_status', ['scheduled', 'in_transit', 'completed', 'cancelled']);
export const rideStatus = pgEnum('ride_status', ['booked', 'boarded', 'completed', 'no_show', 'cancelled']);
export const seatReleaseStatus = pgEnum('seat_release_status', ['open', 'claimed', 'expired', 'cancelled']);
export const seatClaimStatus = pgEnum('seat_claim_status', ['confirmed', 'used', 'no_show', 'refunded']);
export const seatWindow = pgEnum('seat_window', ['morning', 'evening']);
export const ticketStatus = pgEnum('ticket_status', ['open', 'in_progress', 'resolved', 'closed']);
export const ticketPriority = pgEnum('ticket_priority', ['low', 'normal', 'high', 'urgent']);
export const ticketCategory = pgEnum('ticket_category', ['general', 'billing', 'route', 'shuttle', 'account', 'corporate', 'other']);
export const faqCategory = pgEnum('faq_category', ['billing', 'routes', 'shuttle', 'account', 'corporate', 'general']);
export const notificationType = pgEnum('notification_type', [
  'payment_received', 'payment_failed', 'refund_completed', 'refund_failed',
  'seat_claimed', 'seat_released', 'seat_release_expired',
  'subscription_expiring', 'subscription_expired', 'subscription_cancelled',
  'trip_departing', 'document_verified', 'document_rejected',
  'support_reply', 'support_resolved',
  'corporate_member_added', 'corporate_member_removed', 'corporate_reset', 'general',
]);
export const otpPurpose = pgEnum('otp_purpose', ['signup_verification', 'password_reset', 'phone_change']);
export const vehicleType = pgEnum('vehicle_type', ['coaster', 'minibus', 'van', 'sedan']);
export const outboxChannel = pgEnum('outbox_channel', ['notification', 'sms', 'push', 'email', 'refund', 'audit', 'webhook']);
export const documentScanStatus = pgEnum('document_scan_status', ['pending', 'clean', 'infected', 'error']);
export const approvalStatus = pgEnum('approval_status', ['pending', 'approved', 'rejected']);
export const contractorDocumentType = pgEnum('contractor_document_type', ['registration', 'insurance', 'inspection']);
export const outboxEventStatus = pgEnum('outbox_event_status', ['pending', 'processing', 'delivered', 'failed', 'dead']);

const ts = (name: string) => timestamp(name, { withTimezone: true });
const money = (name: string) => decimal(name, { precision: 12, scale: 2 });

export const users = pgTable('users', {
  id: text('id').primaryKey().$defaultFn(createId),
  phone: text('phone').notNull().unique(),
  email: text('email'),
  passwordHash: text('password_hash').notNull(),
  name: text('name').notNull(),
  role: userRole('role').notNull().default('rider'),
  phoneVerified: boolean('phone_verified').notNull().default(false),
