  destLatLng: jsonb('dest_lat_lng').notNull(),
  distanceKm: real('distance_km').notNull(),
  durationMin: integer('duration_min').notNull(),
  morningWindow: jsonb('morning_window').notNull(),
  eveningWindow: jsonb('evening_window').notNull(),
