import { z } from 'zod';

export const Id = z.string().cuid2();
export const EthiopianPhone = z.string().regex(/^\+251(9|7)\d{8}$/, 'Must be a valid Ethiopian phone (+2519XXXXXXXX)');
export const MoneyString = z.string().regex(/^\d+(\.\d{2})?$/, 'Must be ETB amount with 2dp');
export const TimeOfDay = z.string().regex(/^([01]\d|2[0-3]):[0-5]\d$/, 'HH:MM 24h');
export const CursorQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
  cursor: z.string().optional(),
});
export const ErrorSchema = z.object({
  error: z.object({
    code: z.string(), message: z.string(),
    details: z.array(z.any()).optional(),
    requestId: z.string(),
  }),
});
export function envelope<T extends z.ZodTypeAny>(schema: T) {
  return z.object({ data: schema, meta: z.object({ cursor: z.string().optional(), limit: z.number(), total: z.number().optional() }).optional() });
}

import { describe, it, expect } from 'vitest';
import { Money, computeSubsidy, computeEmployeeShare, proratedRideValue } from './money';

describe('Money', () => {
  it('rounds HALF_UP to 2 decimal places', () => {
    expect(Money.fromDecimal(10.005).toString()).toBe('10.01');
    expect(Money.fromDecimal(10.004).toString()).toBe('10.00');
  });

  it('sub() throws on negative result (prevents silent over-refund)', () => {
    expect(() => Money.fromDecimal(5).sub(Money.fromDecimal(10))).toThrow();
  });

  it('subOrZero() clamps to zero instead of throwing', () => {
    const result = Money.fromDecimal(5).subOrZero(Money.fromDecimal(10));
    expect(result.toString()).toBe('0.00');
  });

  it('computeSubsidy applies percentage with correct rounding', () => {
    expect(computeSubsidy(Money.fromDecimal('1200.00'), 60).toString()).toBe('720.00');
  });

  it('computeEmployeeShare is price minus subsidy', () => {
    expect(computeEmployeeShare(Money.fromDecimal('1200.00'), 60).toString()).toBe('480.00');
  });

  it('proratedRideValue divides plan price by rides for finite plans', () => {
    expect(proratedRideValue(Money.fromDecimal('150.00'), 10, Money.fromDecimal('60.00')).toString()).toBe('15.00');
  });

  it('proratedRideValue falls back to route fare for unlimited plans', () => {
    expect(proratedRideValue(Money.fromDecimal('1200.00'), -1, Money.fromDecimal('60.00')).toString()).toBe('60.00');
  });

  it('rejects malformed ETB strings', () => {
    expect(() => Money.fromETBString('12.999')).toThrow();
    expect(() => Money.fromETBString('abc')).toThrow();
  });
});

import zxcvbn from 'zxcvbn';
import { loadEnv } from './env';

const CONTROL_CHAR_RE = /[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/;

const MIN_ZXCVBN_SCORE = 3;

export function scorePasswordStrength(pw: string): { score: number; feedback: string[] } {
  const result = zxcvbn(pw);
  const feedback: string[] = [];
  if (result.feedback.warning) feedback.push(result.feedback.warning);
  if (result.feedback.suggestions) feedback.push(...result.feedback.suggestions);
  return { score: result.score, feedback };
}

export function validatePasswordShape(pw: string): void {
  if (pw.length < 10) throw new Error('Password must be at least 10 characters');
  if (pw.length > 100) throw new Error('Password must be at most 100 characters');

  if (CONTROL_CHAR_RE.test(pw)) throw new Error('Password contains invalid characters');
  const { score, feedback } = scorePasswordStrength(pw);
  if (score < MIN_ZXCVBN_SCORE) {
    const msg = feedback.length > 0 ? feedback.join(' ') : 'Password is too weak — try adding length, variety, or avoiding common patterns';
    throw new Error(msg);
  }
}

export async function hashPassword(pw: string, cost?: number): Promise<string> {
  validatePasswordShape(pw);

  const env = loadEnv();
  const actualCost = cost ?? env.BCRYPT_COST;
  if (actualCost < 10 || actualCost > 15) {
    throw new Error(`Invalid bcrypt cost ${actualCost} — must be between 10 and 15`);
  }
  const { default: bcrypt } = await import('bcryptjs');
  return bcrypt.hash(pw, actualCost);
}

export async function verifyPassword(pw: string, hash: string): Promise<boolean> {

  try {
    const { default: bcrypt } = await import('bcryptjs');
    return await bcrypt.compare(pw, hash);
  } catch {
    return false;
  }
}

async function sha1HexUpper(input: string): Promise<string> {
  const data = new TextEncoder().encode(input);
  const digest = await crypto.subtle.digest('SHA-1', data);
  return Array.from(new Uint8Array(digest))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('')
    .toUpperCase();
}

export async function isPasswordBreached(pw: string): Promise<boolean> {
  const env = loadEnv();
  const failOpen = env.NODE_ENV === 'development' || env.NODE_ENV === 'test';
  try {
    const sha1 = await sha1HexUpper(pw);
    const prefix = sha1.slice(0, 5), suffix = sha1.slice(5);
    const res = await fetch(`https://api.pwnedpasswords.com/range/${prefix}`, {
      signal: AbortSignal.timeout(2000),
      headers: { 'Add-Padding': 'true' },
    });
    if (!res.ok) {

      if (failOpen) return false;
      throw new Error('HIBP breach check unavailable');
    }
    const body = await res.text();
    return body.split('\n').some(line => line.trim().split(':')[0] === suffix);
  } catch (err) {
    if (failOpen) return false;

    console.warn('[password] HIBP check failed, failing closed', (err as Error).message);
    throw new Error('Password breach check is currently unavailable. Please try again later.');
  }
}

import { describe, it, expect } from 'vitest';
import { defineStateMachine, InvalidTransitionError } from './state-machine';

const sm = defineStateMachine<'a' | 'b' | 'c'>({
  initial: 'a',
  transitions: [{ from: 'a', to: 'b', event: 'go' }, { from: 'b', to: 'c', event: 'finish' }],
});

describe('state machine', () => {
  it('resolves valid transitions', () => {
    expect(sm.resolve('a', 'go').to).toBe('b');
  });
  it('throws InvalidTransitionError on illegal transition', () => {
    expect(() => sm.resolve('a', 'finish')).toThrow(InvalidTransitionError);
  });
  it('can() reports transition legality without throwing', () => {
    expect(sm.can('a', 'go')).toBe(true);
    expect(sm.can('c', 'go')).toBe(false);
  });
});

