describe('marketplaceService.claim', () => {
  beforeEach(() => vi.clearAllMocks());

  it('rejects claiming your own released seat', async () => {
    const { db } = await import('@addis/db');
    const txMock = {
      update: vi.fn().mockReturnValue({ set: () => ({ where: () => ({ returning: () => Promise.resolve([{ id: 'r1', riderId: 'rider-1', status: 'open', refundAmount: '60.00', routeId: 'route-1', window: 'morning' }]) }) }) }),
      insert: vi.fn(),
    };
    (db.transaction as any) = (fn: any) => fn(txMock);
    const { marketplaceService } = await import('./service');
    await expect(marketplaceService.claim('rider-1', { seatReleaseId: 'r1', paymentMethod: 'telebirr' }))
      .rejects.toThrow('Cannot claim your own released seat');
  });

  it('throws ConflictError when CAS update matches zero rows (already claimed)', async () => {
    const { db } = await import('@addis/db');
    const txMock = { update: vi.fn().mockReturnValue({ set: () => ({ where: () => ({ returning: () => Promise.resolve([]) }) }) }) };
    (db.transaction as any) = (fn: any) => fn(txMock);
    const { marketplaceService } = await import('./service');
    await expect(marketplaceService.claim('rider-2', { seatReleaseId: 'r1', paymentMethod: 'telebirr' }))
      .rejects.toThrow('Seat already claimed');
  });
});

import { addHours } from 'date-fns';
import { and, eq, gt, desc, lte } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { Money, ConflictError, BadRequestError, NotFoundError, proratedRideValue, PAYMENT_RETENTION_YEARS, loadEnv } from '@addis/shared';
import { getPaymentProvider } from '@addis/payments';
import { createId } from '@paralleldrive/cuid2';
import { scheduleRefund } from '../payment/service';
import { subscriptionRepo } from '../subscription/repository';

const env = loadEnv();
const SEAT_RELEASE_TTL_HOURS = Number(process.env.SEAT_RELEASE_TTL_HOURS ?? 4);
function addYears(d: Date, years: number) { const c = new Date(d); c.setFullYear(c.getFullYear() + years); return c; }

function generateMerchOrderId() { return `CLM${createId()}`; }

export const marketplaceService = {
  async release(riderId: string, input: { subscriptionId: string; releaseDate: string; window: 'morning' | 'evening' }) {
    const [sub] = await db.select().from(schema.subscriptions).where(eq(schema.subscriptions.id, input.subscriptionId));
    if (!sub || sub.riderId !== riderId) throw new NotFoundError('Subscription not found');
    if (sub.status !== 'active') throw new ConflictError('Subscription is not active');
    if (!sub.routeId) throw new BadRequestError('Subscription has no route');

    const releaseDateUTC = new Date(input.releaseDate + 'T00:00:00Z');
    const todayUTC = new Date();
    todayUTC.setUTCHours(0, 0, 0, 0);
    if (releaseDateUTC < todayUTC) throw new BadRequestError('Release date must be in the future');

    const [plan] = await db.select().from(schema.subscriptionPlans).where(eq(schema.subscriptionPlans.id, sub.planId));
    const [route] = await db.select().from(schema.routes).where(eq(schema.routes.id, sub.routeId));
    if (!plan || !route) throw new NotFoundError('Plan or route not found');

    if (plan.ridesIncluded > 0) {
      const ridesLeft = plan.ridesIncluded - sub.ridesUsed;
      if (ridesLeft <= 0) {
        throw new BadRequestError('Subscription ride quota exhausted — no seats available to release');
      }
    }

    let refundAmount: Money;
    if (plan.ridesIncluded > 0) {
      const [payment] = await db.select().from(schema.payments)
        .where(and(eq(schema.payments.subscriptionId, sub.id), eq(schema.payments.status, 'completed')))
        .orderBy(desc(schema.payments.createdAt)).limit(1);
      if (payment) {
        refundAmount = Money.fromDecimal(payment.amount).div(plan.ridesIncluded);
      } else {
        refundAmount = proratedRideValue(Money.fromDecimal(plan.priceETB), plan.ridesIncluded, Money.fromDecimal(route.fare));
      }
    } else {
      refundAmount = proratedRideValue(Money.fromDecimal(plan.priceETB), plan.ridesIncluded, Money.fromDecimal(route.fare));
    }

    try {

      return await db.transaction(async (tx: any) => {
        const [release] = await tx.insert(schema.seatReleases).values({
          subscriptionId: sub.id, riderId, routeId: sub.routeId, window: input.window,
          releaseDate: input.releaseDate, refundAmount: refundAmount.toString(),
          expiresAt: addHours(new Date(`${input.releaseDate}T00:00:00Z`), 24 + SEAT_RELEASE_TTL_HOURS),
        }).returning();

        // PAY-004: incrementRidesUsed performs a conditional UPDATE that only
        // increments if the subscription is active AND the rider has remaining
        // rides. If the update matches 0 rows (e.g. concurrent release pushed
        // rides_used to the limit between our pre-check at line 33 and this
        // increment), the rider has no remaining rides — we must refuse the
        // release, otherwise the rider gets a refund for a seat they didn't
        // consume (money leak). subscriptionRepo.incrementRidesUsed returns
        // void, so we re-query to verify the increment happened.
        const ridesUsedBefore = sub.ridesUsed;
        await subscriptionRepo.incrementRidesUsed(tx as any, sub.id);
        const [subAfter] = await tx.select({ ridesUsed: schema.subscriptions.ridesUsed })
          .from(schema.subscriptions).where(eq(schema.subscriptions.id, sub.id));
        if (!subAfter || subAfter.ridesUsed !== ridesUsedBefore + 1) {
          // Increment did not happen — quota exhausted concurrently. Force
          // a rollback by throwing; the catch block re-throws as a 409.
          throw new ConflictError('Subscription ride quota exhausted — no seats available to release (concurrent race)');
        }

        await tx.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'seat_released', userId: riderId } });
        return release!;
      });
    } catch (e: any) {
      if (e.code === '23505') throw new ConflictError('Seat already released for this date/window');
      throw e;
    }
  },

  async cancelRelease(riderId: string, releaseId: string) {
    const [release] = await db.select().from(schema.seatReleases).where(eq(schema.seatReleases.id, releaseId));
    if (!release || release.riderId !== riderId) throw new NotFoundError('Release not found');
    if (release.status !== 'open') throw new ConflictError('Release cannot be cancelled in its current state');
    await db.transaction(async (tx) => {
      await tx.update(schema.seatReleases).set({ status: 'cancelled', cancelledAt: new Date(), updatedAt: new Date() }).where(eq(schema.seatReleases.id, releaseId));

      if (release.subscriptionId) {
        await subscriptionRepo.decrementRidesUsed(tx as any, release.subscriptionId);
      }
    });
  },

  async claim(claimerId: string, input: { seatReleaseId: string; paymentMethod: 'telebirr' | 'cbe' }) {
    const result = await db.transaction(async (tx) => {
      const claimed = await tx.update(schema.seatReleases)
        .set({ status: 'claimed', updatedAt: new Date() })
        .where(and(
          eq(schema.seatReleases.id, input.seatReleaseId),
          eq(schema.seatReleases.status, 'open'),
          gt(schema.seatReleases.expiresAt, new Date()),
        ))
        .returning();
      if (claimed.length === 0) throw new ConflictError('Seat already claimed, cancelled, or expired');

      const release = claimed[0]!;
      if (release.riderId === claimerId) throw new BadRequestError('Cannot claim your own released seat');

      const merchOrderId = generateMerchOrderId();
      const [payment] = await tx.insert(schema.payments).values({
        riderId: claimerId, amount: release.refundAmount, method: input.paymentMethod,
        reference: merchOrderId, status: 'pending', retentionExpiresAt: addYears(new Date(), PAYMENT_RETENTION_YEARS),
      }).returning();

      const [claim] = await tx.insert(schema.seatClaims).values({
        seatReleaseId: input.seatReleaseId, riderId: claimerId, routeId: release.routeId,
        window: release.window, paymentId: payment!.id, status: 'confirmed',
      }).returning();

      await tx.update(schema.payments).set({ seatClaimId: claim!.id }).where(eq(schema.payments.id, payment!.id));

      return { release, claim: claim!, payment: payment! };
    });

    const provider = getPaymentProvider(input.paymentMethod);
    try {
      const checkout = await provider.createCheckout({
        merchOrderId: result.payment.reference, amount: Money.fromDecimal(result.payment.amount),
        description: 'Addis Ride — claim released seat', notifyUrl: env.TELEBIRR_NOTIFY_URL, redirectUrl: env.TELEBIRR_REDIRECT_URL,
      });
      return { ...result, checkout };
    } catch (err) {

      await db.transaction(async (tx) => {
        await tx.update(schema.seatReleases).set({ status: 'open', updatedAt: new Date() }).where(eq(schema.seatReleases.id, result.release.id));
        await tx.update(schema.seatClaims).set({ status: 'refunded', updatedAt: new Date() }).where(eq(schema.seatClaims.id, result.claim.id));
        await tx.update(schema.payments).set({ status: 'failed', updatedAt: new Date() }).where(eq(schema.payments.id, result.payment.id));
      });
      throw err;
    }
  },

  async onClaimPaymentSettled(seatClaimId: string) {
    const [claim] = await db.select().from(schema.seatClaims).where(eq(schema.seatClaims.id, seatClaimId));
    if (!claim) return;
    const [release] = await db.select().from(schema.seatReleases).where(eq(schema.seatReleases.id, claim.seatReleaseId));
    if (!release) return;

    const [originalPayment] = await db.select().from(schema.payments)
      .where(and(
        eq(schema.payments.subscriptionId, release.subscriptionId),
        eq(schema.payments.status, 'completed'),
        lte(schema.payments.createdAt, release.createdAt),
      ))
      .orderBy(desc(schema.payments.createdAt))
      .limit(1);
    if (!originalPayment) return;

    const [existingRefund] = await db.select().from(schema.refundRetries)
      .where(and(
        eq(schema.refundRetries.paymentId, originalPayment.id),
        eq(schema.refundRetries.reason, 'seat_claimed'),
      ))
      .limit(1);
    if (existingRefund) return;
    await scheduleRefund(originalPayment.id, Money.fromDecimal(release.refundAmount), 'seat_claimed');
    await db.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'seat_claimed', userId: release.riderId } });
  },
};

import { z } from 'zod';
import { Id } from '@addis/shared';

export const CreateSeatReleaseInput = z.object({
  subscriptionId: Id,
  releaseDate: z.string().date(),
  window: z.enum(['morning', 'evening']),
});
export const ClaimSeatInput = z.object({
  seatReleaseId: Id,
  paymentMethod: z.enum(['telebirr', 'cbe']),
});

import { TypedOpenAPIHono } from '../../src/typed-hono';
import { requireRole } from '../../src/middleware/auth';
import { CreateSeatReleaseInput, ClaimSeatInput } from './types';
import { marketplaceService } from './service';
import { db, schema } from '@addis/db';
import { eq, and, gt } from 'drizzle-orm';
import { NotFoundError } from '@addis/shared';

export const marketplaceRoutes = new TypedOpenAPIHono();

async function riderProfileIdFor(userId: string): Promise<string> {
  const [profile] = await db.select().from(schema.riderProfiles).where(eq(schema.riderProfiles.userId, userId));
  if (!profile) throw new NotFoundError('Rider profile not found');
  return profile.id;
}

marketplaceRoutes.get('/seat-releases', requireRole('rider'), async (c) => {
  const limit = Math.min(Math.max(1, Number(c.req.query('limit') ?? 20) || 20), 100);
  const rows = await db.select().from(schema.seatReleases)
    .where(and(eq(schema.seatReleases.status, 'open'), gt(schema.seatReleases.expiresAt, new Date())))
    .limit(limit);
  return c.json({ data: rows });
});
marketplaceRoutes.post('/seat-releases', requireRole('rider'), async (c) => {
  const body = CreateSeatReleaseInput.parse(await c.req.json());

  const riderId = await riderProfileIdFor(c.get('session')!.userId);
  const row = await marketplaceService.release(riderId, body);
  return c.json({ data: row }, 201);
});

marketplaceRoutes.get('/seat-releases/:id', requireRole('rider'), async (c) => {
  const [row] = await db.select().from(schema.seatReleases).where(eq(schema.seatReleases.id, c.req.param('id')));
  if (!row) throw new NotFoundError('Release not found');
  const riderId = await riderProfileIdFor(c.get('session')!.userId);
  if (row.riderId !== riderId) {

    throw new NotFoundError('Release not found');
  }
  return c.json({ data: row });
});
marketplaceRoutes.delete('/seat-releases/:id', requireRole('rider'), async (c) => {
  const riderId = await riderProfileIdFor(c.get('session')!.userId);
  await marketplaceService.cancelRelease(riderId, c.req.param('id'));
  return c.body(null, 204);
});

marketplaceRoutes.get('/seat-claims', requireRole('rider'), async (c) => {
  const riderId = await riderProfileIdFor(c.get('session')!.userId);
  const rows = await db.select().from(schema.seatClaims).where(eq(schema.seatClaims.riderId, riderId));
  return c.json({ data: rows });
});
marketplaceRoutes.post('/seat-claims', requireRole('rider'), async (c) => {
  const body = ClaimSeatInput.parse(await c.req.json());
  const riderId = await riderProfileIdFor(c.get('session')!.userId);
  const result = await marketplaceService.claim(riderId, body);
  return c.json({ data: { claim: result.claim, checkout: result.checkout } }, 201);
});
marketplaceRoutes.get('/seat-claims/:id', requireRole('rider'), async (c) => {
  const riderId = await riderProfileIdFor(c.get('session')!.userId);
  const [row] = await db.select().from(schema.seatClaims).where(eq(schema.seatClaims.id, c.req.param('id')));
  if (!row) throw new NotFoundError('Claim not found');
  if (row.riderId !== riderId) throw new NotFoundError('Claim not found');
  return c.json({ data: row });
});

import { TypedOpenAPIHono } from '../../src/typed-hono';
import { eq, and, inArray } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { getPaymentProvider } from '@addis/payments';
import { settlePayment, failPayment, scheduleRefund } from '../payment/service';
import { marketplaceService } from '../marketplace/service';
import { Money } from '@addis/shared';

export const webhookRoutes = new TypedOpenAPIHono();

webhookRoutes.post('/telebirr/notify', async (c) => {
  const provider = getPaymentProvider('telebirr');
  let event;
  try {
    event = await provider.parseWebhook(c.req.raw);
  } catch (err) {

    c.get('logger')?.warn({ err: (err as Error).message }, 'telebirr webhook parse/signature failure');
    return c.text('BAD_SIGNATURE', 401);
  }

  if (event.signatureValid !== true) {
    return c.text('INVALID_SIGNATURE', 401);
  }

  if (event.type === 'payment.settled' || event.type === 'payment.failed') {

    const outRequestNo = (event as any).outRequestNo ?? `auto-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    try {
      await db.insert(schema.telebirrNotifyEvents)
        .values({ merchOrderId: event.merchOrderId, tradeStatus: event.type, outRequestNo });
    } catch (err: any) {
      if (err.code === '23505') return c.text('SUCCESS');
      throw err;
    }

    const [payment] = await db.select().from(schema.payments).where(eq(schema.payments.reference, event.merchOrderId));
    // PAY-005: For unknown payment references, return 404 (not SUCCESS) so
    // Telebirr retries. Log to Sentry + audit-log so ops can detect the
    // mismatch (e.g. payment row not yet committed, or misrouted webhook).
    // After 24h of retries (Telebirr's max), the webhook is dead-lettered
    // by Telebirr — at that point the only recovery is manual reconciliation.
    if (!payment) {
      c.get('logger')?.error(
        { merchOrderId: event.merchOrderId, outRequestNo },
        'webhook: notification for unknown payment reference — returning 404 so Telebirr retries',
      );
      try {
        await db.insert(schema.outboxEvents).values({
          channel: 'audit',
          payload: {
            action: 'webhook.unknown_payment_reference',
            entityId: event.merchOrderId,
            after: { outRequestNo, type: event.type },
          },
        });
      } catch { /* audit failure must not change the response */ }
      // Sentry is only configured in the worker; the worker's audit-handler
      // will pick up the audit event above and forward critical ones to
      // Sentry. We also log at error level so the API's logger (pino)
      // surfaces it in structured logs.
      return c.text('NOT_FOUND', 404);
    }

    if (event.type === 'payment.settled') {
      if (payment.status === 'pending') {
        const settled = await settlePayment(event.merchOrderId, event.amount);
        if (settled && payment.seatClaimId) {
          await db.insert(schema.outboxEvents).values({
            channel: 'audit',
            payload: { action: 'claim_settlement_pending', entityId: payment.seatClaimId, paymentId: payment.id },
          });
          try {
            await marketplaceService.onClaimPaymentSettled(payment.seatClaimId);
            await db.insert(schema.outboxEvents).values({
              channel: 'audit',
              payload: { action: 'claim_settlement_completed', entityId: payment.seatClaimId, paymentId: payment.id },
            });
          } catch (err) {
            c.get('logger')?.error(
              { paymentId: payment.id, seatClaimId: payment.seatClaimId, err },
              'onClaimPaymentSettled failed — reconcile-claims cron will retry',
            );
          }
        }
      } else if (payment.status === 'failed') {
        // PAY-001: A late settlement for a payment we already marked failed.
        // The failPayment flow released the seat claim back to 'open' and
        // re-opened the seat release. If a different rider has since claimed
        // that seat release, reopening this payment would double-spend the
        // seat (original rider gets active subscription, new rider also has
        // a valid claim). Check the seat release state before reopening.
        let canReopen = true;
        let reopenBlocker: string | null = null;
        if (payment.seatClaimId) {
          const [claim] = await db.select().from(schema.seatClaims)
            .where(eq(schema.seatClaims.id, payment.seatClaimId));
          if (claim) {
            const [release] = await db.select().from(schema.seatReleases)
              .where(eq(schema.seatReleases.id, claim.seatReleaseId));
            if (release && release.status !== 'claimed') {
              // The seat release was re-opened and may have been re-claimed
              // by another rider. Reopening this payment would create a
              // double-spend on the seat. Refuse to reopen; refund the
              // original rider instead.
              canReopen = false;
              reopenBlocker = `seat_release ${release.id} is in status '${release.status}' (expected 'claimed')`;
            }
          }
        }
        if (!canReopen) {
          c.get('logger')?.warn(
            { paymentId: payment.id, merchOrderId: event.merchOrderId, reopenBlocker },
            'webhook: late settlement refused — seat was re-claimed; refunding original rider instead',
          );
          await db.insert(schema.outboxEvents).values({
            channel: 'audit',
            payload: {
              action: 'payment.late_settlement_refused_seat_reclaimed',
              entityId: payment.id,
              after: { merchOrderId: event.merchOrderId, reopenBlocker },
            },
          });
          // The payment is still 'failed' — issue a full refund for the
          // original rider's seat-claim payment (if not already refunded).
          try {
            const refundAmount = Money.fromDecimal(payment.amount);
            const alreadyRefunded = payment.refundAmount ? Money.fromDecimal(payment.refundAmount) : Money.ZERO;
            if (alreadyRefunded.lt(refundAmount)) {
              await scheduleRefund(payment.id, refundAmount.sub(alreadyRefunded), 'late_settlement_refused_seat_reclaimed');
            }
          } catch (err) {
            c.get('logger')?.error({ paymentId: payment.id, err }, 'late-settlement refund scheduling failed');
          }
          return c.text('SUCCESS');
        }

        const reopened = await db.update(schema.payments)
          .set({ status: 'pending', updatedAt: new Date() })
          .where(and(eq(schema.payments.id, payment.id), eq(schema.payments.status, 'failed')))
          .returning({ id: schema.payments.id });
        if (reopened.length === 0) {

          await db.insert(schema.outboxEvents).values({
            channel: 'audit',
            payload: { action: 'payment.reopen_skipped_concurrent', entityId: payment.id, currentStatus: payment.status },
          });
          return c.text('SUCCESS');
        }
        await db.insert(schema.outboxEvents).values({
          channel: 'audit',
          payload: { action: 'payment.reopened_from_failed', entityId: payment.id, reason: 'late_settlement_notification' },
        });
        const settled = await settlePayment(event.merchOrderId, event.amount);
        if (settled) {
          await db.insert(schema.outboxEvents).values({
            channel: 'audit',
            payload: { action: 'payment.recovered_late_settlement', entityId: payment.id },
          });
        }
      }

    } else {
      if (payment.status === 'pending') {
        await failPayment(event.merchOrderId, event.raw);
      }

    }
    return c.text('SUCCESS');
  }

  if (event.type === 'refund.succeeded' || event.type === 'refund.failed') {
    if (!event.refundRequestNo) return c.text('SUCCESS');
    const newStatus = event.type === 'refund.succeeded' ? 'succeeded' : 'permanent_failure';

    const updated = await db.update(schema.refundRetries)
      .set({ status: newStatus as any, updatedAt: new Date() })
      .where(and(
        eq(schema.refundRetries.refundRequestNo, event.refundRequestNo),
        inArray(schema.refundRetries.status, ['pending', 'processing'] as any),
      ))
      .returning();
    if (updated.length === 0) {

      c.get('logger')?.warn(
        { refundRequestNo: event.refundRequestNo, type: event.type },
        'webhook: refund event for unknown refund_request_no',
      );
      return c.text('SUCCESS');
    }
    const retry = updated[0]!;
    if (event.type === 'refund.succeeded') {

      const { Money } = await import('@addis/shared');
      await db.transaction(async (tx) => {
        const [payment] = await tx.select().from(schema.payments)
          .where(eq(schema.payments.id, retry.paymentId)).for('update');
        if (!payment) return;
        const currentRefundAmount = payment.refundAmount ? Money.fromDecimal(payment.refundAmount) : Money.ZERO;
        const newRefundAmount = currentRefundAmount.add(Money.fromDecimal(retry.amount));
        const allRefunded = newRefundAmount.eq(Money.fromDecimal(payment.amount));
        await tx.update(schema.payments).set({
          status: allRefunded ? 'refunded' : 'partially_refunded',
          refundAmount: newRefundAmount.toString(),
          refundedAt: new Date(), updatedAt: new Date(),
        }).where(eq(schema.payments.id, payment.id));
        await tx.insert(schema.outboxEvents).values({
          channel: 'notification',
          payload: { type: 'refund_completed', userId: payment.riderId },
        });
      });
    } else {
      const [payment] = await db.select().from(schema.payments).where(eq(schema.payments.id, retry.paymentId));
      if (payment) {
        await db.insert(schema.outboxEvents).values({
          channel: 'notification',
          payload: { type: 'refund_failed', userId: payment.riderId },
        });
      }
    }
    return c.text('SUCCESS');
  }

  c.get('logger')?.warn({ type: (event as any).type }, 'webhook: unknown telebirr event type');
  return c.text('SUCCESS');
});

import { eq, and, sql } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { hashPassword, NotFoundError, ConflictError } from '@addis/shared';

export const corporateService = {

  async signup(input: { corpName: string; corpCode: string; contactEmail: string; contactPhone: string; adminName: string; adminPassword: string; subsidyPercent: number; monthlySeatAllowance: number }) {
    return db.transaction(async (tx) => {
      const [admin] = await tx.insert(schema.users).values({
        phone: input.contactPhone, name: input.adminName, passwordHash: await hashPassword(input.adminPassword), role: 'corporate_admin', phoneVerified: false,
      }).returning();
      const [corp] = await tx.insert(schema.corporates).values({
        code: input.corpCode, name: input.corpName, contactEmail: input.contactEmail, contactPhone: input.contactPhone,
        subsidyPercent: input.subsidyPercent, monthlySeatAllowance: input.monthlySeatAllowance, adminUserId: admin!.id,
        isActive: false,
      }).returning();
      // SEC-009: queue a phone-verification OTP for the new corporate admin.
      // The admin cannot use any session-gated route until they verify, because
      // requireRole('corporate_admin') is in TWO_FA_REQUIRED_ROLES and will
      // force 2FA setup on first authenticated call — but the phone is still
      // unverified. We additionally gate corporate-admin-gated endpoints by
      // phoneVerified in the requireRole check below (via a helper).
      try {
        const { otpService } = await import('../identity/otp');
        await otpService.send(input.contactPhone, 'signup_verification');
      } catch {
        // Best-effort — if SMS fails, the admin can request a new OTP via
        // /auth/otp/send. Don't fail the signup.
      }
      return { corp, admin };
    });
  },

  async activate(corpId: string) {
    const [corp] = await db.update(schema.corporates).set({ isActive: true, updatedAt: new Date() }).where(eq(schema.corporates.id, corpId)).returning();
    if (!corp) throw new NotFoundError('Corporate not found');
    return corp;
  },

  async getOwn(adminUserId: string) {
    const [corp] = await db.select().from(schema.corporates).where(eq(schema.corporates.adminUserId, adminUserId));
    if (!corp) throw new NotFoundError('Corporate not found');
    return corp;
  },

  async updateOwn(adminUserId: string, input: Partial<{ name: string; contactEmail: string; contactPhone: string; subsidyPercent: number; monthlySeatAllowance: number }>) {
    const corp = await corporateService.getOwn(adminUserId);
    const [row] = await db.update(schema.corporates).set({ ...input, updatedAt: new Date() }).where(eq(schema.corporates.id, corp.id)).returning();
    return row;
  },

  async listMembers(adminUserId: string) {
    const corp = await corporateService.getOwn(adminUserId);
    return db.select().from(schema.corporateMembers).where(eq(schema.corporateMembers.corporateId, corp.id));
  },

  async updateMember(adminUserId: string, memberId: string, input: { approvalStatus?: 'approved' | 'rejected'; isActive?: boolean }) {
    const corp = await corporateService.getOwn(adminUserId);
    const [member] = await db.select().from(schema.corporateMembers).where(eq(schema.corporateMembers.id, memberId));
    if (!member || member.corporateId !== corp.id) throw new NotFoundError('Member not found');
    const [row] = await db.update(schema.corporateMembers).set({ ...input, updatedAt: new Date() }).where(eq(schema.corporateMembers.id, memberId)).returning();
    if (input.approvalStatus === 'approved') {
      await db.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'corporate_member_added', userId: member.userId } });
    }
    return row;
  },

  async removeMember(adminUserId: string, memberId: string) {
    const corp = await corporateService.getOwn(adminUserId);
    const [member] = await db.select().from(schema.corporateMembers).where(eq(schema.corporateMembers.id, memberId));
    if (!member || member.corporateId !== corp.id) throw new NotFoundError('Member not found');

    await db.update(schema.corporateMembers)
      .set({ deletedAt: new Date(), isActive: false, updatedAt: new Date() })
      .where(eq(schema.corporateMembers.id, memberId));
    await db.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'corporate_member_removed', userId: member.userId } });
  },

  async onboardRider(riderUserId: string, input: { corporateCode: string; employeeId: string }) {
    const [corp] = await db.select().from(schema.corporates).where(and(eq(schema.corporates.code, input.corporateCode), eq(schema.corporates.isActive, true)));
    if (!corp) throw new NotFoundError('Corporate not found');
    // SEC-017: check for an existing active membership BEFORE the insert so
    // we can return a specific error with the corporate name, rather than
    // the generic "Already linked" message from the unique-index violation.
    const [existing] = await db.select().from(schema.corporateMembers)
      .where(and(eq(schema.corporateMembers.userId, riderUserId), sql`${schema.corporateMembers.deletedAt} is null`));
    if (existing) {
      const [existingCorp] = await db.select().from(schema.corporates).where(eq(schema.corporates.id, existing.corporateId));
      throw new ConflictError(
        `You are already linked to corporate "${existingCorp?.name ?? existing.corporateId}". Contact support if you believe this is an error.`,
      );
    }
    try {
      const [member] = await db.insert(schema.corporateMembers).values({
        corporateId: corp.id, userId: riderUserId, employeeId: input.employeeId, approvalStatus: 'pending',
      }).returning();
      return member;
    } catch (e: any) {
      if (e.code === '23505') throw new ConflictError('Employee ID already used at this corporate');
      throw e;
    }
  },

  async myMembership(riderUserId: string) {
    const [member] = await db.select().from(schema.corporateMembers).where(eq(schema.corporateMembers.userId, riderUserId));
    return member ?? null;
  },

  async generateInvite(adminUserId: string) {
    const corp = await corporateService.getOwn(adminUserId);
    const expiresAt = Date.now() + 24 * 3600_000;
    const payload = JSON.stringify({ code: corp.code, expiresAt });
    const { createHmac } = await import('node:crypto');

    const env = (await import('@addis/shared')).loadEnv();
    const sig = createHmac('sha256', env.NEXTAUTH_SECRET).update(payload).digest('hex');
    const token = Buffer.from(`${payload}.${sig}`).toString('base64url');
    return {
      inviteUrl: `${env.NEXTAUTH_URL}/signup/rider?invite=${token}`,
      code: corp.code,
      token,
      expiresAt: new Date(expiresAt).toISOString(),
    };
  },
};

import { TypedOpenAPIHono } from '../../src/typed-hono';
import { z } from 'zod';
import { requireRole } from '../../src/middleware/auth';
import { corporateService } from './service';
import { db, schema } from '@addis/db';

export const corporateRoutes = new TypedOpenAPIHono();

corporateRoutes.post('/signup', async (c) => {
  const body = z.object({
    corpName: z.string().min(2).max(200),
    corpCode: z.string().min(2).max(50).regex(/^[A-Z0-9-]+$/, 'corpCode must be uppercase alphanumeric with dashes'),
    contactEmail: z.string().email(),
    contactPhone: z.string().regex(/^\+251[97]\d{8}$/, 'contactPhone must be an Ethiopian phone (+2519... or +2517...)'),
    adminName: z.string().min(2).max(200),
    adminPassword: z.string().min(10).max(1000),
    subsidyPercent: z.number().min(0).max(100).default(50),
    monthlySeatAllowance: z.number().int().positive().max(10000).default(20),
  }).parse(await c.req.json());
  return c.json({ data: await corporateService.signup(body) }, 201);
});

const UpdateCorporateInput = z.object({
  name: z.string().min(2).optional(),
  contactEmail: z.string().email().optional(),
  contactPhone: z.string().optional(),
