engagementRoutes.delete('/notifications/:id', async (c) => { await engagementService.remove(c.get('session')!.userId, c.req.param('id')); return c.body(null, 204); });

const ChannelKeyZ = z.enum(['inApp', 'push', 'sms', 'email']);
const NotificationTypeZ = z.enum([
  'payment_received', 'payment_failed', 'refund_completed', 'refund_failed',
  'seat_claimed', 'seat_released', 'seat_release_expired',
  'subscription_expiring', 'subscription_expired', 'subscription_cancelled',
  'trip_departing', 'document_verified', 'document_rejected',
  'support_reply', 'support_resolved',
  'corporate_member_added', 'corporate_member_removed', 'corporate_reset',
  'general',
]);
const TimeOfDayZ = z.string().regex(/^([01]\d|2[0-3]):[0-5]\d$/, 'Time must be HH:MM');
const UpdatePreferencesInput = z.object({

  prefs: z.record(NotificationTypeZ, z.record(ChannelKeyZ, z.boolean())).optional(),
  quietHoursStart: TimeOfDayZ.nullable().optional(),
  quietHoursEnd: TimeOfDayZ.nullable().optional(),
}).strict();

engagementRoutes.patch('/notifications/preferences', async (c) => {
  const body = UpdatePreferencesInput.parse(await c.req.json());
  return c.json({ data: await engagementService.updatePreferences(c.get('session')!.userId, body as any) });
});

engagementRoutes.post('/devices', async (c) => {
  const body = z.object({ pushToken: z.string(), platform: z.enum(['ios', 'android', 'web']) }).parse(await c.req.json());
  // SEC-018: include `platform` in the conflict target so a token that
  // somehow gets registered from two different platforms (shouldn't happen
  // with Expo, but defense in depth) updates the platform field rather
  // than leaving it stale.
  const [row] = await db.insert(schema.devices).values({ userId: c.get('session')!.userId, ...body })
    .onConflictDoUpdate({
      target: [schema.devices.userId, schema.devices.pushToken],
      set: { lastSeenAt: new Date(), platform: body.platform },
    }).returning();
  return c.json({ data: row }, 201);
});
engagementRoutes.delete('/devices', async (c) => {
  const { pushToken } = z.object({ pushToken: z.string() }).parse(await c.req.json());
  await db.delete(schema.devices).where(and(eq(schema.devices.userId, c.get('session')!.userId), eq(schema.devices.pushToken, pushToken)));
  return c.body(null, 204);
});

import { and, eq, sql, inArray } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { NotFoundError, ConflictError, BadRequestError, ForbiddenError } from '@addis/shared';
import { subscriptionRepo } from '../subscription/repository';

const MIN_GPS_MOVE_METERS = 5;
function haversineMeters(a: [number, number], b: [number, number]) {
  const R = 6371000, toRad = (d: number) => d * Math.PI / 180;
  const dLat = toRad(b[0] - a[0]), dLng = toRad(b[1] - a[1]);
  const h = Math.sin(dLat / 2) ** 2 + Math.cos(toRad(a[0])) * Math.cos(toRad(b[0])) * Math.sin(dLng / 2) ** 2;
  return 2 * R * Math.asin(Math.sqrt(h));
}

export const operationsService = {
  async startTrip(contractorId: string, input: { shuttleId: string; routeId: string; window: 'morning' | 'evening'; departTime: Date }) {
    const [shuttle] = await db.select().from(schema.shuttles).where(eq(schema.shuttles.id, input.shuttleId));
    if (!shuttle || shuttle.contractorId !== contractorId) throw new NotFoundError('Shuttle not found');

    if (!shuttle.isActive) throw new BadRequestError('Shuttle is not active');
    if (input.departTime.getTime() < Date.now() - 60_000) throw new BadRequestError('departTime must be in the future');
    const [existing] = await db.select().from(schema.trips)
      .where(and(eq(schema.trips.shuttleId, input.shuttleId), eq(schema.trips.status, 'in_transit'))).limit(1);
    if (existing) throw new ConflictError('Shuttle already has an in-transit trip');

    const [trip] = await db.insert(schema.trips).values({ ...input, contractorId, status: 'in_transit' }).returning();
    return trip;
  },

  async completeTrip(contractorId: string, tripId: string) {
    return db.transaction(async (tx) => {

      const [trip] = await tx.update(schema.trips)
        .set({ status: 'completed', arriveTime: new Date(), updatedAt: new Date() })
        .where(and(eq(schema.trips.id, tripId), eq(schema.trips.contractorId, contractorId), eq(schema.trips.status, 'in_transit')))
        .returning();
      if (!trip) throw new ConflictError('Trip not in a completable state');

      const boarded = await tx.update(schema.rides)
        .set({ status: 'completed', updatedAt: new Date() })
        .where(and(eq(schema.rides.tripId, tripId), eq(schema.rides.status, 'boarded')))
        .returning({ id: schema.rides.id, subscriptionId: schema.rides.subscriptionId, seatClaimId: schema.rides.seatClaimId, riderId: schema.rides.riderId });

      await tx.update(schema.rides)
        .set({ status: 'no_show', updatedAt: new Date() })
        .where(and(eq(schema.rides.tripId, tripId), eq(schema.rides.status, 'booked')));

      const seatClaimIds = boarded.map(r => r.seatClaimId).filter((id): id is string => id != null);
      if (seatClaimIds.length > 0) {
        await tx.update(schema.seatClaims)
          .set({ status: 'used', updatedAt: new Date() })
          .where(and(inArray(schema.seatClaims.id, seatClaimIds), eq(schema.seatClaims.status, 'confirmed')));
      }
      const subIds = [...new Set(boarded.map(r => r.subscriptionId).filter((id): id is string => id != null))];
      if (subIds.length > 0) {
        const subs = await tx.select().from(schema.subscriptions)
          .where(and(inArray(schema.subscriptions.id, subIds), eq(schema.subscriptions.status, 'active')));
        const planIds = [...new Set(subs.map(s => s.planId))];
        const plans = planIds.length > 0
          ? await tx.select().from(schema.subscriptionPlans).where(inArray(schema.subscriptionPlans.id, planIds))
          : [];
        const planById = new Map(plans.map(p => [p.id, p]));
        for (const sub of subs) {
          const plan = planById.get(sub.planId);
          if (plan && (plan.ridesIncluded === -1 || sub.ridesUsed < plan.ridesIncluded)) {
            await subscriptionRepo.incrementRidesUsed(tx as any, sub.id);
          }
        }
      }
      await tx.insert(schema.outboxEvents).values({ channel: 'audit', payload: { action: 'trip.completed', entityId: tripId } });
      return trip;
    });
  },

  async bookRide(riderId: string, input: { tripId: string; subscriptionId?: string | undefined; seatClaimId?: string | undefined; pickupStop?: string | undefined }) {
    if (!input.subscriptionId && !input.seatClaimId) {
      throw new BadRequestError('A subscriptionId or seatClaimId is required to book a ride');
    }
    const [trip] = await db.select().from(schema.trips).where(eq(schema.trips.id, input.tripId));

    if (!trip || (trip.status !== 'scheduled' && trip.status !== 'in_transit')) {
      throw new BadRequestError('Trip not open for booking');
    }
    const [shuttle] = await db.select().from(schema.shuttles).where(eq(schema.shuttles.id, trip.shuttleId));

    if (input.subscriptionId) {
      const [sub] = await db.select().from(schema.subscriptions).where(eq(schema.subscriptions.id, input.subscriptionId));
      if (!sub || sub.riderId !== riderId) throw new ForbiddenError('Subscription does not belong to this rider');
      if (sub.status !== 'active') throw new BadRequestError('Subscription is not active');
      const [plan] = await db.select().from(schema.subscriptionPlans).where(eq(schema.subscriptionPlans.id, sub.planId));
      if (plan && plan.ridesIncluded !== -1 && sub.ridesUsed >= plan.ridesIncluded) {
        throw new BadRequestError('Subscription ride quota exhausted');
      }
    }
    if (input.seatClaimId) {
      const [claim] = await db.select().from(schema.seatClaims).where(eq(schema.seatClaims.id, input.seatClaimId));
      if (!claim || claim.riderId !== riderId) throw new ForbiddenError('Seat claim does not belong to this rider');
      if (claim.status !== 'confirmed') throw new BadRequestError('Seat claim is not confirmed');
    }

    try {
      return await db.transaction(async (tx) => {
        const capacity = shuttle?.capacity ?? 0;
        const updated = await tx.update(schema.trips)
          .set({ seatsBooked: sql`${schema.trips.seatsBooked} + 1`, updatedAt: new Date() })
          .where(and(
            eq(schema.trips.id, trip.id),
            inArray(schema.trips.status, ['scheduled', 'in_transit']),
            sql`${schema.trips.seatsBooked} < ${capacity}`,
          ))
          .returning();
        if (updated.length === 0) throw new ConflictError('Trip is full');
        const [ride] = await tx.insert(schema.rides).values({ riderId, ...input, status: 'booked' }).returning();
        return ride;
      });
    } catch (e: any) {
      if (e.code === '23505') throw new ConflictError('Already booked on this trip');
      throw e;
    }
  },

  async board(riderId: string, rideId: string) {
    const [ride] = await db.update(schema.rides)
      .set({ status: 'boarded', updatedAt: new Date() })
      .where(and(
        eq(schema.rides.id, rideId),
        eq(schema.rides.riderId, riderId),
        eq(schema.rides.status, 'booked'),

        sql`EXISTS (SELECT 1 FROM ${schema.trips} WHERE ${schema.trips.id} = ${schema.rides.tripId} AND ${schema.trips.status} = 'in_transit')`,
      ))
      .returning();
    if (!ride) throw new ConflictError('Ride cannot be boarded in its current state');
    return ride;
  },

  async reportPosition(shuttleId: string, pos: { lat: number; lng: number; heading?: number | undefined; speed?: number | undefined }) {

    if (!Number.isFinite(pos.lat) || pos.lat < -90 || pos.lat > 90) throw new BadRequestError('lat must be in [-90, 90]');
    if (!Number.isFinite(pos.lng) || pos.lng < -180 || pos.lng > 180) throw new BadRequestError('lng must be in [-180, 180]');

    const [existing] = await db.select().from(schema.shuttlePositions).where(eq(schema.shuttlePositions.shuttleId, shuttleId));
    if (existing && haversineMeters([existing.lat, existing.lng], [pos.lat, pos.lng]) < MIN_GPS_MOVE_METERS) {
      return existing;
    }
    const [row] = await db.insert(schema.shuttlePositions)
      .values({ shuttleId, ...pos, updatedAt: new Date() })
      .onConflictDoUpdate({ target: schema.shuttlePositions.shuttleId, set: { ...pos, updatedAt: new Date() } })
      .returning();
    return row!;
  },
};

import { TypedOpenAPIHono } from '../../src/typed-hono';
import { z } from 'zod';
import { eq, and } from 'drizzle-orm';
import { requireRole } from '../../src/middleware/auth';
import { operationsService } from './service';
import { db, schema } from '@addis/db';
import { riderProfileIdFor, contractorProfileIdFor } from '../../src/profile-cache';
import { redis } from '../../infra/redis';

export const operationsRoutes = new TypedOpenAPIHono();

operationsRoutes.get('/trips', requireRole('contractor'), async (c) => {
  const profileId = await contractorProfileIdFor(c.get('session')!.userId);
  // API-004: paginate /trips — was returning ALL trips ever for the contractor.
  // Default to 50, max 200. Cursor pagination would be better but the table
  // lacks a monotonic cursor; limit + offset is acceptable for this admin-
  // ish endpoint. Status filter added.
  const limit = Math.min(Math.max(1, Number(c.req.query('limit') ?? 50) || 50), 200);
  const status = c.req.query('status');
  const VALID_STATUSES = ['scheduled', 'in_transit', 'completed', 'cancelled'] as const;
  const statusFilter = status && (VALID_STATUSES as readonly string[]).includes(status)
    ? (status as typeof VALID_STATUSES[number]) : undefined;
  const rows = await db.select().from(schema.trips)
    .where(and(
      eq(schema.trips.contractorId, profileId),
      statusFilter ? eq(schema.trips.status, statusFilter) : undefined,
    ))
    .orderBy(schema.trips.departTime)
    .limit(limit);
  return c.json({ data: rows });
});
operationsRoutes.post('/trips', requireRole('contractor'), async (c) => {
  const profileId = await contractorProfileIdFor(c.get('session')!.userId);

  const body = z.object({
    shuttleId: z.string(),
    routeId: z.string(),
    window: z.enum(['morning', 'evening']),

    departTime: z.never().optional(),
  }).parse(await c.req.json());
  const trip = await operationsService.startTrip(profileId, {
    shuttleId: body.shuttleId,
    routeId: body.routeId,
    window: body.window,
    departTime: new Date(),
  });
  return c.json({ data: trip }, 201);
});
operationsRoutes.patch('/trips/:id', requireRole('contractor'), async (c) => {
  const profileId = await contractorProfileIdFor(c.get('session')!.userId);
  const { event } = z.object({ event: z.literal('complete') }).parse(await c.req.json());
  const trip = event === 'complete' ? await operationsService.completeTrip(profileId, c.req.param('id')) : null;
  return c.json({ data: trip });
});

operationsRoutes.get('/rides', requireRole('rider'), async (c) => {
  const profileId = await riderProfileIdFor(c.get('session')!.userId);
  // API-004: paginate /rides — was returning ALL rides ever for the rider.
  const limit = Math.min(Math.max(1, Number(c.req.query('limit') ?? 50) || 50), 200);
  const status = c.req.query('status');
  const VALID_STATUSES = ['booked', 'boarded', 'completed', 'no_show', 'cancelled'] as const;
  const statusFilter = status && (VALID_STATUSES as readonly string[]).includes(status)
    ? (status as typeof VALID_STATUSES[number]) : undefined;
  const rows = await db.select().from(schema.rides)
    .where(and(
      eq(schema.rides.riderId, profileId),
      statusFilter ? eq(schema.rides.status, statusFilter) : undefined,
    ))
    .orderBy(schema.rides.createdAt)
    .limit(limit);
  return c.json({ data: rows });
});
operationsRoutes.post('/rides', requireRole('rider'), async (c) => {
  const profileId = await riderProfileIdFor(c.get('session')!.userId);
  const body = z.object({ tripId: z.string(), subscriptionId: z.string().optional(), seatClaimId: z.string().optional(), pickupStop: z.string().optional() }).parse(await c.req.json());
  const ride = await operationsService.bookRide(profileId, body);
  return c.json({ data: ride }, 201);
});
operationsRoutes.patch('/rides/:id', requireRole('rider'), async (c) => {
  const profileId = await riderProfileIdFor(c.get('session')!.userId);
  const { event } = z.object({ event: z.literal('board') }).parse(await c.req.json());
  const ride = event === 'board' ? await operationsService.board(profileId, c.req.param('id')) : null;
  return c.json({ data: ride });
});

operationsRoutes.get('/shuttle-positions', async (c) => {
  const ids = (c.req.query('shuttleIds') ?? '').split(',').filter(Boolean);
  if (!ids.length) {
    const rows = await db.select().from(schema.shuttlePositions);
    return c.json({ data: rows }, 200, { 'Cache-Control': 'public, max-age=10' });
  }
  const cached = await Promise.all(ids.map((id) => redis.hgetall(`shuttle:pos:${id}`)));
  return c.json({ data: cached.filter(Boolean) }, 200, { 'Cache-Control': 'public, max-age=10' });
});

operationsRoutes.post('/shuttle-positions', requireRole('contractor'), async (c) => {
  const body = z.object({ shuttleId: z.string(), lat: z.number(), lng: z.number(), heading: z.number().optional(), speed: z.number().optional() }).parse(await c.req.json());

  const profileId = await contractorProfileIdFor(c.get('session')!.userId);
  const [shuttle] = await db.select().from(schema.shuttles).where(eq(schema.shuttles.id, body.shuttleId));

  if (!shuttle || shuttle.contractorId !== profileId) {
    return c.json({ error: { code: 'FORBIDDEN', message: 'Not assigned to this shuttle', requestId: c.get('requestId') } }, 403);
  }

  const rlKey = `rl:gps:${body.shuttleId}`;
  const blocked = await redis.set(rlKey, '1', { nx: true, ex: 5 });
  if (!blocked) return c.json({ error: { code: 'RATE_LIMITED', message: 'GPS reports limited to 1 per 5s', requestId: c.get('requestId') } }, 429);

  const row = await operationsService.reportPosition(body.shuttleId, body);
  await redis.hset(`shuttle:pos:${body.shuttleId}`, { lat: row.lat, lng: row.lng, heading: row.heading, updatedAt: row.updatedAt });
  await redis.expire(`shuttle:pos:${body.shuttleId}`, 300);
  await redis.publish(`shuttle:updates:${body.shuttleId}`, JSON.stringify(row));
  return c.json({ data: row }, 201);
});

operationsRoutes.get('/shuttle-positions/stream', requireRole('rider'), async (c) => {
  const ids = (c.req.query('shuttleIds') ?? '').split(',').filter(Boolean);

  return new Response(new ReadableStream({
    async start(controller) {
      const encoder = new TextEncoder();
      const closed = { value: false };

      const pushPositions = async () => {
        if (closed.value) return;
        try {
          const positions = await Promise.all(ids.map((id) => redis.hgetall(`shuttle:pos:${id}`)));
          const valid = positions.filter(Boolean);
          if (valid.length) {
            controller.enqueue(encoder.encode(`data: ${JSON.stringify(valid)}\n\n`));
          } else {
            controller.enqueue(encoder.encode(':heartbeat\n\n'));
          }
        } catch {

          controller.enqueue(encoder.encode(':heartbeat\n\n'));
        }
      };

      await pushPositions();
      const interval = setInterval(pushPositions, 5000);

      c.req.raw.signal.addEventListener('abort', () => {
        closed.value = true;
        clearInterval(interval);
        try { controller.close(); } catch {  }
      });
    },
  }), { headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache', Connection: 'keep-alive' } });
});

import { defineStateMachine } from '@addis/shared';
import type { TripStatus, RideStatus } from '@addis/shared';

export const tripState = defineStateMachine<TripStatus>({
  initial: 'scheduled',
  transitions: [
    { from: 'scheduled', to: 'in_transit', event: 'contractor.start' },
    { from: 'in_transit', to: 'completed', event: 'contractor.complete', sideEffects: ['rides.fan_out', 'audit.trip_completed'] },
    { from: 'scheduled', to: 'cancelled', event: 'contractor.cancel' },
    { from: 'in_transit', to: 'cancelled', event: 'admin.cancel' },
  ],
});

export const rideState = defineStateMachine<RideStatus>({
  initial: 'booked',
  transitions: [
    { from: 'booked', to: 'boarded', event: 'rider.board' },
    { from: 'boarded', to: 'completed', event: 'trip.completed', sideEffects: ['subscription.increment_rides', 'seat_claim.mark_used'] },
    { from: 'booked', to: 'no_show', event: 'trip.completed' },
    { from: 'booked', to: 'cancelled', event: 'rider.cancel' },
  ],
});

import { and, eq, lt, sql, inArray } from 'drizzle-orm';
import { db, schema } from '@addis/db';

export const subscriptionRepo = {
  async findById(id: string) {
    const [row] = await db.select().from(schema.subscriptions).where(eq(schema.subscriptions.id, id));
    return row ?? null;
  },
  async findActiveForRiderRoute(riderId: string, routeId: string) {
    const [row] = await db.select().from(schema.subscriptions).where(and(
      eq(schema.subscriptions.riderId, riderId),
      eq(schema.subscriptions.routeId, routeId),
      eq(schema.subscriptions.status, 'active'),
    ));
    return row ?? null;
  },
  async hasUsedTrial(riderId: string, trialPlanId: string) {

    const rows = await db.select({ id: schema.subscriptions.id }).from(schema.subscriptions)
      .where(and(
        eq(schema.subscriptions.riderId, riderId),
        eq(schema.subscriptions.planId, trialPlanId),
        sql`${schema.subscriptions.status} in ('active', 'expired')`,
      ));
    return rows.length > 0;
  },

  async expireDue(tx = db) {
    const expired = await tx.update(schema.subscriptions)
      .set({ status: 'expired', updatedAt: new Date() })
      .where(and(eq(schema.subscriptions.status, 'active'), lt(schema.subscriptions.endDate, sql`now()`)))
      .returning({ id: schema.subscriptions.id, riderId: schema.subscriptions.riderId });

    if (expired.length > 0) {
      await tx.insert(schema.outboxEvents).values(
        expired.flatMap(s => [
          { channel: 'notification' as const, payload: { type: 'subscription_expired', userId: s.riderId, subscriptionId: s.id } },
          { channel: 'audit' as const, payload: { action: 'subscription.expired', entityId: s.id } },
        ]),
      );
    }
    return expired;
  },

  async cancelStalePending(tx = db, olderThanHours = 2) {
    const cancelled = await tx.update(schema.subscriptions)
      .set({ status: 'cancelled', cancelledAt: new Date(), updatedAt: new Date() })
      .where(and(
        eq(schema.subscriptions.status, 'pending_payment'),
        lt(schema.subscriptions.createdAt, sql`now() - make_interval(hours => ${olderThanHours})`),
      ))
      .returning({ id: schema.subscriptions.id, riderId: schema.subscriptions.riderId });

    if (cancelled.length > 0) {

      const subIds = cancelled.map(s => s.id);
      await tx.update(schema.payments)
        .set({ status: 'failed', updatedAt: new Date() })
        .where(and(
          inArray(schema.payments.subscriptionId, subIds),
          eq(schema.payments.status, 'pending'),
        ));
      await tx.insert(schema.outboxEvents).values(
        cancelled.map(s => ({
          channel: 'audit' as const,
          payload: { action: 'subscription.cancelled_stale', entityId: s.id, userId: s.riderId },
        })),
      );
    }
    return cancelled;
  },

  async decrementRidesUsed(tx = db, subscriptionId: string) {
    await tx.update(schema.subscriptions)
      .set({ ridesUsed: sql`greatest(${schema.subscriptions.ridesUsed} - 1, 0)`, updatedAt: new Date() })
      .where(and(eq(schema.subscriptions.id, subscriptionId), eq(schema.subscriptions.status, 'active')));
  },

  async incrementRidesUsed(tx = db, subscriptionId: string) {

    await tx.execute(sql`
      UPDATE subscriptions SET rides_used = rides_used + 1, updated_at = now()
      WHERE id = ${subscriptionId}
        AND status = 'active'
        AND (
          (SELECT rides_included FROM subscription_plans WHERE id = subscriptions.plan_id) = -1
          OR (SELECT rides_included FROM subscription_plans WHERE id = subscriptions.plan_id) > rides_used
        )
    `);
  },
};

import { addDays } from 'date-fns';
import { and, desc, eq } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { Money, ConflictError, BadRequestError, NotFoundError, PAYMENT_RETENTION_YEARS, loadEnv } from '@addis/shared';
import { getPaymentProvider } from '@addis/payments';
import { createId } from '@paralleldrive/cuid2';
import type { CreateSubscriptionInput } from './types';
import { subscriptionRepo } from './repository';
import { transitionSubscription } from './state';
import { scheduleRefund } from '../payment/service';

const env = loadEnv();
function addYears(d: Date, years: number) { const c = new Date(d); c.setFullYear(c.getFullYear() + years); return c; }

function generateMerchOrderId() { return `SUB${createId()}`; }

export const subscriptionService = {
  async create(input: CreateSubscriptionInput) {
    const [plan] = await db.select().from(schema.subscriptionPlans).where(eq(schema.subscriptionPlans.id, input.planId));
    if (!plan || !plan.isActive) throw new NotFoundError('Plan not found');
    const [route] = await db.select().from(schema.routes).where(eq(schema.routes.id, input.routeId));
    if (!route || !route.isActive) throw new NotFoundError('Route not found');

    const existing = await subscriptionRepo.findActiveForRiderRoute(input.riderId, input.routeId);
    if (existing) throw new ConflictError('Rider already has an active subscription on this route');

    if (plan.isTrial && await subscriptionRepo.hasUsedTrial(input.riderId, plan.id)) {
      throw new ConflictError('Trial plan already used');
    }

    let price = Money.fromDecimal(plan.priceETB);
    let corporateMemberId: string | null = null;
    if (input.corporateMemberId) {

      const [member] = await db.select().from(schema.corporateMembers).where(eq(schema.corporateMembers.id, input.corporateMemberId));
      if (!member || member.approvalStatus !== 'approved' || !member.isActive) {
        throw new BadRequestError('Corporate membership not approved');
      }

      const [riderProfile] = await db.select().from(schema.riderProfiles).where(eq(schema.riderProfiles.id, input.riderId));
      if (!riderProfile || member.userId !== riderProfile.userId) {
        throw new BadRequestError('Corporate membership does not belong to this rider');
      }
      const [corp] = await db.select().from(schema.corporates).where(eq(schema.corporates.id, member.corporateId));
      if (corp && corp.isActive) {
        price = price.sub(price.pct(corp.subsidyPercent));
      }
      corporateMemberId = member.id;
    }

    const { sub, payment, merchOrderId } = await db.transaction(async (tx) => {
      const [sub] = await tx.insert(schema.subscriptions).values({
        riderId: input.riderId, planId: plan.id, routeId: route.id, corporateMemberId,
        status: 'pending_payment',
        morningSlot: input.morningSlot, eveningSlot: input.eveningSlot,
        startDate: new Date(), endDate: addDays(new Date(), plan.durationDays),
      }).returning();

      const merchOrderId = generateMerchOrderId();
      const [payment] = await tx.insert(schema.payments).values({
        riderId: input.riderId, subscriptionId: sub!.id, amount: price.toString(),
        method: input.paymentMethod, reference: merchOrderId, status: 'pending',
        retentionExpiresAt: addYears(new Date(), PAYMENT_RETENTION_YEARS),
      }).returning();

      return { sub: sub!, payment: payment!, merchOrderId };
    });

    const provider = getPaymentProvider(input.paymentMethod);
    const checkout = await provider.createCheckout({
      merchOrderId, amount: price, description: `Addis Ride — ${plan.name}`,
      notifyUrl: env.TELEBIRR_NOTIFY_URL, redirectUrl: env.TELEBIRR_REDIRECT_URL,
    });

    if (checkout.status === 'checkout') {
      await db.update(schema.payments).set({ prepayId: checkout.prepayId }).where(eq(schema.payments.id, payment.id));
    }

    return { subscription: sub, payment, checkout };
  },

  async renew(subscriptionId: string, riderId: string, paymentMethod: 'telebirr' | 'cbe') {
    const sub = await subscriptionRepo.findById(subscriptionId);
    if (!sub || sub.riderId !== riderId) throw new NotFoundError('Subscription not found');
    if (sub.status !== 'expired' && sub.status !== 'cancelled') throw new ConflictError('Only expired/cancelled subscriptions can be renewed');

    if (!sub.routeId) throw new BadRequestError('Cannot renew a subscription whose route has been deleted');
    return subscriptionService.create({
      riderId, planId: sub.planId, routeId: sub.routeId,
      morningSlot: sub.morningSlot ?? undefined, eveningSlot: sub.eveningSlot ?? undefined,
      paymentMethod, corporateMemberId: sub.corporateMemberId ?? undefined,
    });
  },

  async cancel(subscriptionId: string, riderId: string) {
    const sub = await subscriptionRepo.findById(subscriptionId);
    if (!sub || sub.riderId !== riderId) throw new NotFoundError('Subscription not found');
    return db.transaction(async (tx) => {
      const result = await transitionSubscription(tx, subscriptionId, 'subscription.cancelled');
      await tx.update(schema.subscriptions).set({ cancelledAt: new Date() }).where(eq(schema.subscriptions.id, subscriptionId));

      if (sub.status === 'active') {
        const [plan] = await tx.select().from(schema.subscriptionPlans).where(eq(schema.subscriptionPlans.id, sub.planId));
        const [payment] = await tx.select().from(schema.payments)
          .where(and(eq(schema.payments.subscriptionId, subscriptionId), eq(schema.payments.status, 'completed')))
          .orderBy(desc(schema.payments.createdAt)).limit(1);
        if (plan && payment && plan.ridesIncluded > 0) {
          const unusedRides = Math.max(0, plan.ridesIncluded - sub.ridesUsed);
          if (unusedRides > 0) {

            const paidAmount = Money.fromDecimal(payment.amount);
            const refundAmount = paidAmount.mul(unusedRides).div(plan.ridesIncluded);

            if (refundAmount.isPositive() && refundAmount.lte(paidAmount)) {
              await scheduleRefund(payment.id, refundAmount, 'subscription_cancelled', tx);
            }
          }
        }
      }

      await tx.insert(schema.outboxEvents).values([
        { channel: 'notification', payload: { type: 'subscription_cancelled', userId: riderId } },
        { channel: 'audit', payload: { action: 'subscription.cancelled', entityId: subscriptionId } },
      ]);
      return result;
    });
  },
};

import { z } from 'zod';
import { Id, TimeOfDay } from '@addis/shared';

export const CreateSubscriptionInput = z.object({
  planId: Id, routeId: Id,
  morningSlot: TimeOfDay.optional(), eveningSlot: TimeOfDay.optional(),
  paymentMethod: z.enum(['telebirr', 'cbe']),
  corporateMemberId: Id.optional(),
});
export type CreateSubscriptionInput = z.infer<typeof CreateSubscriptionInput> & { riderId: string };

export interface SubscriptionSummary {
  id: string; riderId: string; status: string; routeId: string | null;
  ridesUsed: number; ridesIncluded: number; endDate: Date;
}

import { createRoute, z } from '@hono/zod-openapi';
import { TypedOpenAPIHono } from '../../src/typed-hono';
import { ErrorSchema, envelope } from '@addis/shared';
import { requireRole } from '../../src/middleware/auth';
import { CreateSubscriptionInput } from './types';
import { subscriptionService } from './service';
import { db, schema } from '@addis/db';
import { eq, and, desc } from 'drizzle-orm';
import { NotFoundError } from '@addis/shared';

export const subscriptionRoutes = new TypedOpenAPIHono();

const SubscriptionSchema = z.object({
  id: z.string(), riderId: z.string(), planId: z.string(), routeId: z.string().nullable(),
  status: z.string(), ridesUsed: z.number(), startDate: z.string(), endDate: z.string(),
});

async function riderProfileIdFor(userId: string): Promise<string> {
  const [profile] = await db.select().from(schema.riderProfiles).where(eq(schema.riderProfiles.userId, userId));
  if (!profile) throw new NotFoundError('Rider profile not found');
  return profile.id;
}

// API-002: GET /subscriptions — list the rider's own subscriptions (active +
// history). Previously missing — riders could only see their most recent
// active sub via /dashboard/rider, with no history.
subscriptionRoutes.get('/', requireRole('rider'), async (c) => {
  const session = c.get('session')!;
  const riderId = await riderProfileIdFor(session.userId);
  const status = c.req.query('status');
  const VALID_STATUSES = ['pending_payment', 'active', 'expired', 'cancelled'] as const;
  const statusFilter = status && (VALID_STATUSES as readonly string[]).includes(status)
    ? (status as typeof VALID_STATUSES[number]) : undefined;
  const limit = Math.min(Math.max(1, Number(c.req.query('limit') ?? 50) || 50), 200);
  const rows = await db.select().from(schema.subscriptions)
    .where(and(
      eq(schema.subscriptions.riderId, riderId),
      statusFilter ? eq(schema.subscriptions.status, statusFilter) : undefined,
    ))
    .orderBy(desc(schema.subscriptions.createdAt))
    .limit(limit);
  return c.json({ data: rows });
});

const createRoute1 = createRoute({
  method: 'post', path: '/', security: [{ bearerAuth: [] }, { cookieAuth: [] }],
  middleware: [requireRole('rider')] as const,
  request: { body: { content: { 'application/json': { schema: CreateSubscriptionInput } } } },
  responses: {
    201: { content: { 'application/json': { schema: envelope(SubscriptionSchema) } }, description: 'Created' },
    400: { content: { 'application/json': { schema: ErrorSchema } }, description: 'Validation' },
    409: { content: { 'application/json': { schema: ErrorSchema } }, description: 'Conflict (dup active sub / trial used)' },
  },
});

subscriptionRoutes.openapi(createRoute1, async (c) => {
  const body = c.req.valid('json');
  const session = c.get('session');
  const riderId = await riderProfileIdFor(session.userId);
  const result = await subscriptionService.create({ ...body, riderId });
  return c.json({ data: result.subscription, meta: { checkout: result.checkout } } as any, 201);
});

const renewRoute = createRoute({
