  responses: { 201: { content: { 'application/json': { schema: envelope(SubscriptionSchema) } }, description: 'Renewed' } },
});
subscriptionRoutes.openapi(renewRoute, async (c) => {
  const { id } = c.req.valid('param');
  const { paymentMethod } = c.req.valid('json');
  const session = c.get('session');
  const riderId = await riderProfileIdFor(session.userId);
  const result = await subscriptionService.renew(id, riderId, paymentMethod);
  return c.json({ data: result.subscription } as any, 201);
});

const cancelRoute = createRoute({
  method: 'delete', path: '/{id}', security: [{ bearerAuth: [] }, { cookieAuth: [] }],
  middleware: [requireRole('rider')] as const,
  request: { params: z.object({ id: z.string() }) },
  responses: { 200: { content: { 'application/json': { schema: envelope(z.object({ status: z.string() })) } }, description: 'Cancelled' } },
});
subscriptionRoutes.openapi(cancelRoute, async (c) => {
  const { id } = c.req.valid('param');
  const session = c.get('session');
  const riderId = await riderProfileIdFor(session.userId);
  const result = await subscriptionService.cancel(id, riderId);
  return c.json({ data: { status: result.to } } as any, 200);
});

import { defineStateMachine } from '@addis/shared';
import type { SubscriptionStatus } from '@addis/shared';
import { and, eq } from 'drizzle-orm';

export const subscriptionState = defineStateMachine<SubscriptionStatus>({
  initial: 'pending_payment',
  transitions: [
    { from: 'pending_payment', to: 'active', event: 'payment.settled', sideEffects: ['notify.payment_received', 'audit.subscription_activated'] },
    { from: 'pending_payment', to: 'cancelled', event: 'payment.failed', sideEffects: ['notify.payment_failed', 'audit.subscription_cancelled'] },
    { from: 'pending_payment', to: 'cancelled', event: 'subscription.stale', sideEffects: ['audit.subscription_cancelled'] },
    { from: 'active', to: 'expired', event: 'subscription.expired', sideEffects: ['notify.subscription_expired', 'audit.subscription_expired'] },
    { from: 'active', to: 'cancelled', event: 'subscription.cancelled', sideEffects: ['refund.if_eligible', 'notify.subscription_cancelled', 'audit.subscription_cancelled'] },
  ],
});

export async function transitionSubscription(
  tx: import('@addis/db').DbOrTx, subscriptionId: string, event: string,
) {
  const { schema } = await import('@addis/db');
  const [row] = await tx.select().from(schema.subscriptions).where(eq(schema.subscriptions.id, subscriptionId));
  if (!row) throw new Error(`Subscription ${subscriptionId} not found`);
  const t = subscriptionState.resolve(row.status, event);

  const updated = await tx.update(schema.subscriptions)
    .set({ status: t.to, updatedAt: new Date() })
    .where(and(eq(schema.subscriptions.id, subscriptionId), eq(schema.subscriptions.status, row.status)))
    .returning();
  if (updated.length === 0) {

    const [fresh] = await tx.select().from(schema.subscriptions).where(eq(schema.subscriptions.id, subscriptionId));
    if (fresh) {

      subscriptionState.resolve(fresh.status, event);
    }
    throw new Error(`Subscription ${subscriptionId} transition lost to concurrent writer`);
  }
  return { from: t.from, to: t.to, sideEffects: t.sideEffects ?? [] };
}

import { and, eq, lt } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { NotFoundError, ForbiddenError, BadRequestError } from '@addis/shared';
import { z } from 'zod';
import { ticketState } from './state';

export const supportService = {

  async createTicket(userId: string, input: { subject: string; body: string; category: string; subscriptionId?: string | undefined; paymentId?: string | undefined }) {
    if (input.subscriptionId) {
      const [profile] = await db.select().from(schema.riderProfiles).where(eq(schema.riderProfiles.userId, userId));
      if (!profile) throw new BadRequestError('Rider profile not found');
      const [sub] = await db.select().from(schema.subscriptions)
        .where(and(eq(schema.subscriptions.id, input.subscriptionId), eq(schema.subscriptions.riderId, profile.id))).limit(1);
      if (!sub) throw new ForbiddenError('Subscription does not belong to this rider');
    }
    if (input.paymentId) {
      const [profile] = await db.select().from(schema.riderProfiles).where(eq(schema.riderProfiles.userId, userId));
      if (!profile) throw new BadRequestError('Rider profile not found');
      const [payment] = await db.select().from(schema.payments)
        .where(and(eq(schema.payments.id, input.paymentId), eq(schema.payments.riderId, profile.id))).limit(1);
      if (!payment) throw new ForbiddenError('Payment does not belong to this rider');
    }
    const [ticket] = await db.insert(schema.supportTickets).values({ userId, ...input } as any).returning();
    await db.insert(schema.outboxEvents).values({ channel: 'audit', payload: { action: 'ticket.created', entityId: ticket!.id, actorId: userId } });
    return ticket;
  },

  async listForUser(userId: string, isStaff: boolean, opts?: { limit?: number }) {

    const rawLimit = opts?.limit ?? 50;
    const limit = Math.min(Math.max(1, Math.trunc(rawLimit)), 500);
    if (isStaff) return db.select().from(schema.supportTickets).orderBy(schema.supportTickets.createdAt).limit(limit);
    return db.select().from(schema.supportTickets)
      .where(eq(schema.supportTickets.userId, userId))
      .orderBy(schema.supportTickets.createdAt)
      .limit(limit);
  },

  async getTicket(userId: string, isStaff: boolean, ticketId: string) {
    const [t] = await db.select().from(schema.supportTickets).where(eq(schema.supportTickets.id, ticketId));
    if (!t) throw new NotFoundError('Ticket not found');
    if (!isStaff && t.userId !== userId) throw new ForbiddenError();
    return t;
  },

  async reply(authorId: string, isStaff: boolean, ticketId: string, body: string) {
    return db.transaction(async (tx) => {
      const [ticket] = await tx.select().from(schema.supportTickets).where(eq(schema.supportTickets.id, ticketId));
      if (!ticket) throw new NotFoundError('Ticket not found');
      if (!isStaff && ticket.userId !== authorId) throw new ForbiddenError('Not your ticket');

      await tx.insert(schema.ticketMessages).values({ ticketId, authorId, body, isStaff });

      if (isStaff && ticket.status === 'open') {
        const t = ticketState.resolve('open', 'staff.replied');
        await tx.update(schema.supportTickets).set({
          status: t.to, firstResponseAt: ticket.firstResponseAt ?? new Date(), assignedToId: ticket.assignedToId ?? authorId, updatedAt: new Date(),
        }).where(eq(schema.supportTickets.id, ticketId));
        await tx.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'support_reply', userId: ticket.userId } });
      } else if (!isStaff && (ticket.status === 'resolved' || ticket.status === 'closed')) {

        const t = ticketState.resolve(ticket.status, 'user.reopened');
        await tx.update(schema.supportTickets).set({
          status: t.to, resolvedAt: null, closedAt: null, updatedAt: new Date(),
        }).where(eq(schema.supportTickets.id, ticketId));
      }
    });
  },

  async setStatus(adminId: string, ticketId: string, event: 'staff.resolved' | 'user.reopened') {
    const [ticket] = await db.select().from(schema.supportTickets).where(eq(schema.supportTickets.id, ticketId));
    if (!ticket) throw new NotFoundError('Ticket not found');

    if (event === 'user.reopened' && ticket.userId !== adminId) {
      throw new ForbiddenError('Not your ticket');
    }
    const t = ticketState.resolve(ticket.status, event);

    await db.update(schema.supportTickets).set({
      status: t.to,
      resolvedAt: t.to === 'resolved' ? new Date() : ticket.resolvedAt,
      resolvedById: t.to === 'resolved' ? adminId : null,
      updatedAt: new Date(),
    }).where(eq(schema.supportTickets.id, ticketId));
    if (t.to === 'resolved') await db.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'support_resolved', userId: ticket.userId } });
    return t;
  },

  async autoCloseStale() {
    return db.update(schema.supportTickets).set({ status: 'closed', closedAt: new Date(), updatedAt: new Date() })
      .where(and(eq(schema.supportTickets.status, 'resolved'), lt(schema.supportTickets.resolvedAt, new Date(Date.now() - 7 * 86400_000))))
      .returning({ id: schema.supportTickets.id });
  },
};

const FaqInput = z.object({
  question: z.string().min(3).max(500),
  answer: z.string().min(1).max(5000),
  category: z.enum(['billing', 'routes', 'shuttle', 'account', 'corporate', 'general']),
  sortOrder: z.number().int().min(0).max(10000).optional(),
  isActive: z.boolean().optional(),
}).strict();

export const faqService = {
  async list(category?: string) {
    const where = category ? and(eq(schema.faqArticles.isActive, true), eq(schema.faqArticles.category, category as any)) : eq(schema.faqArticles.isActive, true);
    return db.select().from(schema.faqArticles).where(where).orderBy(schema.faqArticles.sortOrder);
  },
  async create(input: unknown) {
    const data = FaqInput.parse(input);
    const [row] = await db.insert(schema.faqArticles).values(data).returning();
    return row;
  },
  async update(id: string, input: unknown) {
    const data = FaqInput.partial().parse(input);
    const [row] = await db.update(schema.faqArticles).set({ ...data, updatedAt: new Date() }).where(eq(schema.faqArticles.id, id)).returning();
    if (!row) throw new NotFoundError('FAQ article not found');
    return row;
  },
  async remove(id: string) { await db.update(schema.faqArticles).set({ isActive: false }).where(eq(schema.faqArticles.id, id)); },
  async vote(id: string, helpful: boolean) {
    const col = helpful ? schema.faqArticles.helpfulYes : schema.faqArticles.helpfulNo;
    const { sql } = await import('drizzle-orm');
    await db.update(schema.faqArticles).set({ [helpful ? 'helpfulYes' : 'helpfulNo']: sql`${col} + 1` } as any).where(eq(schema.faqArticles.id, id));
  },
};

import { TypedOpenAPIHono } from '../../src/typed-hono';
import { z } from 'zod';
import { eq } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { requireAuth } from '../../src/middleware/auth';
import { supportService, faqService } from './service';

export const supportRoutes = new TypedOpenAPIHono();

const CreateTicket = z.object({ subject: z.string().min(3), body: z.string().min(1), category: z.string().default('general'), subscriptionId: z.string().optional(), paymentId: z.string().optional() });
const Reply = z.object({ body: z.string().min(1) });

supportRoutes.use('/tickets/*', requireAuth);
supportRoutes.use('/tickets', requireAuth);

supportRoutes.get('/tickets', async (c) => {
  const session = c.get('session')!;
  const isStaff = session.role === 'platform_admin';
  return c.json({ data: await supportService.listForUser(session.userId, isStaff) });
});
supportRoutes.post('/tickets', async (c) => {
  const session = c.get('session')!;
  const body = CreateTicket.parse(await c.req.json());
  return c.json({ data: await supportService.createTicket(session.userId, body) }, 201);
});
supportRoutes.get('/tickets/:id', async (c) => {
  const session = c.get('session')!;
  return c.json({ data: await supportService.getTicket(session.userId, session.role === 'platform_admin', c.req.param('id')) });
});
// API-003: GET /tickets/:id/messages — list messages for a ticket. The web
// ticket-detail page calls this but the route was missing — messages were
// never displayed. Gated to the ticket owner or platform_admin staff.
supportRoutes.get('/tickets/:id/messages', async (c) => {
  const session = c.get('session')!;
  const isStaff = session.role === 'platform_admin';
  // Reuse getTicket to enforce ownership / staff access.
  await supportService.getTicket(session.userId, isStaff, c.req.param('id'));
  const rows = await db.select().from(schema.ticketMessages)
    .where(eq(schema.ticketMessages.ticketId, c.req.param('id')))
    .orderBy(schema.ticketMessages.createdAt);
  return c.json({ data: rows });
});
supportRoutes.post('/tickets/:id/messages', async (c) => {
  const session = c.get('session')!;
  const body = Reply.parse(await c.req.json());
  await supportService.reply(session.userId, session.role === 'platform_admin', c.req.param('id'), body.body);
  return c.body(null, 201);
});
supportRoutes.patch('/tickets/:id', async (c) => {

  const session = c.get('session')!;
  const { event } = z.object({ event: z.enum(['staff.resolved', 'user.reopened']) }).parse(await c.req.json());
  if (event === 'staff.resolved' && session.role !== 'platform_admin') {
    return c.json({ error: { code: 'FORBIDDEN', message: 'Only staff can resolve tickets', requestId: c.get('requestId') } }, 403);
  }
  return c.json({ data: await supportService.setStatus(session.userId, c.req.param('id'), event) });
});

supportRoutes.get('/faq', async (c) => c.json({ data: await faqService.list(c.req.query('category')) }));

import { defineStateMachine } from '@addis/shared';
import type { TicketStatus } from '@addis/shared';

export const ticketState = defineStateMachine<TicketStatus>({
  initial: 'open',
  transitions: [
    { from: 'open', to: 'in_progress', event: 'staff.replied', sideEffects: ['notify.support_reply'] },
    { from: 'in_progress', to: 'resolved', event: 'staff.resolved', sideEffects: ['notify.support_resolved'] },
    { from: 'open', to: 'resolved', event: 'staff.resolved', sideEffects: ['notify.support_resolved'] },
    { from: 'resolved', to: 'closed', event: 'auto.close', sideEffects: [] },
    { from: 'resolved', to: 'open', event: 'user.reopened', sideEffects: [] },
    { from: 'closed', to: 'open', event: 'user.reopened', sideEffects: [] },
  ],
});

import { describe, it, expect, vi, beforeEach } from 'vitest';

const TICKET_ROW = {
  id: 'ticket-1', userId: 'user-owner-1', status: 'resolved',
  firstResponseAt: new Date(), resolvedAt: new Date(), assignedToId: null,
  subject: 'Test', body: 'Test body', priority: 'normal', category: 'general',
  closedAt: null,
};

vi.mock('@addis/db', () => {
  const chain = {
    from: vi.fn(() => chain),
    where: vi.fn(async () => [TICKET_ROW]),
  };
  const updateChain = {
    set: vi.fn(() => updateChain),
    where: vi.fn(async () => [TICKET_ROW]),
  };
  return {
    db: {
      select: vi.fn(() => chain),
      update: vi.fn(() => updateChain),
      insert: vi.fn(() => ({ values: vi.fn() })),
    },
    schema: new Proxy({}, { get: () => ({}) }),
  };
});

vi.mock('./state', () => ({
  ticketState: {
    resolve: vi.fn((current: string, event: string) => {
      if (current === 'resolved' && event === 'user.reopened') return { from: 'resolved', to: 'open', sideEffects: [] };
      if (current === 'closed' && event === 'user.reopened') return { from: 'closed', to: 'open', sideEffects: [] };
      if (current === 'open' && event === 'staff.resolved') return { from: 'open', to: 'resolved', sideEffects: ['notify.support_resolved'] };
      if (current === 'in_progress' && event === 'staff.resolved') return { from: 'in_progress', to: 'resolved', sideEffects: ['notify.support_resolved'] };
      throw new Error(`No transition from ${current} on ${event}`);
    }),
  },
}));

describe('supportService.setStatus', () => {
  beforeEach(() => vi.clearAllMocks());

  it('transitions a resolved ticket to open on user.reopened (owner caller)', async () => {
    const { supportService } = await import('./service');

    const result = await supportService.setStatus('user-owner-1', 'ticket-1', 'user.reopened');
    expect(result.to).toBe('open');
  });

  it('rejects a non-owner caller on user.reopened (SEC-002 IDOR fix)', async () => {
    const { supportService } = await import('./service');

    await expect(supportService.setStatus('user-attacker', 'ticket-1', 'user.reopened'))
      .rejects.toThrow(/not your ticket/i);
  });

  it('transitions an open ticket to resolved on staff.resolved', async () => {

    const { db } = await import('@addis/db');
    const chain = (db.select as any)();
    chain.where.mockResolvedValueOnce([{ ...TICKET_ROW, status: 'open' }]);
    const { supportService } = await import('./service');
    const result = await supportService.setStatus('admin-1', 'ticket-1', 'staff.resolved');
    expect(result.to).toBe('resolved');
  });

  it('throws NotFoundError when the ticket does not exist', async () => {
    const { db } = await import('@addis/db');
    const chain = (db.select as any)();
    chain.where.mockResolvedValueOnce([]);
    const { supportService } = await import('./service');

    await expect(supportService.setStatus('user-owner-1', 'nonexistent', 'user.reopened'))
      .rejects.toThrow(/not found/i);
  });
});

import { and, desc, eq, sql } from 'drizzle-orm';
import { db, schema } from '@addis/db';

export const dashboardService = {
  async rider(userId: string) {
    const [profile] = await db.select().from(schema.riderProfiles).where(eq(schema.riderProfiles.userId, userId));
    if (!profile) return { activeSubscription: null, unreadNotifications: 0 };

    const [sub] = await db.select({
      id: schema.subscriptions.id, status: schema.subscriptions.status, ridesUsed: schema.subscriptions.ridesUsed,
      planName: schema.subscriptionPlans.name, ridesIncluded: schema.subscriptionPlans.ridesIncluded,
      routeName: schema.routes.name, routeId: schema.routes.id, endDate: schema.subscriptions.endDate,
    }).from(schema.subscriptions)
      .innerJoin(schema.subscriptionPlans, eq(schema.subscriptions.planId, schema.subscriptionPlans.id))
      .leftJoin(schema.routes, eq(schema.subscriptions.routeId, schema.routes.id))
      .where(and(eq(schema.subscriptions.riderId, profile.id), eq(schema.subscriptions.status, 'active')))
      .orderBy(desc(schema.subscriptions.createdAt)).limit(1);

    const unread = (await db.select({ count: sql<number>`count(*)::int` }).from(schema.notifications)
      .where(and(eq(schema.notifications.userId, userId), sql`${schema.notifications.readAt} is null`)))[0]!.count;

    return {
      activeSubscription: sub ? { id: sub.id, status: sub.status, ridesUsed: sub.ridesUsed, plan: { name: sub.planName, ridesIncluded: sub.ridesIncluded }, route: { name: sub.routeName, id: sub.routeId } } : null,
      unreadNotifications: unread,
    };
  },

  async riderActiveTrip(userId: string, subscriptionId: string) {
    const [profile] = await db.select().from(schema.riderProfiles).where(eq(schema.riderProfiles.userId, userId));
    const [sub] = await db.select().from(schema.subscriptions).where(and(eq(schema.subscriptions.id, subscriptionId), eq(schema.subscriptions.riderId, profile!.id)));
    if (!sub?.routeId) return null;

    const [trip] = await db.select({
      id: schema.trips.id, shuttleId: schema.trips.shuttleId, departTime: schema.trips.departTime,
      plateNumber: schema.shuttles.plateNumber,
      contractorName: schema.users.name, contractorPhone: schema.users.phone, contractorRating: schema.contractorProfiles.rating,
      polyline: schema.routes.polyline, destination: schema.routes.destination,
    }).from(schema.trips)
      .innerJoin(schema.shuttles, eq(schema.trips.shuttleId, schema.shuttles.id))
      .innerJoin(schema.contractorProfiles, eq(schema.trips.contractorId, schema.contractorProfiles.id))
      .innerJoin(schema.users, eq(schema.contractorProfiles.userId, schema.users.id))
      .innerJoin(schema.routes, eq(schema.trips.routeId, schema.routes.id))
      .where(and(eq(schema.trips.routeId, sub.routeId), eq(schema.trips.status, 'in_transit')))
      .orderBy(desc(schema.trips.departTime)).limit(1);

    if (!trip) return null;
    return { ...trip, pickupStop: sub.morningSlot ?? 'Nearest stop', destinationStop: trip.destination, etaMinutes: 8 };
  },

  async contractor(userId: string) {
    const [profile] = await db.select().from(schema.contractorProfiles).where(eq(schema.contractorProfiles.userId, userId));
    if (!profile) return null;

    return { verificationStatus: profile.verificationStatus, rating: profile.rating, earningsThisMonth: '0.00' };
  },

  async corporate(adminUserId: string) {
    const [corp] = await db.select().from(schema.corporates).where(eq(schema.corporates.adminUserId, adminUserId));
    if (!corp) return null;
    const memberCount = (await db.select({ count: sql<number>`count(*)::int` }).from(schema.corporateMembers).where(eq(schema.corporateMembers.corporateId, corp.id)))[0]!;
    const pendingCount = (await db.select({ count: sql<number>`count(*)::int` }).from(schema.corporateMembers)
      .where(and(eq(schema.corporateMembers.corporateId, corp.id), eq(schema.corporateMembers.approvalStatus, 'pending'))))[0]!;
    return { corporate: corp, memberCount, pendingApprovals: pendingCount };
  },
};

