adminRoutes.get('/payments', async (c) => {
  const status = c.req.query('status');

  const VALID_STATUSES = ['pending', 'completed', 'failed', 'refunded'] as const;
  const statusFilter = status && (VALID_STATUSES as readonly string[]).includes(status) ? (status as typeof VALID_STATUSES[number]) : undefined;
  const rows = await db.select().from(schema.payments)
    .where(statusFilter ? eq(schema.payments.status, statusFilter) : undefined)
    .limit(boundedLimit(c.req.query('limit'), 50, 500));
  return c.json({ data: rows });
});
adminRoutes.post('/payments/:id/verify', async (c) => {

  const body = z.object({
    verifiedAmount: z.string().regex(/^\d+(\.\d{1,2})?$/, 'verifiedAmount must be a decimal ETB string'),
    reason: z.string().min(3).max(500),
  }).parse(await c.req.json());
  const adminId = c.get('session')!.userId;
  const ipAddress = clientIp(c) ?? null;

  const result = await db.transaction(async (tx) => {
    const { writeAudit } = await import('./audit');
    const { transitionSubscription } = await import('../subscription/state');
    const { Money } = await import('@addis/shared');

    const [payment] = await tx.update(schema.payments)
      .set({ status: 'completed', updatedAt: new Date() })
      .where(and(eq(schema.payments.id, c.req.param('id')), eq(schema.payments.status, 'pending')))
      .returning();
    if (!payment) return { payment: null };

    const expected = Money.fromDecimal(payment.amount);
    const actual = Money.fromETBString(body.verifiedAmount);
    if (!expected.eq(actual)) {

      await tx.update(schema.payments).set({ status: 'failed', updatedAt: new Date() }).where(eq(schema.payments.id, payment.id));
      await writeAudit(tx as any, {
        actorId: adminId, action: 'payment.manually_verified_amount_mismatch',
        entityType: 'payment', entityId: payment.id,
        before: { status: 'pending', amount: payment.amount },
        after: { status: 'failed', verifiedAmount: body.verifiedAmount, reason: body.reason },
        ipAddress,
      });
      return { payment, amountMismatch: true };
    }

    if (payment.subscriptionId) {
      await transitionSubscription(tx, payment.subscriptionId, 'payment.settled');
    }
    await writeAudit(tx as any, {
      actorId: adminId, action: 'payment.manually_verified',
      entityType: 'payment', entityId: payment.id,
      before: { status: 'pending' },
      after: { status: 'completed', verifiedAmount: body.verifiedAmount, reason: body.reason },
      ipAddress,
    });
    return { payment, amountMismatch: false };
  });

  if (!result.payment) {
    return c.json({ error: { code: 'NOT_FOUND', message: 'No pending payment with that id', requestId: c.get('requestId') } }, 404);
  }
  if (result.amountMismatch) {
    return c.json({ error: { code: 'AMOUNT_MISMATCH', message: 'Verified amount does not match expected amount; payment marked failed', requestId: c.get('requestId') } }, 409);
  }
  return c.json({ data: result.payment });
});

adminRoutes.post('/refunds', async (c) => {

  const body = z.object({
    paymentId: z.string(),
    amount: z.string().regex(/^\d+(\.\d{1,2})?$/, 'amount must be a decimal ETB string'),
    reason: z.string().min(3).max(500),
  }).parse(await c.req.json());
  const adminId = c.get('session')!.userId;
  const ipAddress = clientIp(c) ?? null;
  try {
    await scheduleRefund(body.paymentId, Money.fromETBString(body.amount), body.reason);

    await db.insert(schema.outboxEvents).values({
      channel: 'audit',
      payload: { action: 'refund.scheduled', actorId: adminId, paymentId: body.paymentId, amount: body.amount, reason: body.reason, ipAddress },
    });
  } catch (err: any) {

    const status = err.httpStatus ?? 500;
    return c.json({ error: { code: err.code ?? 'INTERNAL', message: err.message ?? 'Refund scheduling failed', requestId: c.get('requestId') } }, status);
  }
  return c.body(null, 202);
});

const EXPORT_FIELD_DENYLIST: Record<string, string[]> = {
  users: ['passwordHash', 'twoFactorSecret', 'twoFactorEnabled', 'phone', 'email', 'name'],
  payments: ['prepayId', 'reference', 'refundRequestNo', 'riderId'],
  subscriptions: ['riderId', 'morningSlot', 'eveningSlot'],
  tickets: ['userId', 'subject', 'body'],
};

adminRoutes.get('/export/:resource', async (c) => {
  const resource = c.req.param('resource');
  const tableMap: Record<string, any> = { users: schema.users, payments: schema.payments, subscriptions: schema.subscriptions, tickets: schema.supportTickets };
  const table = tableMap[resource];
  if (!table) return c.json({ error: { code: 'BAD_REQUEST', message: 'Unknown export resource', requestId: c.get('requestId') } }, 400);
  const rawRows = await db.select().from(table).limit(10_000);
  const denylist = EXPORT_FIELD_DENYLIST[resource] ?? [];
  const rows = denylist.length ? rawRows.map((r: Record<string, unknown>) => {
    const copy = { ...r };
    for (const field of denylist) delete copy[field];
    return copy;
  }) : rawRows;
  const csv = toCsv(rows);

  const adminId = c.get('session')!.userId;
  const ipAddress = clientIp(c) ?? null;
  try {
    await db.insert(schema.outboxEvents).values({
      channel: 'audit',
      payload: { action: 'admin.csv_export', actorId: adminId, resource, rowCount: rows.length, ipAddress },
    });
  } catch (err) {
    c.get('logger')?.error({ err, resource, rowCount: rows.length }, 'admin.csv_export: audit insert failed — refusing to return CSV without audit trail');
    return c.json({ error: { code: 'INTERNAL', message: 'Export audit failed — refusing to return CSV without audit trail', requestId: c.get('requestId') } }, 500);
  }

  return new Response(csv, { headers: { 'Content-Type': 'text/csv', 'Content-Disposition': `attachment; filename="${resource}.csv"` } });
});

function toCsv(rows: Record<string, unknown>[]): string {
  if (!rows.length) return '';
  const headers = Object.keys(rows[0]!);

  const FORMULA_LEAD = /^[=+\-@\t\r]/;
  const escape = (v: unknown) => {
    let s = String(v ?? '');
    if (FORMULA_LEAD.test(s)) s = `'${s}`;
    return `"${s.replace(/"/g, '""')}"`;
  };
  return [headers.join(','), ...rows.map((r) => headers.map((h) => escape(r[h])).join(','))].join('\n');
}

import { createHash } from 'node:crypto';
import { desc, sql } from 'drizzle-orm';
import { db, schema } from '@addis/db';

const AUDIT_CHAIN_LOCK_KEY = 'addis_ride_audit_chain';

const SANITIZE_FIELDS = [
  'passwordHash', 'twoFactorSecret', 'twoFactorEnabled',
  'accessToken', 'refreshToken', 'devCode',
  'sessionToken', 'cookie',
];

function sanitize(value: unknown): unknown {
  if (value == null || typeof value !== 'object') return value;
  if (Array.isArray(value)) return value.map(sanitize);
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
    if (SANITIZE_FIELDS.some(f => k.toLowerCase().includes(f.toLowerCase()))) continue;
    out[k] = sanitize(v);
  }
  return out;
}

function normalizeForHash(value: unknown): unknown {
  if (value === undefined) return null;
  if (Array.isArray(value)) return value.map(normalizeForHash);
  if (value && typeof value === 'object') {
    const out: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
      out[k] = normalizeForHash(v);
    }
    return out;
  }
  return value;
}

export async function writeAudit(tx: any, entry: {
  actorId: string | null; action: string; entityType: string; entityId?: string;
  before?: unknown; after?: unknown; ipAddress?: string | undefined; userAgent?: string | undefined;
}) {

  await tx.execute(sql`select pg_advisory_xact_lock(hashtext(${AUDIT_CHAIN_LOCK_KEY}))`);

  const [last] = await tx.select().from(schema.auditLogs)
    .orderBy(desc(schema.auditLogs.createdAt), desc(schema.auditLogs.id))
    .limit(1);
  const prevHash = last?.hash ?? 'GENESIS';

  const sanitizedEntry = {
    actorId: entry.actorId ?? null,
    action: entry.action,
    entityType: entry.entityType,
    entityId: entry.entityId ?? null,
    before: sanitize(entry.before ?? null),
    after: sanitize(entry.after ?? null),
    ipAddress: entry.ipAddress ?? null,
    userAgent: entry.userAgent ?? null,
    prevHash,
  };
  const payload = JSON.stringify(normalizeForHash(sanitizedEntry));
  const hash = createHash('sha256').update(payload).digest('hex');
  const [row] = await tx.insert(schema.auditLogs).values({
    actorId: sanitizedEntry.actorId,
    action: sanitizedEntry.action,
    entityType: sanitizedEntry.entityType,
    entityId: sanitizedEntry.entityId,
    before: sanitizedEntry.before,
    after: sanitizedEntry.after,
    ipAddress: sanitizedEntry.ipAddress,
    userAgent: sanitizedEntry.userAgent,
    prevHash, hash,
  }).returning();
  return row;
}

export async function verifyAuditChain(limit?: number) {
  const BATCH_SIZE = 5_000;
  let prevHash = 'GENESIS';
  let lastSeenId: string | undefined;
  let verified = 0;

  while (true) {
    const batchLimit = limit ? Math.min(BATCH_SIZE, limit - verified) : BATCH_SIZE;
    if (batchLimit <= 0) break;

    const rows = await db.select().from(schema.auditLogs)
      .orderBy(schema.auditLogs.createdAt, schema.auditLogs.id)
      .where(lastSeenId
        ? sql`(created_at, id) > (
          SELECT created_at, id FROM audit_logs WHERE id = ${lastSeenId}
        )`
        : sql`true`
      )
      .limit(batchLimit);

    if (rows.length === 0) break;

    for (const row of rows) {
      const sanitized = {
        actorId: row.actorId,
        action: row.action,
        entityType: row.entityType,
        entityId: row.entityId ?? null,
        before: sanitize(row.before ?? null),
        after: sanitize(row.after ?? null),
        ipAddress: row.ipAddress ?? null,
        userAgent: row.userAgent ?? null,
        prevHash,
      };
      const expected = createHash('sha256').update(JSON.stringify(normalizeForHash(sanitized))).digest('hex');
      if (expected !== row.hash) {
        return { valid: false, brokenAt: row.id, verified };
      }
      prevHash = row.hash;
      lastSeenId = row.id;
      verified++;
    }

    if (rows.length < batchLimit) break;
  }

  return { valid: true, verified };
}

export async function anchorAuditChain() {
  const { s3 } = await import('../../infra/s3');
  const [last] = await db.select().from(schema.auditLogs)
    .orderBy(desc(schema.auditLogs.createdAt), desc(schema.auditLogs.id))
    .limit(1);
  const countRow = await db.select({ count: sql<number>`count(*)::int` }).from(schema.auditLogs);
  const count = countRow[0]?.count ?? 0;

  const tipHash = last?.hash ?? 'GENESIS';
  const anchorPayload = {
    tipHash,
    lastRowId: last?.id ?? null,
    lastRowCreatedAt: last?.createdAt ?? null,
    rowCount: count,
    anchoredAt: new Date().toISOString(),
  };

  const hourBucket = new Date().toISOString().slice(0, 13);
  const key = `audit-anchor/${hourBucket}.json`;
  await s3.putObject(key, Buffer.from(JSON.stringify(anchorPayload, null, 2), 'utf-8'), 'application/json');
  return { key, ...anchorPayload };
}

export async function verifyAuditChainWithAnchors() {
  const { s3 } = await import('../../infra/s3');

  const now = new Date();
  const candidates: string[] = [];
  for (let i = 0; i < 24; i++) {
    const d = new Date(now.getTime() - i * 3600_000);
    candidates.push(`audit-anchor/${d.toISOString().slice(0, 13)}.json`);
  }
  let anchor: { tipHash: string; lastRowId: string | null; anchoredAt: string } | null = null;
  for (const key of candidates) {
    const buf = await s3.getObject(key).catch(() => null);
    if (buf) {
      try { anchor = JSON.parse(buf.toString('utf-8')); break; } catch {  }
    }
  }
  if (!anchor) {
    return { valid: false, reason: 'no_anchor_found' as const, verified: 0 };
  }

  const chain = await verifyAuditChain();
  if (!chain.valid) return chain;

  const [currentTip] = await db.select().from(schema.auditLogs)
    .orderBy(desc(schema.auditLogs.createdAt), desc(schema.auditLogs.id))
    .limit(1);
  const currentTipHash = currentTip?.hash ?? 'GENESIS';

  if (currentTipHash === anchor.tipHash) {
    return { valid: true, verified: chain.verified, anchoredAt: anchor.anchoredAt };
  }

  if (anchor.lastRowId) {
    const [anchoredRow] = await db.select().from(schema.auditLogs)
      .where(sql`id = ${anchor.lastRowId}`).limit(1);
    if (!anchoredRow) {
      return { valid: false, reason: 'anchored_row_deleted' as const, verified: chain.verified };
    }
    if (anchoredRow.hash !== anchor.tipHash) {
      return { valid: false, reason: 'tip_divergence' as const, verified: chain.verified, anchoredAt: anchor.anchoredAt };
    }
  }
  return { valid: true, verified: chain.verified, anchoredAt: anchor.anchoredAt };
}

