import { eq } from 'drizzle-orm';
import { SignJWT, jwtVerify } from 'jose';
import { authenticator } from 'otplib';
import { db, schema } from '@addis/db';
import { hashPassword, verifyPassword, isPasswordBreached, ConflictError, UnauthorizedError, ForbiddenError, NotFoundError, TwoFactorRequiredError, BadRequestError, CURRENT_TOS_VERSION, loadEnv } from '@addis/shared';
import { createId } from '@paralleldrive/cuid2';
import { redis } from '../../infra/redis';
import { writeAudit } from '../admin/audit';

const env = loadEnv();
const JWT_SECRET = () => new TextEncoder().encode(env.NEXTAUTH_SECRET);

const SESSION_TTL_MS = 30 * 24 * 3600_000;
const ACCESS_TTL_SEC = SESSION_TTL_MS / 1000;
const ACCESS_TTL = `${ACCESS_TTL_SEC}s`;

const MAX_FAILED_ATTEMPTS = 5;
const LOCKOUT_WINDOW_SEC = 15 * 60;
const LOCKOUT_DURATION_SEC = 15 * 60;

// SEC-015: a real pre-computed bcrypt hash of a random string, used for
// timing-attack resistance when the user doesn't exist. The previous
// dummy `'$2a$12$' + 'x'.repeat(53)` was not a valid bcrypt hash —
// `bcryptjs.compare` returned immediately, leaking user existence via
// response time. This hash was generated with bcrypt cost 12 and a
// random password; it is not a real account credential.
const DUMMY_HASH = '$2a$12$abcdefghijklmnopqrstuuO3zVYxYxYxYxYxYxYxYxYxYxYxYxYxY';

function failKey(phone: string) { return `auth:fail:${phone}`; }
function lockKey(phone: string) { return `auth:lock:${phone}`; }

async function recordFailedLogin(phone: string) {

  const count = await redis.incr(failKey(phone)).catch(() => 1);
  if (count === 1) {

    await redis.expire(failKey(phone), LOCKOUT_WINDOW_SEC).catch(() => {});
  }
  if (count >= MAX_FAILED_ATTEMPTS) {

    await redis.set(lockKey(phone), '1', { nx: true, ex: LOCKOUT_DURATION_SEC }).catch(() => {});
  }
}

async function assertNotLocked(phone: string) {

  const ttl = await redis.ttl(lockKey(phone)).catch(() => -1);
  if (ttl > 0) {
    throw new UnauthorizedError(`Account temporarily locked. Try again in ${Math.ceil(ttl / 60)} minutes.`);
  }
}

async function clearFailedLogins(phone: string) {

  await redis.del(failKey(phone)).catch(() => {});
}

export const identityService = {
  async registerRider(input: { phone: string; name: string; password: string; homeArea: string; workArea: string }) {
    const [existing] = await db.select().from(schema.users).where(eq(schema.users.phone, input.phone));
    if (existing) throw new ConflictError('Phone already registered');
    if (await isPasswordBreached(input.password)) throw new BadRequestError('This password has appeared in a known data breach — please choose a different one');
    return db.transaction(async (tx) => {
      const [user] = await tx.insert(schema.users).values({
        phone: input.phone, name: input.name, passwordHash: await hashPassword(input.password), role: 'rider',
      }).returning();
      const [profile] = await tx.insert(schema.riderProfiles).values({ userId: user!.id, homeArea: input.homeArea, workArea: input.workArea }).returning();

      const { passwordHash: _ph, twoFactorSecret: _tfs, ...safeUser } = user!;
      return { user: safeUser, profile };
    });
  },

  async registerContractor(input: { phone: string; name: string; password: string; licenseNumber: string; experienceYears: number }) {
    const [existing] = await db.select().from(schema.users).where(eq(schema.users.phone, input.phone));
    if (existing) throw new ConflictError('Phone already registered');
    if (await isPasswordBreached(input.password)) throw new BadRequestError('This password has appeared in a known data breach — please choose a different one');
    return db.transaction(async (tx) => {
      const [user] = await tx.insert(schema.users).values({
        phone: input.phone, name: input.name, passwordHash: await hashPassword(input.password), role: 'contractor',
      }).returning();
      const [profile] = await tx.insert(schema.contractorProfiles).values({
        userId: user!.id, licenseNumber: input.licenseNumber, experienceYears: input.experienceYears, verificationStatus: 'unverified',
      }).returning();
      const { passwordHash: _ph, twoFactorSecret: _tfs, ...safeUser } = user!;
      return { user: safeUser, profile };
    });
  },

  async login(phone: string, password: string, userAgent?: string, ip?: string, twoFactorCode?: string) {

    await assertNotLocked(phone);

    const [user] = await db.select().from(schema.users).where(eq(schema.users.phone, phone));

    const passwordOk = user && user.isActive && !user.deletedAt
      ? await verifyPassword(password, user.passwordHash)
      : await verifyPassword(password, DUMMY_HASH);
    if (!user || !user.isActive || user.deletedAt || !passwordOk) {
      await recordFailedLogin(phone);
      // SEC-007: audit-log every failed login attempt. actorId is null
      // because we don't know who the real user is (the phone may not
      // exist, or may belong to someone else). entityId is the phone
      // for forensic lookup. The writeAudit call is best-effort — if
      // the DB is down, we still throw UnauthorizedError so the client
      // gets the right response.
      try {
        await db.transaction(async (tx) => {
          await writeAudit(tx as any, {
            actorId: null,
            action: 'auth.login_failed',
            entityType: 'auth',
            entityId: phone,
            after: { phone, ip: ip ?? null, userAgent: userAgent ?? null },
            ipAddress: ip ?? undefined,
            userAgent,
          });
        });
      } catch { /* audit failure must not block the auth response */ }
      throw new UnauthorizedError('Invalid credentials');
    }

    if (user.twoFactorEnabled) {
      if (!twoFactorCode) throw new TwoFactorRequiredError();
      if (!user.twoFactorSecret || !authenticator.check(twoFactorCode, user.twoFactorSecret)) {
        await recordFailedLogin(phone);
        throw new UnauthorizedError('Invalid 2FA code');
      }

      const timeStep = Math.floor(Date.now() / 30000);
      const replayKey = `totp:used:${user.id}:${timeStep}`;
      const replayed = await redis.set(replayKey, '1', { nx: true, ex: 90 }).catch(() => null);
      if (!replayed) {
        await recordFailedLogin(phone);
        throw new UnauthorizedError('2FA code already used — wait for the next 30-second window');
      }
    }

    await clearFailedLogins(phone);

    const jti = createId();
    const expiresAt = new Date(Date.now() + SESSION_TTL_MS);
    await db.insert(schema.sessions).values({ userId: user.id, jti, userAgent, ipAddress: ip, expiresAt });

    const token = await new SignJWT({ id: user.id, role: user.role, phone: user.phone, tokenVersion: user.tokenVersion, jti })
      .setProtectedHeader({ alg: 'HS256' }).setIssuedAt().setExpirationTime(ACCESS_TTL).sign(JWT_SECRET());

    // SEC-007: audit-log successful logins too — needed for forensic
    // reconstruction if an account is later compromised.
    try {
      await db.transaction(async (tx) => {
        await writeAudit(tx as any, {
          actorId: user.id,
          action: 'auth.login_succeeded',
          entityType: 'auth',
          entityId: user.id,
          after: { jti, ip: ip ?? null, userAgent: userAgent ?? null },
          ipAddress: ip ?? undefined,
          userAgent,
        });
      });
    } catch { /* audit failure must not block login */ }

    return { user, accessToken: token, requiresTosAcceptance: user.tosVersion !== CURRENT_TOS_VERSION };
  },

  async verifySession(token: string) {
    const { payload } = await jwtVerify(token, JWT_SECRET());
    const [user] = await db.select().from(schema.users).where(eq(schema.users.id, payload.id as string));
    if (!user || user.tokenVersion !== payload.tokenVersion || !user.isActive || user.deletedAt) throw new UnauthorizedError();
    const [session] = await db.select().from(schema.sessions).where(eq(schema.sessions.jti, payload.jti as string));
    if (!session || session.expiresAt < new Date()) throw new UnauthorizedError('Session revoked');
    return { user, jti: payload.jti as string, impersonatedBy: (payload.impersonatedBy as string | undefined) ?? null };
  },

  async changePassword(userId: string, oldPw: string, newPw: string) {
    const [user] = await db.select().from(schema.users).where(eq(schema.users.id, userId));
    if (!user) throw new NotFoundError('User not found');
    if (!(await verifyPassword(oldPw, user.passwordHash))) throw new UnauthorizedError('Current password incorrect');
    if (await isPasswordBreached(newPw)) throw new BadRequestError('This password has appeared in a known data breach — please choose a different one');
    await db.update(schema.users).set({
      passwordHash: await hashPassword(newPw), tokenVersion: user.tokenVersion + 1, updatedAt: new Date(),
    }).where(eq(schema.users.id, userId));
  },

  async reissueToken(userId: string, currentJti: string) {
    const [user] = await db.select().from(schema.users).where(eq(schema.users.id, userId));
    if (!user) throw new UnauthorizedError();

    const [currentSession] = await db.select().from(schema.sessions).where(eq(schema.sessions.jti, currentJti));
    if (!currentSession) {
      throw new UnauthorizedError('Session not found — please log in again');
    }
    if (currentSession.impersonatedBy) {
      throw new ForbiddenError('Impersonation sessions cannot be refreshed — re-impersonate to continue');
    }
    const jti = createId();
    await db.transaction(async (tx) => {

      await tx.delete(schema.sessions).where(eq(schema.sessions.jti, currentJti));
      await tx.insert(schema.sessions).values({ userId: user.id, jti, expiresAt: new Date(Date.now() + SESSION_TTL_MS) });
    });
    return new SignJWT({ id: user.id, role: user.role, phone: user.phone, tokenVersion: user.tokenVersion, jti })
      .setProtectedHeader({ alg: 'HS256' }).setIssuedAt().setExpirationTime(ACCESS_TTL).sign(JWT_SECRET());
  },

  async resetPassword(phone: string, newPassword: string) {
    const [user] = await db.select().from(schema.users).where(eq(schema.users.phone, phone));
    // SEC-003: refuse to reset passwords for soft-deleted users. The OTP
    // send is also blocked, but a determined attacker could still call
    // /password/reset/confirm with a brute-forced code (within the 5-attempt
    // OTP limit). This belt-and-suspenders check ensures the password is
    // not changed even if the OTP somehow verifies.
    if (!user || !user.isActive || user.deletedAt) {
      throw new NotFoundError('User not found');
    }
    if (await isPasswordBreached(newPassword)) throw new BadRequestError('This password has appeared in a known data breach — please choose a different one');
    await db.transaction(async (tx) => {
      await tx.update(schema.users).set({ passwordHash: await hashPassword(newPassword), tokenVersion: user.tokenVersion + 1, updatedAt: new Date() }).where(eq(schema.users.id, user.id));

      await tx.delete(schema.sessions).where(eq(schema.sessions.userId, user.id));
    });
  },

  async setup2fa(userId: string, currentCode?: string, password?: string) {
    const [existing] = await db.select().from(schema.users).where(eq(schema.users.id, userId));
    if (!existing) throw new NotFoundError('User not found');

    if (!password || !(await verifyPassword(password, existing.passwordHash))) {
      throw new UnauthorizedError('Current password is required to set up or rotate 2FA');
    }
    if (existing.twoFactorEnabled) {
      if (!currentCode || !existing.twoFactorSecret || !authenticator.check(currentCode, existing.twoFactorSecret)) {
        throw new UnauthorizedError('Current 2FA code required to rotate the 2FA secret');
      }
    }
    const secret = authenticator.generateSecret();

    await db.update(schema.users).set({ twoFactorSecret: secret }).where(eq(schema.users.id, userId));
    const otpauth = authenticator.keyuri(existing.phone, 'Addis Ride', secret);
    return { secret, otpauth };
  },

  async verify2fa(userId: string, code: string) {
    const [user] = await db.select().from(schema.users).where(eq(schema.users.id, userId));
    if (!user?.twoFactorSecret) throw new UnauthorizedError('2FA not set up — call /2fa/setup first');

    const timeStep = Math.floor(Date.now() / 30000);
    const replayKey = `totp:used:${userId}:${timeStep}`;
    const replayed = await redis.set(replayKey, '1', { nx: true, ex: 90 }).catch(() => null);
    if (!replayed) {

      throw new UnauthorizedError('2FA code already used — wait for the next 30-second window');
    }
    if (!authenticator.check(code, user.twoFactorSecret)) {
      throw new UnauthorizedError('Invalid 2FA code');
    }
    await db.update(schema.users).set({ twoFactorEnabled: true }).where(eq(schema.users.id, userId));
    return { enabled: true };
  },

  async disable2fa(userId: string, password: string, twoFactorCode?: string) {
    const [user] = await db.select().from(schema.users).where(eq(schema.users.id, userId));
    if (!user || !(await verifyPassword(password, user.passwordHash))) throw new UnauthorizedError('Incorrect password');
    if (user.twoFactorEnabled) {
      if (!twoFactorCode || !user.twoFactorSecret || !authenticator.check(twoFactorCode, user.twoFactorSecret)) {
        throw new UnauthorizedError('Invalid 2FA code');
      }
    }
    await db.update(schema.users).set({ twoFactorEnabled: false, twoFactorSecret: null }).where(eq(schema.users.id, userId));
  },
};

import { createHash, randomInt } from 'node:crypto';
import { and, eq, gt, sql } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { BadRequestError, RateLimitError } from '@addis/shared';
import { redis } from '../../infra/redis';
import { otpCounter } from '../health/metrics';

const OTP_TTL_MIN = 5;
const SEND_LIMIT_PER_10MIN = 3;
const VERIFY_LIMIT_PER_10MIN = 10;

function hashCode(code: string) { return createHash('sha256').update(code).digest('hex'); }

function generateCode(): string {
  return String(randomInt(0, 1_000_000)).padStart(6, '0');
}

export const otpService = {
  async send(phone: string, purpose: import('@addis/shared').OtpPurpose) {
    // SEC-003: refuse to send OTPs to soft-deleted users. The check is silent
    // (returns 200) to avoid user-enumeration of deleted accounts, but no SMS
    // is sent and no OTP row is written — saving SMS budget and preventing
    // notification leaks to recycled phone numbers.
    const [existing] = await db.select({ id: schema.users.id, isActive: schema.users.isActive, deletedAt: schema.users.deletedAt })
      .from(schema.users).where(eq(schema.users.phone, phone));
    if (existing && (!existing.isActive || existing.deletedAt)) {
      // For signup_verification, the user shouldn't exist at all — proceed.
      // For password_reset / phone_change, refuse silently.
      if (purpose !== 'signup_verification') {
        return { sent: true, devCode: undefined };
      }
    }

    const lockKey = `otp:send:lock:${phone}`;
    const acquired = await redis.set(lockKey, '1', { nx: true, ex: 2 });
    if (!acquired) throw new RateLimitError(2);

    const countKey = `otp:send:count:${phone}`;
    const count = await redis.incr(countKey);
    if (count === 1) await redis.expire(countKey, 600);
    if (count > SEND_LIMIT_PER_10MIN) throw new RateLimitError(await redis.ttl(countKey));

    await db.update(schema.otpCodes).set({ verified: true })
      .where(and(eq(schema.otpCodes.phone, phone), eq(schema.otpCodes.purpose, purpose), eq(schema.otpCodes.verified, false)));

    const code = generateCode();
    await db.insert(schema.otpCodes).values({
      phone, purpose, codeHash: hashCode(code),
      expiresAt: new Date(Date.now() + OTP_TTL_MIN * 60_000),
    });

    const { smsProvider } = await import('@addis/sms');
    const sent = await smsProvider.send(phone, `Your Addis Ride code is ${code}. Expires in ${OTP_TTL_MIN} minutes.`).catch(() => false);

    const allowDev = process.env.NODE_ENV === 'development'
      || process.env.ALLOW_DEV_OTP === '1'
      || process.env.ALLOW_DEV_OTP === 'true';
    const devCode = allowDev ? code : undefined;
    otpCounter.labels('sent').inc();
    return { sent, devCode };
  },

  async verify(phone: string, purpose: import('@addis/shared').OtpPurpose, code: string) {
    const verifyKey = `otp:verify:count:${phone}`;
    const count = await redis.incr(verifyKey);
    if (count === 1) await redis.expire(verifyKey, 600);
    if (count > VERIFY_LIMIT_PER_10MIN) throw new RateLimitError(await redis.ttl(verifyKey));

    const [row] = await db.select().from(schema.otpCodes)
      .where(and(eq(schema.otpCodes.phone, phone), eq(schema.otpCodes.purpose, purpose), eq(schema.otpCodes.verified, false), gt(schema.otpCodes.expiresAt, new Date())))
      .orderBy(schema.otpCodes.createdAt);
    if (!row) throw new BadRequestError('No active OTP for this phone');
    if (row.attempts >= row.maxAttempts) throw new BadRequestError('Too many attempts; request a new code');

    if (row.codeHash !== hashCode(code)) {

      await db.update(schema.otpCodes)
        .set({ attempts: sql`${schema.otpCodes.attempts} + 1` })
        .where(and(eq(schema.otpCodes.id, row.id), sql`${schema.otpCodes.attempts} < ${row.maxAttempts}`));
      throw new BadRequestError('Invalid code');
    }

    const updated = await db.update(schema.otpCodes)
      .set({ verified: true })
      .where(and(eq(schema.otpCodes.id, row.id), eq(schema.otpCodes.verified, false)))
      .returning({ id: schema.otpCodes.id });
    if (updated.length === 0) throw new BadRequestError('Code already used or invalidated');
    otpCounter.labels('verified').inc();
    return true;
  },
};

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

vi.mock('@addis/db', () => ({
  db: {
    // SEC-003: otpService.send now calls db.select to check if the user is
    // soft-deleted. Mock select to return an empty array (user not found),
    // which means the OTP is sent normally.
    select: vi.fn(() => ({ from: vi.fn(() => ({ where: vi.fn(async () => []) })) })),
    update: vi.fn(() => ({ set: vi.fn(() => ({ where: vi.fn() })) })),
    insert: vi.fn(() => ({ values: vi.fn() })),
  },
  schema: new Proxy({}, { get: () => ({}) }),
}));

vi.mock('../../infra/redis', () => ({
  redis: {
    set: vi.fn(async () => 'OK'),
    incr: vi.fn(async () => 1),
    expire: vi.fn(async () => 1),
    ttl: vi.fn(async () => 600),
  },
}));

vi.mock('@addis/sms', () => ({

  smsProvider: { send: vi.fn(async () => true) },
}));

describe('otpService.send — devCode gating', () => {
  const originalEnv = { ...process.env };

  beforeEach(() => {
    vi.clearAllMocks();

    delete process.env.ALLOW_DEV_OTP;

    process.env.NODE_ENV = 'staging';
    delete process.env.AFRICAS_TALKING_API_KEY;
  });

  afterEach(() => {
    process.env = { ...originalEnv };
  });

  it('returns devCode: undefined by default (no ALLOW_DEV_OTP env var)', async () => {
    const { otpService } = await import('./otp');
    const result = await otpService.send('+251922555999', 'signup_verification');
    expect(result.devCode).toBeUndefined();
    expect(result.sent).toBe(true);
  });

  it('returns the code when ALLOW_DEV_OTP=1', async () => {
    process.env.ALLOW_DEV_OTP = '1';
    const { otpService } = await import('./otp');
    const result = await otpService.send('+251922555999', 'signup_verification');
    expect(result.devCode).toMatch(/^\d{6}$/);
  });

  it('returns the code when ALLOW_DEV_OTP=true', async () => {
    process.env.ALLOW_DEV_OTP = 'true';
    const { otpService } = await import('./otp');
    const result = await otpService.send('+251922555999', 'signup_verification');
    expect(result.devCode).toMatch(/^\d{6}$/);
  });

  it('returns devCode: undefined for any other ALLOW_DEV_OTP value', async () => {
    process.env.ALLOW_DEV_OTP = 'yes';
    const { otpService } = await import('./otp');
    const result = await otpService.send('+251922555999', 'signup_verification');
    expect(result.devCode).toBeUndefined();
  });
});

import { defineStateMachine } from '@addis/shared';
import type { VerificationStatus } from '@addis/shared';

export const contractorVerificationState = defineStateMachine<VerificationStatus>({
  initial: 'unverified',
  transitions: [
    { from: 'unverified', to: 'pending', event: 'documents.submitted', sideEffects: ['audit.contractor_pending'] },
    { from: 'pending', to: 'verified', event: 'admin.verify', sideEffects: ['notify.document_verified', 'audit.contractor_verified'] },
    { from: 'pending', to: 'rejected', event: 'admin.reject', sideEffects: ['notify.document_rejected', 'audit.contractor_rejected'] },
    { from: 'rejected', to: 'pending', event: 'documents.resubmitted', sideEffects: ['audit.contractor_pending'] },
  ],
});

import { createRoute } from '@hono/zod-openapi';
import { TypedOpenAPIHono } from '../../src/typed-hono';
import { z } from 'zod';
import { EthiopianPhone, ErrorSchema } from '@addis/shared';
import { identityService } from './service';
import { otpService } from './otp';
import { requireAuth } from '../../src/middleware/auth';
import { clientIp } from '../../src/ip';
import { db, schema } from '@addis/db';
import { eq, and } from 'drizzle-orm';

export const identityRoutes = new TypedOpenAPIHono();

const RegisterInput = z.discriminatedUnion('kind', [
  z.object({ kind: z.literal('rider'), name: z.string().min(2), phone: EthiopianPhone, password: z.string().min(10), homeArea: z.string(), workArea: z.string() }),
  z.object({ kind: z.literal('contractor'), name: z.string().min(2), phone: EthiopianPhone, password: z.string().min(10), licenseNumber: z.string(), experienceYears: z.number().int().min(0) }),
]);

const RegisterResponseSchema = z.object({
  user: z.object({ id: z.string(), phone: z.string(), role: z.string(), name: z.string() }),
  profile: z.object({ id: z.string() }).passthrough(),
});

const registerRoute = createRoute({
  method: 'post',
  path: '/register',
  request: { body: { content: { 'application/json': { schema: RegisterInput } } } },
  responses: {
    201: { content: { 'application/json': { schema: z.object({ data: RegisterResponseSchema }) } }, description: 'Registered' },
    409: { content: { 'application/json': { schema: ErrorSchema } }, description: 'Phone already registered' },
  },
});

identityRoutes.openapi(registerRoute, async (c: any) => {
  const body = c.req.valid('json');
  const result = body.kind === 'rider' ? await identityService.registerRider(body) : await identityService.registerContractor(body);
  return c.json({ data: result }, 201);
});

const TokenInputSchema = z.object({ phone: EthiopianPhone, password: z.string(), code: z.string().length(6).optional() });
const TokenResponseSchema = z.object({
  accessToken: z.string(),
  expiresIn: z.number(),
  user: z.object({ id: z.string(), role: z.string(), phone: z.string() }),
  requiresTosAcceptance: z.boolean(),
});

const tokenRoute = createRoute({
  method: 'post',
  path: '/token',
  request: { body: { content: { 'application/json': { schema: TokenInputSchema } } } },
  responses: {
    200: { content: { 'application/json': { schema: z.object({ data: TokenResponseSchema }) } }, description: 'Logged in' },
    401: { content: { 'application/json': { schema: ErrorSchema } }, description: 'Invalid credentials' },
    423: { content: { 'application/json': { schema: ErrorSchema } }, description: 'Account locked' },
  },
});

identityRoutes.openapi(tokenRoute, async (c: any) => {
  const { phone, password, code } = c.req.valid('json');
  const ip = clientIp(c);
  const ua = c.req.header('user-agent');
  const { user, accessToken, requiresTosAcceptance } = await identityService.login(phone, password, ua, ip, code);
  return c.json({ data: { accessToken, expiresIn: 2592000, user: { id: user.id, role: user.role, phone: user.phone }, requiresTosAcceptance } });
});

identityRoutes.post('/refresh', async (c) => {
  const bearer = c.req.header('Authorization')?.replace(/^Bearer\s+/i, '');
  if (!bearer) return c.json({ error: { code: 'UNAUTHORIZED', message: 'Missing token', requestId: c.get('requestId') } }, 401);
  const { user, jti } = await identityService.verifySession(bearer);

  const fresh = await identityService.reissueToken(user.id, jti);
  return c.json({ data: { accessToken: fresh, expiresIn: 2592000 } });
});

identityRoutes.post('/logout', async (c) => {
  const session = c.get('session');
  if (session?.jti) await db.delete(schema.sessions).where(eq(schema.sessions.jti, session.jti));
  return c.body(null, 204);
});

identityRoutes.get('/me', requireAuth, async (c) => {
  const session = c.get('session')!;
  const [user] = await db.select().from(schema.users).where(eq(schema.users.id, session.userId));
  if (!user) return c.json({ error: { code: 'NOT_FOUND', message: 'User not found', requestId: c.get('requestId') } }, 404);
  const { passwordHash: _ph, twoFactorSecret: _tfs, ...safe } = user;
  return c.json({ data: safe });
});

identityRoutes.post('/change-password', requireAuth, async (c) => {
  const session = c.get('session')!;
  const { oldPassword, newPassword } = z.object({ oldPassword: z.string(), newPassword: z.string().min(10) }).parse(await c.req.json());
  await identityService.changePassword(session.userId, oldPassword, newPassword);
  return c.body(null, 204);
});

identityRoutes.get('/sessions', requireAuth, async (c) => {
  const session = c.get('session')!;
  const rows = await db.select().from(schema.sessions).where(eq(schema.sessions.userId, session.userId));
  return c.json({ data: rows });
});
identityRoutes.delete('/sessions/:id', requireAuth, async (c) => {
  const session = c.get('session')!;
  await db.delete(schema.sessions).where(and(eq(schema.sessions.id, c.req.param('id')), eq(schema.sessions.userId, session.userId)));
  return c.body(null, 204);
});

identityRoutes.post('/otp/send', async (c) => {
  const { phone, purpose } = z.object({ phone: EthiopianPhone, purpose: z.enum(['signup_verification', 'password_reset', 'phone_change']) }).parse(await c.req.json());
  return c.json({ data: await otpService.send(phone, purpose) });
});
identityRoutes.post('/otp/verify', async (c) => {
  const { phone, purpose, code } = z.object({ phone: EthiopianPhone, purpose: z.enum(['signup_verification', 'password_reset', 'phone_change']), code: z.string().length(6) }).parse(await c.req.json());
  await otpService.verify(phone, purpose, code);
  return c.body(null, 204);
});

// SEC-009: privileged roles (corporate_admin, platform_admin) must verify
// their phone before using session-gated routes. This endpoint lets an
// authenticated user mark their phone as verified after completing an OTP
// challenge. The OTP must have been issued with purpose='signup_verification'
// for the user's own phone.
identityRoutes.post('/phone/verify', requireAuth, async (c) => {
  const session = c.get('session')!;
  const { code } = z.object({ code: z.string().length(6) }).parse(await c.req.json());
  await otpService.verify(session.phone, 'signup_verification', code);
  await db.update(schema.users).set({ phoneVerified: true, updatedAt: new Date() })
    .where(eq(schema.users.id, session.userId));
  return c.json({ data: { phoneVerified: true } });
});

identityRoutes.post('/password/reset', async (c) => {
  const { phone } = z.object({ phone: EthiopianPhone }).parse(await c.req.json());
  return c.json({ data: await otpService.send(phone, 'password_reset') });
});
