import { TypedOpenAPIHono } from '../../src/typed-hono';
import { z } from 'zod';
import { requireRole } from '../../src/middleware/auth';
import { documentService } from './documents';
import { BadRequestError, NotFoundError } from '@addis/shared';
import { db, schema } from '@addis/db';
import { eq } from 'drizzle-orm';

export const documentRoutes = new TypedOpenAPIHono();

const DocType = z.enum(['registration', 'insurance', 'inspection']);

async function contractorIdForUser(userId: string) {
  const [p] = await db.select().from(schema.contractorProfiles).where(eq(schema.contractorProfiles.userId, userId));
  if (!p) throw new NotFoundError('Contractor profile not found');
  return p.id;
}

documentRoutes.get('/documents', requireRole('contractor'), async (c) => {
  const contractorId = await contractorIdForUser(c.get('session')!.userId);
  return c.json({ data: await documentService.list(contractorId) });
});

documentRoutes.post('/documents', requireRole('contractor'), async (c) => {
  const contractorId = await contractorIdForUser(c.get('session')!.userId);
  const form = await c.req.formData();
  const file = form.get('file') as File;
  if (!file) throw new BadRequestError('Missing file');

  const MAX_SIZE_BYTES = 10 * 1024 * 1024;
  if (file.size > MAX_SIZE_BYTES) {
    throw new BadRequestError('File exceeds 10MB limit');
  }
  const type = DocType.parse(form.get('type'));
  const buffer = Buffer.from(await file.arrayBuffer());
  const doc = await documentService.upload(contractorId, { type, filename: file.name, buffer });
  return c.json({ data: doc }, 201);
});

documentRoutes.get('/documents/:id', requireRole('contractor', 'platform_admin'), async (c) => {
  const session = c.get('session')!;

  const requesterContractorId = session.role === 'platform_admin' ? null : await contractorIdForUser(session.userId);
  const url = await documentService.signedDownloadUrl(c.req.param('id'), requesterContractorId);
  return c.json({ data: { url } });
});

documentRoutes.delete('/documents/:id', requireRole('contractor', 'platform_admin'), async (c) => {
  const session = c.get('session')!;
  const requesterContractorId = session.role === 'platform_admin' ? null : await contractorIdForUser(session.userId);
  await documentService.remove(requesterContractorId, c.req.param('id'));
  return c.body(null, 204);
});

import { fileTypeFromBuffer } from 'file-type';
import { createHash } from 'node:crypto';
import { eq, and } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { BadRequestError, NotFoundError, ConflictError } from '@addis/shared';
import { s3 } from '../../infra/s3';
import { contractorVerificationState } from './contractor-state';

const ALLOWED_MIME = new Set(['application/pdf', 'image/jpeg', 'image/png']);
const MAX_SIZE_BYTES = 10 * 1024 * 1024;
const DOC_TYPES = ['registration', 'insurance', 'inspection'] as const;

export const documentService = {
  async upload(contractorId: string, input: { type: (typeof DOC_TYPES)[number]; filename: string; buffer: Buffer }) {
    if (input.buffer.byteLength > MAX_SIZE_BYTES) throw new BadRequestError('File exceeds 10MB limit');

    const sniffed = await fileTypeFromBuffer(input.buffer);
    const mimeType = sniffed?.mime ?? 'application/octet-stream';
    if (!ALLOWED_MIME.has(mimeType)) throw new BadRequestError('Only PDF, JPEG, PNG allowed');

    const checksum = createHash('sha256').update(input.buffer).digest('hex');

    const [dup] = await db.select().from(schema.contractorDocuments)
      .where(and(eq(schema.contractorDocuments.contractorId, contractorId), eq(schema.contractorDocuments.checksumSha256, checksum)));
    if (dup) return dup;

    const storageKey = `contractors/${contractorId}/${input.type}/${checksum}`;
    await s3.putObject(storageKey, input.buffer, mimeType);

    const [doc] = await db.transaction(async (tx) => {
      const inserted = await tx.insert(schema.contractorDocuments).values({
        contractorId, type: input.type, originalFilename: input.filename,
        storageKey, mimeType, sizeBytes: input.buffer.byteLength, checksumSha256: checksum,
      }).returning();
      await tx.insert(schema.outboxEvents).values({ channel: 'webhook', payload: { kind: 'clamav_scan', storageKey } });

      const [profile] = await tx.select().from(schema.contractorProfiles).where(eq(schema.contractorProfiles.id, contractorId));
      if (profile?.verificationStatus === 'unverified') {
        const t = contractorVerificationState.resolve('unverified', 'documents.submitted');
        await tx.update(schema.contractorProfiles).set({ verificationStatus: t.to, updatedAt: new Date() }).where(eq(schema.contractorProfiles.id, contractorId));
      } else if (profile?.verificationStatus === 'rejected') {
        const t = contractorVerificationState.resolve('rejected', 'documents.resubmitted');
        await tx.update(schema.contractorProfiles).set({ verificationStatus: t.to, verificationReason: null, updatedAt: new Date() }).where(eq(schema.contractorProfiles.id, contractorId));
      }
      return inserted;
    });
    return doc;
  },

  async list(contractorId: string) {
    return db.select().from(schema.contractorDocuments).where(eq(schema.contractorDocuments.contractorId, contractorId));
  },

  async remove(requesterContractorId: string | null, documentId: string) {
    const [doc] = await db.select().from(schema.contractorDocuments).where(eq(schema.contractorDocuments.id, documentId));
    if (!doc) throw new NotFoundError('Document not found');
    if (requesterContractorId !== null && doc.contractorId !== requesterContractorId) throw new NotFoundError('Document not found');
    await db.delete(schema.contractorDocuments).where(eq(schema.contractorDocuments.id, documentId));
    await s3.deleteObject(doc.storageKey);
  },

  async signedDownloadUrl(documentId: string, requesterContractorId: string | null) {
    const [doc] = await db.select().from(schema.contractorDocuments).where(eq(schema.contractorDocuments.id, documentId));
    if (!doc) throw new NotFoundError('Document not found');
    if (requesterContractorId !== null && doc.contractorId !== requesterContractorId) {
      throw new NotFoundError('Document not found');
    }
    return s3.presignGet(doc.storageKey, 15 * 60);
  },

  async verify(adminId: string, contractorId: string) {
    return db.transaction(async (tx) => {
      const [profile] = await tx.select().from(schema.contractorProfiles).where(eq(schema.contractorProfiles.id, contractorId));
      if (!profile) throw new NotFoundError('Contractor not found');
      if (profile.verificationStatus !== 'pending') throw new ConflictError('Only pending contractors can be verified');

      const docs = await tx.select().from(schema.contractorDocuments)
        .where(eq(schema.contractorDocuments.contractorId, contractorId));
      const presentTypes = new Set(docs.map(d => d.type));
      const missing = DOC_TYPES.filter(t => !presentTypes.has(t));
      if (missing.length > 0) {
        throw new ConflictError(`Cannot verify: missing document types: ${missing.join(', ')}`);
      }

      const uncleared = docs.filter(d => d.scanStatus !== 'clean');
      if (uncleared.length > 0) {
        throw new ConflictError('Cannot verify: one or more documents are pending or failed malware scan');
      }

      const t = contractorVerificationState.resolve('pending', 'admin.verify');
      await tx.update(schema.contractorProfiles).set({
        verificationStatus: t.to, verifiedById: adminId, verifiedAt: new Date(), updatedAt: new Date(),
      }).where(eq(schema.contractorProfiles.id, contractorId));
      await tx.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'document_verified', userId: profile.userId } });
      return t;
    });
  },

  async reject(adminId: string, contractorId: string, reason: string) {
    return db.transaction(async (tx) => {
      const [profile] = await tx.select().from(schema.contractorProfiles).where(eq(schema.contractorProfiles.id, contractorId));
      if (!profile) throw new NotFoundError('Contractor not found');
      if (profile.verificationStatus !== 'pending') throw new ConflictError('Only pending contractors can be rejected');
      const t = contractorVerificationState.resolve('pending', 'admin.reject');
      await tx.update(schema.contractorProfiles).set({
        verificationStatus: t.to, verificationReason: reason, verifiedById: adminId, verifiedAt: new Date(), updatedAt: new Date(),
      }).where(eq(schema.contractorProfiles.id, contractorId));
      await tx.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'document_rejected', userId: profile.userId, reason } });
      return t;
    });
  },
};

import { and, eq, sql, inArray } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { Money, BadRequestError, NotFoundError } from '@addis/shared';
import { getPaymentProvider } from '@addis/payments';
import { transitionSubscription } from '../subscription/state';
import { createId } from '@paralleldrive/cuid2';
import { paymentCounter, refundCounter } from '../health/metrics';

export async function settlePayment(reference: string, reportedAmount?: Money): Promise<boolean> {
  return db.transaction(async (tx) => {
    const updated = await tx.update(schema.payments)
      .set({ status: 'completed', updatedAt: new Date() })
      .where(and(eq(schema.payments.reference, reference), eq(schema.payments.status, 'pending')))
      .returning();
    if (updated.length === 0) return false;
    const p = updated[0]!;

    if (reportedAmount) {
      const expected = Money.fromDecimal(p.amount);
      if (!expected.eq(reportedAmount)) {
        await tx.update(schema.payments).set({ status: 'failed', updatedAt: new Date() }).where(eq(schema.payments.id, p.id));
        await tx.insert(schema.outboxEvents).values({
          channel: 'audit',
          payload: { action: 'payment.amount_mismatch', entityId: p.id, expectedAmount: p.amount, reportedAmount: reportedAmount.toString() },
        });
        return false;
      }
    } else {

      await tx.insert(schema.outboxEvents).values({
        channel: 'audit',
        payload: { action: 'payment.settled_without_amount_verification', entityId: p.id, reference },
      });
    }

    if (p.subscriptionId) {
      await transitionSubscription(tx, p.subscriptionId, 'payment.settled');
    }
    if (p.seatClaimId) {
      await tx.update(schema.seatClaims).set({ status: 'confirmed', updatedAt: new Date() }).where(eq(schema.seatClaims.id, p.seatClaimId));
    }

    await tx.insert(schema.outboxEvents).values([
      { channel: 'notification', payload: { type: 'payment_received', userId: p.riderId, amount: p.amount } },
      { channel: 'audit', payload: { action: 'payment.settled', entityId: p.id } },
    ]);

    paymentCounter.labels('completed', p.method).inc();
    return true;
  });
}

export async function failPayment(reference: string, reasonRaw: unknown): Promise<boolean> {
  return db.transaction(async (tx) => {
    const updated = await tx.update(schema.payments)
      .set({ status: 'failed', updatedAt: new Date() })
      .where(and(eq(schema.payments.reference, reference), eq(schema.payments.status, 'pending')))
      .returning();
    if (updated.length === 0) return false;
    const p = updated[0]!;
    if (p.subscriptionId) await transitionSubscription(tx, p.subscriptionId, 'payment.failed');
    if (p.seatClaimId) {

      const [claim] = await tx.update(schema.seatClaims).set({ status: 'refunded', updatedAt: new Date() })
        .where(eq(schema.seatClaims.id, p.seatClaimId)).returning();
      if (claim) await tx.update(schema.seatReleases).set({ status: 'open', updatedAt: new Date() }).where(eq(schema.seatReleases.id, claim.seatReleaseId));
    }
    await tx.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'payment_failed', userId: p.riderId, raw: reasonRaw } });
    paymentCounter.labels('failed', p.method).inc();
    return true;
  });
}

// PAY-003: scheduleRefund now opens its own transaction with a row lock on the
// payment when called without a tx, preventing concurrent refund requests from
// both passing the "would exceed" check and over-refunding the customer. The
// lock is acquired with `for('update')` inside the transaction; the existing
// `tx` parameter is preserved for callers that already hold a transaction
// (e.g. subscription.cancel) — in that case the caller is responsible for
// having acquired the lock.
export async function scheduleRefund(paymentId: string, amount: Money, reason: string, tx: import('@addis/db').DbOrTx = db) {
  // If the caller passed the default `db`, wrap in a transaction + row lock.
  // If they passed a real tx, assume they've already acquired the lock.
  const run = async (txOrDb: import('@addis/db').DbOrTx) => {
    const [payment] = await (txOrDb as any).select().from(schema.payments).where(eq(schema.payments.id, paymentId)).for('update');
    if (!payment) throw new NotFoundError(`Payment ${paymentId} not found`);
    if (payment.status !== 'completed') throw new BadRequestError('Only completed payments can be refunded');
    if (!amount.isPositive()) throw new BadRequestError('Refund amount must be positive');

    const originalAmount = Money.fromDecimal(payment.amount);
    const alreadyRefunded = payment.refundAmount ? Money.fromDecimal(payment.refundAmount) : Money.ZERO;
    const totalAfterRefund = alreadyRefunded.add(amount);
    if (totalAfterRefund.gt(originalAmount)) {
      throw new BadRequestError(
        `Refund of ${amount.toString()} would exceed payment amount. ` +
        `Original: ${originalAmount.toString()}, already refunded: ${alreadyRefunded.toString()}.`
      );
    }

    const refundRequestNo = `RF${createId()}`;
    await (txOrDb as any).insert(schema.refundRetries).values({
      paymentId, merchOrderId: payment.reference, refundRequestNo, amount: amount.toString(), reason,
    });
  };

  // Detect whether `tx` is a transaction (has `rollback`) or the top-level db.
  if (tx === db || typeof (tx as any).rollback !== 'function') {
    return db.transaction(async (innerTx) => run(innerTx));
  }
  return run(tx);
}

const BACKOFF_MIN = [15, 30, 60, 120, 240];

// PAY-002: rewrite processRefundRetries to use the typed drizzle query builder
// instead of raw SQL. The previous raw-SQL `RETURNING *` returned rows with
// snake_case column names (`payment_id`, `attempts`, etc.) — but the loop
// accessed `retry.paymentId`, `retry.attempts`, etc. (camelCase), which were
// all `undefined`. Every refund silently failed with a TypeError, ending up
// in permanent_failure. The integration test missed this because it mocks
// @addis/db entirely.
export async function processRefundRetries(limit = 50) {
  // Reset stale 'processing' rows back to 'pending' (worker crashed mid-flight).
  await db.update(schema.refundRetries)
    .set({ status: 'pending', updatedAt: new Date() })
    .where(and(eq(schema.refundRetries.status, 'processing'), sql`${schema.refundRetries.updatedAt} < now() - interval '15 minutes'`));

  // Claim a batch using FOR UPDATE SKIP LOCKED. Use the query builder so we
  // get typed camelCase rows.
  const claimed = await db.transaction(async (tx) => {
    const rows = await tx.select().from(schema.refundRetries)
      .where(and(eq(schema.refundRetries.status, 'pending'), sql`${schema.refundRetries.nextAttemptAt} <= now()`))
      .orderBy(schema.refundRetries.nextAttemptAt)
      .limit(limit)
      .for('update', { skipLocked: true });
    if (rows.length === 0) return [];
    await tx.update(schema.refundRetries)
      .set({ status: 'processing', updatedAt: new Date() })
      .where(inArray(schema.refundRetries.id, rows.map(r => r.id)));
    return rows;
  });

  let processed = 0;

  for (const retry of claimed) {
    const [payment] = await db.select().from(schema.payments).where(eq(schema.payments.id, retry.paymentId));
    if (!payment) continue;
    const provider = getPaymentProvider(payment.method);

    let result;
    try {
      result = await provider.refund({
        merchOrderId: retry.merchOrderId, refundRequestNo: retry.refundRequestNo,
        amount: Money.fromDecimal(retry.amount), reason: retry.reason,
      });
    } catch (err) {
      result = { status: 'failed' as const, error: (err as Error).message, permanent: false };
    }

    await db.transaction(async (tx) => {
      if (result.status === 'succeeded') {

        const updatedRetry = await tx.update(schema.refundRetries)
          .set({ status: 'succeeded', updatedAt: new Date() })
          .where(and(
            eq(schema.refundRetries.id, retry.id),
            inArray(schema.refundRetries.status, ['pending', 'processing']),
          ))
          .returning();
        if (updatedRetry.length === 0) return;

        const [freshPayment] = await tx.select().from(schema.payments)
          .where(eq(schema.payments.id, payment.id)).for('update');
        if (!freshPayment) return;
        const currentRefundAmount = freshPayment.refundAmount ? Money.fromDecimal(freshPayment.refundAmount) : Money.ZERO;
        const newRefundAmount = currentRefundAmount.add(Money.fromDecimal(retry.amount));
        const allRefunded = newRefundAmount.eq(Money.fromDecimal(freshPayment.amount));
        await tx.update(schema.payments).set({
          status: allRefunded ? 'refunded' : 'partially_refunded',
          refundAmount: newRefundAmount.toString(),
          refundedAt: new Date(), updatedAt: new Date(),
        }).where(eq(schema.payments.id, freshPayment.id));

        await tx.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'refund_completed', userId: freshPayment.riderId } });
        refundCounter.labels('succeeded').inc();
      } else {
        const attempts = retry.attempts + 1;
        if (result.status === 'failed' && result.permanent) {
          await tx.update(schema.refundRetries).set({ status: 'permanent_failure', attempts, lastError: result.error, updatedAt: new Date() }).where(eq(schema.refundRetries.id, retry.id));
          await tx.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'refund_failed', userId: payment.riderId } });
          refundCounter.labels('permanent_failure').inc();
        } else if (attempts >= retry.maxAttempts) {
          await tx.update(schema.refundRetries).set({ status: 'permanent_failure', attempts, updatedAt: new Date() }).where(eq(schema.refundRetries.id, retry.id));
          await tx.insert(schema.outboxEvents).values({ channel: 'notification', payload: { type: 'refund_failed', userId: payment.riderId } });
          refundCounter.labels('permanent_failure').inc();
        } else {
          const backoffMin = BACKOFF_MIN[Math.min(attempts - 1, BACKOFF_MIN.length - 1)]!;
          await tx.update(schema.refundRetries).set({
            attempts, nextAttemptAt: new Date(Date.now() + backoffMin * 60_000),
            lastError: result.status === 'failed' ? result.error : null, updatedAt: new Date(),
          }).where(eq(schema.refundRetries.id, retry.id));
        }
      }
    });
    processed++;
  }
  return { processed };
}

import { describe, it, expect, beforeAll, afterAll, vi } from 'vitest';
import { PostgreSqlContainer, StartedPostgreSqlContainer } from '@testcontainers/postgresql';
import { migrate } from 'drizzle-orm/postgres-js/migrator';
import postgres from 'postgres';
import { drizzle } from 'drizzle-orm/postgres-js';
import { eq, and, desc } from 'drizzle-orm';
import { createId } from '@paralleldrive/cuid2';
import * as schema from '@addis/db/schema';
import { Money } from '@addis/shared';

let container: StartedPostgreSqlContainer;
let db: ReturnType<typeof drizzle>;

let settlePayment: typeof import('./service').settlePayment;
let failPayment: typeof import('./service').failPayment;
let scheduleRefund: typeof import('./service').scheduleRefund;
let processRefundRetries: typeof import('./service').processRefundRetries;
let marketplaceService: typeof import('../marketplace/service').marketplaceService;
let transitionSubscription: typeof import('../subscription/state').transitionSubscription;

beforeAll(async () => {
  container = await new PostgreSqlContainer('postgres:16').start();
  const client = postgres(container.getConnectionUri());
  db = drizzle(client, { schema });

  await migrate(db, { migrationsFolder: '../../../packages/db/migrations' });

  vi.doMock('@addis/db', () => ({ db, schema, Db: undefined as any, DbOrTx: undefined as any }));

  vi.doMock('@addis/payments', () => ({
    getPaymentProvider: () => ({
      refund: vi.fn().mockResolvedValue({ status: 'succeeded' as const }),
      verifyPayment: vi.fn().mockResolvedValue({
        status: 'completed' as const,
        amount: Money.fromDecimal('500.00'),
      }),
      createCheckout: vi.fn().mockResolvedValue({
        status: 'checkout' as const,
        checkoutUrl: 'https://stub.example/checkout',
        prepayId: 'stub-prepay-id',
      }),
      parseWebhook: vi.fn(),
      name: 'telebirr' as const,
    }),
  }));

  const serviceMod = await import('./service');
  settlePayment = serviceMod.settlePayment;
  failPayment = serviceMod.failPayment;
  scheduleRefund = serviceMod.scheduleRefund;
  processRefundRetries = serviceMod.processRefundRetries;
  const marketplaceMod = await import('../marketplace/service');
  marketplaceService = marketplaceMod.marketplaceService;
  const stateMod = await import('../subscription/state');
  transitionSubscription = stateMod.transitionSubscription;
}, 60_000);

afterAll(async () => {
  vi.doUnmock('@addis/db');
  vi.doUnmock('@addis/payments');
  await container.stop();
});

function addDays(d: Date, n: number) { const c = new Date(d); c.setDate(c.getDate() + n); return c; }

async function seedSubscription() {
  const [user] = await db.insert(schema.users).values({
    phone: `+251911${Math.random().toString(10).slice(2, 8)}`,
    name: 'Test Rider',
    passwordHash: 'hash',
    role: 'rider',
  }).returning();
  const [riderProfile] = await db.insert(schema.riderProfiles).values({ userId: user.id, homeArea: 'Bole', workArea: 'Merkato' }).returning();
  const [plan] = await db.insert(schema.subscriptionPlans).values({
    name: `Test Plan ${Date.now()}`, durationDays: 30, ridesIncluded: 10, priceETB: '500.00', description: 'Test',
  }).returning();
  const [route] = await db.insert(schema.routes).values({
    name: `Test Route ${Date.now()}`, origin: 'A', destination: 'B',
    distanceKm: 10, durationMin: 30, fare: '50.00',
    stops: [], polyline: [], originLatLng: [9, 38.7], destLatLng: [9.03, 38.75],
    morningWindow: { start: '06:30', end: '09:00' }, eveningWindow: { start: '16:30', end: '19:30' },
  }).returning();
  const [sub] = await db.insert(schema.subscriptions).values({
    riderId: riderProfile.id, planId: plan.id, routeId: route.id, status: 'pending_payment',
    startDate: new Date(), endDate: addDays(new Date(), 30),
  }).returning();
  const ref = `REF${createId()}`;
  const [payment] = await db.insert(schema.payments).values({
    riderId: riderProfile.id, subscriptionId: sub.id, amount: '500.00',
    method: 'telebirr', reference: ref, status: 'pending',
    retentionExpiresAt: addDays(new Date(), 365 * 7),
  }).returning();
  return { user, riderProfile, plan, route, sub, payment, ref };
}

describe('settlePayment', () => {
  it('transitions pending payment to completed and activates subscription', async () => {
    const { sub, payment, ref } = await seedSubscription();
    const result = await settlePayment(ref);
    expect(result).toBe(true);
    const [p] = await db.select().from(schema.payments).where(eq(schema.payments.id, payment.id));
    expect(p!.status).toBe('completed');
    const [s] = await db.select().from(schema.subscriptions).where(eq(schema.subscriptions.id, sub.id));
    expect(s!.status).toBe('active');
  });

  it('returns false on second call (idempotent)', async () => {
    const { ref } = await seedSubscription();
    const first = await settlePayment(ref);
    expect(first).toBe(true);
    const second = await settlePayment(ref);
    expect(second).toBe(false);
  });

  it('fails payment on amount mismatch', async () => {
    const { payment, ref } = await seedSubscription();
    const result = await settlePayment(ref, Money.fromDecimal('400.00'));
    expect(result).toBe(false);
    const [p] = await db.select().from(schema.payments).where(eq(schema.payments.id, payment.id));
    expect(p!.status).toBe('failed');
  });

  it('fails payment on zero amount', async () => {
    const { payment, ref } = await seedSubscription();
    const result = await settlePayment(ref, Money.ZERO);
    expect(result).toBe(false);
    const [p] = await db.select().from(schema.payments).where(eq(schema.payments.id, payment.id));
    expect(p!.status).toBe('failed');
  });

  it('no-ops on unknown reference', async () => {
    const result = await settlePayment(`NONEXISTENT_${createId()}`);
    expect(result).toBe(false);
  });
});

describe('processRefundRetries', () => {
  it('processes a due refund retry and marks it succeeded', async () => {
    const { payment, ref } = await seedSubscription();
    await settlePayment(ref);
    const [completed] = await db.select().from(schema.payments).where(eq(schema.payments.id, payment.id));
    const refundAmount = Money.fromDecimal('50.00');
    await scheduleRefund(payment.id, refundAmount, 'test refund');

    await db.update(schema.refundRetries).set({ nextAttemptAt: new Date(0) }).where(eq(schema.refundRetries.paymentId, payment.id));
    const result = await processRefundRetries(10);
    expect(result.processed).toBeGreaterThanOrEqual(1);
    const [retry] = await db.select().from(schema.refundRetries).where(eq(schema.refundRetries.paymentId, payment.id));
    expect(retry!.status).toBe('succeeded');
    const [p] = await db.select().from(schema.payments).where(eq(schema.payments.id, payment.id));
    expect(p!.refundAmount).toBe('50.00');
    expect(p!.status).toBe('partially_refunded');
  });

  it('accumulates refundAmount across multiple partial refunds', async () => {
    const { payment, ref } = await seedSubscription();
    await settlePayment(ref);
    await scheduleRefund(payment.id, Money.fromDecimal('30.00'), 'first partial');
    await db.update(schema.refundRetries).set({ nextAttemptAt: new Date(0) }).where(eq(schema.refundRetries.paymentId, payment.id));
    await processRefundRetries(10);
    await scheduleRefund(payment.id, Money.fromDecimal('20.00'), 'second partial');
    await db.update(schema.refundRetries).set({ nextAttemptAt: new Date(0) }).where(eq(schema.refundRetries.paymentId, payment.id));
    await processRefundRetries(10);
    const [p] = await db.select().from(schema.payments).where(eq(schema.payments.id, payment.id));
    expect(p!.refundAmount).toBe('50.00');
    expect(p!.status).toBe('partially_refunded');
  });

  it('marks payment refunded when total refund equals amount', async () => {
    const { payment, ref } = await seedSubscription();
    await settlePayment(ref);
    await scheduleRefund(payment.id, Money.fromDecimal('500.00'), 'full');
    await db.update(schema.refundRetries).set({ nextAttemptAt: new Date(0) }).where(eq(schema.refundRetries.paymentId, payment.id));
    await processRefundRetries(10);
    const [p] = await db.select().from(schema.payments).where(eq(schema.payments.id, payment.id));
    expect(p!.status).toBe('refunded');
    expect(p!.refundAmount).toBe('500.00');
  });
});

describe('marketplaceService.claim CAS guarantee', () => {
  async function seedClaimScenario() {
    const { user, riderProfile, sub, route } = await seedSubscription();

    const [activeSub] = await db.update(schema.subscriptions).set({ status: 'active' }).where(eq(schema.subscriptions.id, sub.id)).returning();
    const releaseDate = new Date(Date.now() + 86400000).toISOString().slice(0, 10);
    const [release] = await db.insert(schema.seatReleases).values({
      subscriptionId: sub.id, riderId: riderProfile.id, routeId: route.id, window: 'morning',
      releaseDate, refundAmount: '50.00',
      expiresAt: addDays(new Date(), 1),
    }).returning();

    const [claimerUser] = await db.insert(schema.users).values({
      phone: `+251911${Math.random().toString(10).slice(2, 8)}`,
      name: 'Claimer', passwordHash: 'hash', role: 'rider',
    }).returning();
    const [claimerProfile] = await db.insert(schema.riderProfiles).values({ userId: claimerUser.id, homeArea: 'Bole', workArea: 'Merkato' }).returning();
    return { release, claimerId: claimerProfile.id, route };
  }

  it('only one concurrent claimer wins', async () => {
    const { release, claimerId } = await seedClaimScenario();

    const results = await Promise.allSettled([
      marketplaceService.claim(claimerId, { seatReleaseId: release.id, paymentMethod: 'telebirr' }),
      marketplaceService.claim(claimerId, { seatReleaseId: release.id, paymentMethod: 'telebirr' }),
    ]);
    const successes = results.filter(r => r.status === 'fulfilled');
    const failures = results.filter(r => r.status === 'rejected');
    expect(successes.length).toBe(1);
    expect(failures.length).toBeGreaterThanOrEqual(1);

    const [r] = await db.select().from(schema.seatReleases).where(eq(schema.seatReleases.id, release.id));
    expect(r!.status).toBe('claimed');
  });

  it('rejects expired releases', async () => {
    const { release, claimerId } = await seedClaimScenario();
    await db.update(schema.seatReleases).set({ expiresAt: new Date(Date.now() - 1000) }).where(eq(schema.seatReleases.id, release.id));
    await expect(
      marketplaceService.claim(claimerId, { seatReleaseId: release.id, paymentMethod: 'telebirr' }),
    ).rejects.toThrow(/claimed|cancelled|expired/i);
  });

  it('rejects own release', async () => {
    const { riderProfile } = await seedSubscription();
    const releaseDate = new Date(Date.now() + 86400000).toISOString().slice(0, 10);
    const { route } = await seedClaimScenario();

    const sub = await db.select().from(schema.subscriptions).where(eq(schema.subscriptions.riderId, riderProfile.id)).limit(1);

    const [ownRelease] = await db.insert(schema.seatReleases).values({
      subscriptionId: sub[0]!.id, riderId: riderProfile.id, routeId: route.id, window: 'morning',
      releaseDate, refundAmount: '50.00', expiresAt: addDays(new Date(), 1),
    }).returning();
    await expect(
      marketplaceService.claim(riderProfile.id, { seatReleaseId: ownRelease.id, paymentMethod: 'telebirr' }),
    ).rejects.toThrow(/cannot claim your own/i);
  });
});

describe('transitionSubscription CAS race', () => {
  it('prevents double transition from concurrent calls', async () => {
    const { sub } = await seedSubscription();
    const results = await Promise.allSettled([
      transitionSubscription(db as any, sub.id, 'payment.settled'),
      transitionSubscription(db as any, sub.id, 'payment.failed'),
    ]);
    const fulfilled = results.filter(r => r.status === 'fulfilled');
    const rejected = results.filter(r => r.status === 'rejected');
    expect(fulfilled.length).toBe(1);
    expect(rejected.length).toBeGreaterThanOrEqual(1);
    const [s] = await db.select().from(schema.subscriptions).where(eq(schema.subscriptions.id, sub.id));

    expect(['active', 'cancelled']).toContain(s!.status);
  });

  it('rejects invalid transition', async () => {
    const { sub } = await seedSubscription();
    await db.update(schema.subscriptions).set({ status: 'active' }).where(eq(schema.subscriptions.id, sub.id));
    await expect(
      transitionSubscription(db as any, sub.id, 'payment.settled'),
    ).rejects.toThrow(/no transition|invalid transition/i);
  });

  it('side effects are declared', async () => {
    const { sub } = await seedSubscription();
    const result = await transitionSubscription(db as any, sub.id, 'payment.settled');
    expect(result.from).toBe('pending_payment');
    expect(result.to).toBe('active');
    expect(result.sideEffects).toContain('notify.payment_received');
  });
});

describe('scheduleRefund validation', () => {
  it('rejects refund on pending payment', async () => {
    const { payment, ref } = await seedSubscription();
    await expect(
      scheduleRefund(payment.id, Money.fromDecimal('50.00'), 'test'),
    ).rejects.toThrow(/only completed payments/i);
  });

  it('rejects refund exceeding payment amount', async () => {
    const { payment, ref } = await seedSubscription();
    await settlePayment(ref);
    await expect(
      scheduleRefund(payment.id, Money.fromDecimal('999999.00'), 'too much'),
    ).rejects.toThrow(/exceed payment amount/i);
  });

  it('rejects zero amount refund', async () => {
    const { payment, ref } = await seedSubscription();
    await settlePayment(ref);
    await expect(
      scheduleRefund(payment.id, Money.ZERO, 'zero'),
    ).rejects.toThrow(/must be positive/i);
  });
});

import { TypedOpenAPIHono } from '../../src/typed-hono';
import { timingSafeEqual } from 'node:crypto';
import { CRON_JOBS, withLock } from '../../src/cron-jobs';

export const cronRoutes = new TypedOpenAPIHono();

cronRoutes.use('*', async (c, next) => {
  const provided = c.req.header('Authorization')?.replace(/^Bearer\s+/i, '') ?? '';
  const expected = process.env.CRON_SECRET ?? '';
  if (expected.length < 32) return c.json({ error: { code: 'UNAUTHORIZED', message: 'Cron secret not configured', requestId: c.get('requestId') } }, 401);
  const ok = provided.length === expected.length && timingSafeEqual(Buffer.from(provided), Buffer.from(expected));
  if (!ok) return c.json({ error: { code: 'UNAUTHORIZED', message: 'Invalid cron secret', requestId: c.get('requestId') } }, 401);
  return await next();
});

for (const job of CRON_JOBS) {
  cronRoutes.post(`/${job.route}`, async (c) => {
    const result = await withLock(job.name, job.run);
    return c.json(result);
  });
}

cronRoutes.get('/', async (c) => {
  return c.json({
    data: CRON_JOBS.map((j) => ({
      name: j.name,
      route: `/api/v1/cron/${j.route}`,
      intervalMs: j.intervalMs,
    })),
  });
});

import { and, eq, gt, isNull } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { decodeCursor, encodeCursor } from '../../src/pagination';

export const catalogRepo = {
  async listRoutes(limit: number, cursor?: string) {
    const after = decodeCursor(cursor);
    const rows = await db.select().from(schema.routes)
      .where(and(eq(schema.routes.isActive, true), isNull(schema.routes.deletedAt), after ? gt(schema.routes.id, after) : undefined))
      .orderBy(schema.routes.id).limit(limit + 1);
    return paginate(rows, limit);
  },
  async listPlans() {
    return db.select().from(schema.subscriptionPlans).where(eq(schema.subscriptionPlans.isActive, true));
  },
  async listShuttles(limit: number, cursor?: string) {
    const after = decodeCursor(cursor);
    const rows = await db.select().from(schema.shuttles)
      .where(after ? gt(schema.shuttles.id, after) : undefined).orderBy(schema.shuttles.id).limit(limit + 1);
    return paginate(rows, limit);
  },
};

function paginate<T extends { id: string }>(rows: T[], limit: number) {
  const hasMore = rows.length > limit;
  const page = hasMore ? rows.slice(0, limit) : rows;
  return { rows: page, cursor: hasMore ? encodeCursor(page[page.length - 1]!.id) : undefined };
}

import { eq } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { NotFoundError, ConflictError } from '@addis/shared';
import { catalogRepo } from './repository';
import type { CreateRouteInput, UpdateRouteInput, CreatePlanInput, UpdatePlanInput, CreateShuttleInput, UpdateShuttleInput } from './types';

export const catalogService = {
  listRoutes: catalogRepo.listRoutes,
  listPlans: catalogRepo.listPlans,
  listShuttles: catalogRepo.listShuttles,

  async getRoute(id: string) {
    const [r] = await db.select().from(schema.routes).where(eq(schema.routes.id, id));
    if (!r) throw new NotFoundError('Route not found');
    return r;
  },

  async createRoute(input: z.infer<typeof CreateRouteInput>) {
    try {
      const [row] = await db.insert(schema.routes).values(input as any).returning();
      return row;
    } catch (e: any) { if (e.code === '23505') throw new ConflictError('Route name already exists'); throw e; }
  },
  async updateRoute(id: string, input: z.infer<typeof UpdateRouteInput>) {
    const [row] = await db.update(schema.routes).set({ ...input, updatedAt: new Date() } as any).where(eq(schema.routes.id, id)).returning();
    if (!row) throw new NotFoundError('Route not found');
    return row;
  },
  async deleteRoute(id: string) {
    const [row] = await db.update(schema.routes).set({ deletedAt: new Date(), isActive: false }).where(eq(schema.routes.id, id)).returning();
    if (!row) throw new NotFoundError('Route not found');
  },

  async createPlan(input: z.infer<typeof CreatePlanInput>) {
    try {
      const [row] = await db.insert(schema.subscriptionPlans).values(input as any).returning();
      return row;
    } catch (e: any) { if (e.code === '23505') throw new ConflictError('Plan name already exists'); throw e; }
  },
  async updatePlan(id: string, input: z.infer<typeof UpdatePlanInput>) {
    const [row] = await db.update(schema.subscriptionPlans).set({ ...input, updatedAt: new Date() } as any).where(eq(schema.subscriptionPlans.id, id)).returning();
    if (!row) throw new NotFoundError('Plan not found');
    return row;
  },
  async deletePlan(id: string) {
    const [row] = await db.update(schema.subscriptionPlans).set({ isActive: false }).where(eq(schema.subscriptionPlans.id, id)).returning();
    if (!row) throw new NotFoundError('Plan not found');
  },

  async createShuttle(input: z.infer<typeof CreateShuttleInput>) {
    try {
      const [row] = await db.insert(schema.shuttles).values(input as any).returning();
      return row;
    } catch (e: any) { if (e.code === '23505') throw new ConflictError('Plate number already registered'); throw e; }
  },
  async updateShuttle(id: string, input: z.infer<typeof UpdateShuttleInput>) {
    const [row] = await db.update(schema.shuttles).set({ ...input, updatedAt: new Date() } as any).where(eq(schema.shuttles.id, id)).returning();
    if (!row) throw new NotFoundError('Shuttle not found');
    return row;
  },
  async deleteShuttle(id: string) {
    const [row] = await db.update(schema.shuttles).set({ isActive: false }).where(eq(schema.shuttles.id, id)).returning();
    if (!row) throw new NotFoundError('Shuttle not found');
  },
};
import type { z } from 'zod';

import { z } from 'zod';
import { MoneyString, TimeOfDay } from '@addis/shared';

export const LatLng = z.tuple([z.number(), z.number()]);
export const CreateRouteInput = z.object({
  name: z.string().min(3), origin: z.string(), destination: z.string(),
  stops: z.array(z.object({ name: z.string(), lat: z.number(), lng: z.number() })).default([]),
  polyline: z.array(LatLng).default([]),
  originLatLng: LatLng, destLatLng: LatLng,
  distanceKm: z.number().positive(), durationMin: z.number().int().positive(),
  morningWindow: z.object({ start: TimeOfDay, end: TimeOfDay }),
  eveningWindow: z.object({ start: TimeOfDay, end: TimeOfDay }),
  fare: MoneyString, needsShuttle: z.boolean().default(true),
});
export const UpdateRouteInput = CreateRouteInput.partial().extend({ isActive: z.boolean().optional() });

export const CreatePlanInput = z.object({
  name: z.string().min(3), durationDays: z.number().int().positive(),
  ridesIncluded: z.number().int(), priceETB: MoneyString, description: z.string(),
  isPopular: z.boolean().default(false), isTrial: z.boolean().default(false),
});
export const UpdatePlanInput = CreatePlanInput.partial().extend({ isActive: z.boolean().optional() });

export const CreateShuttleInput = z.object({
  plateNumber: z.string(), model: z.string(), year: z.number().int(),
  vehicleType: z.enum(['coaster', 'minibus', 'van', 'sedan']),
  capacity: z.number().int().positive().default(14),
  contractorId: z.string().optional(),
});
export const UpdateShuttleInput = CreateShuttleInput.partial().extend({ isActive: z.boolean().optional() });

import { TypedOpenAPIHono } from '../../src/typed-hono';
import { catalogService } from './service';
import { CreateRouteInput, UpdateRouteInput, CreateShuttleInput, UpdateShuttleInput } from './types';

export const catalogRoutes = new TypedOpenAPIHono();

catalogRoutes.get('/routes', async (c) => {

