import { Redis } from '@upstash/redis';
import { loadEnv } from '@addis/shared';

const env = loadEnv();

if (!env.REDIS_URL && env.NODE_ENV === 'production') {
  throw new Error('REDIS_URL is required in production; refusing to start with in-memory fallback');
}

class InMemoryRedis {

  private store = new Map<string, { value: string; expiresAt?: number }>();

  private isExpired(entry: { expiresAt?: number } | undefined): boolean {
    return !!entry?.expiresAt && entry.expiresAt <= Date.now();
  }

  private cleanup(k: string) {
    const e = this.store.get(k);
    if (this.isExpired(e)) { this.store.delete(k); return undefined; }
    return e;
  }

  async set(k: string, v: string, opts?: { nx?: boolean; ex?: number }) {
    const existing = this.cleanup(k);
    if (opts?.nx && existing) return null;
    this.store.set(k, { value: v, ...(opts?.ex ? { expiresAt: Date.now() + opts.ex * 1000 } : {}) });
    return 'OK';
  }
  async incr(k: string) {
    const e = this.cleanup(k);
    const cur = Number(e?.value ?? 0) + 1;

    this.store.set(k, { value: String(cur), ...(e?.expiresAt ? { expiresAt: e.expiresAt } : {}) });
    return cur;
  }
  // FE-006: add get() for the profile-ID cache. The Upstash Redis client
  // has get(); the in-memory shim was missing it.
  async get(k: string): Promise<string | null> {
    const e = this.cleanup(k);
    if (!e) return null;
    return e.value;
  }
  async expire(k: string, sec: number) {
    const e = this.cleanup(k);
    if (e) e.expiresAt = Date.now() + sec * 1000;
  }
  async ttl(k: string): Promise<number> {
    const e = this.cleanup(k);
    if (!e) return -2;
    if (!e.expiresAt) return -1;
    return Math.max(0, Math.round((e.expiresAt - Date.now()) / 1000));
  }
  async hset(k: string, v: Record<string, unknown>) {
    const existing = this.cleanup(k);

    let prev: Record<string, unknown> = {};
    if (existing) {
      try { prev = JSON.parse(existing.value); } catch { prev = {}; }
    }
    const merged = { ...prev, ...v };
    this.store.set(k, { value: JSON.stringify(merged), ...(existing?.expiresAt ? { expiresAt: existing.expiresAt } : {}) });
  }
  async hgetall(k: string) {
    const e = this.cleanup(k);
    if (!e) return null;

    try { return JSON.parse(e.value); } catch { return null; }
  }
  async del(k: string) { this.store.delete(k); return 1; }
  async publish() {  }
  duplicate() { return this; }
  async subscribe() {  }
  disconnect() {}
}

export const redis: Redis = env.REDIS_URL
  ? new Redis({ url: env.REDIS_URL, token: process.env.REDIS_TOKEN ?? '' })
  : (new InMemoryRedis() as unknown as Redis);

import { describe, it, expect, beforeEach, vi } from 'vitest';

describe('In-memory Redis fallback', () => {
  let redis: any;

  beforeEach(async () => {
    vi.resetModules();

    vi.doMock('@addis/shared', () => ({
      loadEnv: () => ({
        REDIS_URL: undefined,
        NODE_ENV: 'test',
        LOG_LEVEL: 'error',
      }),
    }));
    ({ redis } = await import('./redis'));
  });

  it('incr() preserves TTL set by a prior set({ex}) call', async () => {
    await redis.set('rl:foo', '1', { ex: 600 });
    expect(await redis.ttl('rl:foo')).toBeGreaterThan(0);

    const before = await redis.ttl('rl:foo');
    await redis.incr('rl:foo');
    await redis.incr('rl:foo');
    await redis.incr('rl:foo');
    const after = await redis.ttl('rl:foo');

    expect(after).toBeGreaterThan(0);

    expect(Math.abs(before - after)).toBeLessThanOrEqual(2);
  });

  it('ttl() returns -2 for missing keys', async () => {
    expect(await redis.ttl('does-not-exist')).toBe(-2);
  });

  it('ttl() returns -1 for keys without an expiry', async () => {
    await redis.set('no-expiry', 'hello');
    expect(await redis.ttl('no-expiry')).toBe(-1);
  });

  it('set({nx:true}) refuses to overwrite an existing key', async () => {
    await redis.set('nx-key', 'first');
    const result = await redis.set('nx-key', 'second', { nx: true });
    expect(result).toBeNull();

    await redis.set('nx-key', 'first-confirmed');
    expect(await redis.ttl('nx-key')).toBe(-1);
  });

  it('hset preserves TTL from the original key', async () => {
    await redis.set('hash-key', 'initial', { ex: 300 });
    const ttlBefore = await redis.ttl('hash-key');
    expect(ttlBefore).toBeGreaterThan(0);

    await redis.hset('hash-key', { field1: 'value1' });
    const ttlAfter = await redis.ttl('hash-key');
    expect(ttlAfter).toBeGreaterThan(0);
    expect(Math.abs(ttlBefore - ttlAfter)).toBeLessThanOrEqual(2);

    const data = await redis.hgetall('hash-key');
    expect(data.field1).toBe('value1');
  });
});

import { S3Client, PutObjectCommand, DeleteObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { Readable } from 'node:stream';
import { loadEnv } from '@addis/shared';

const env = loadEnv();
const client = new S3Client({
  endpoint: env.S3_ENDPOINT, region: 'us-east-1', forcePathStyle: true,
  credentials: { accessKeyId: env.S3_ACCESS_KEY_ID, secretAccessKey: env.S3_SECRET_ACCESS_KEY },
});

export const s3 = {
  async putObject(key: string, body: Buffer, contentType: string) {

    await client.send(new PutObjectCommand({
      Bucket: env.S3_BUCKET, Key: key, Body: body, ContentType: contentType,
      ServerSideEncryption: 'AES256',
    }));
  },

  async getObject(key: string): Promise<Buffer | null> {
    try {
      const res = await client.send(new GetObjectCommand({ Bucket: env.S3_BUCKET, Key: key }));
      if (!res.Body) return null;
      const chunks: Uint8Array[] = [];
      for await (const chunk of res.Body as Readable) {
        chunks.push(typeof chunk === 'string' ? Buffer.from(chunk) : chunk);
      }
      return Buffer.concat(chunks);
    } catch (err: any) {
      if (err?.name === 'NoSuchKey' || err?.$metadata?.httpStatusCode === 404) return null;
      throw err;
    }
  },
  async deleteObject(key: string) {
    try {
      await client.send(new DeleteObjectCommand({ Bucket: env.S3_BUCKET, Key: key }));
    } catch (err) {

      console.error('[s3] deleteObject failed', { key, err: (err as Error).message });
      throw err;
    }
  },
  async presignGet(key: string, expiresInSec: number) {
    return getSignedUrl(client, new GetObjectCommand({ Bucket: env.S3_BUCKET, Key: key }), { expiresIn: expiresInSec });
  },
};

import pino from 'pino';
