import type { Logger } from 'pino';
import type { Context } from 'hono';

export interface Session {
  userId: string;
  role: import('@addis/shared').UserRole;
  phone: string;
  tosVersion: string | null;
  jti: string;

  impersonatedBy: string | null;
}

export interface Variables {
  requestId: string;
  logger: Logger;
  session: Session | undefined;
}

export function getSession(c: Context<{ Variables: Variables }>): Session {
  const session = c.get('session');
  if (!session) {
    throw new Error('getSession() called on a route without requireAuth/requireRole — check middleware ordering');
  }
  return session;
}

export function getOptionalSession(c: Context<{ Variables: Variables }>): Session | undefined {
  return c.get('session');
}

// SEC-002 / SEC-004: IP extraction.
//
// Round-1 code returned the RIGHTMOST entry of X-Forwarded-For, which is the
// value set by the LAST hop — fully attacker-controllable if the attacker can
// prepend their own XFF header. The correct entry is the LEFTMOST, but only
// when the immediate connection comes from a trusted proxy (e.g. Caddy,
// Vercel Edge). When no trusted proxy is configured, we fall back to the TCP
// peer address. When even that is unavailable (e.g. Vercel Edge runtime where
// `c.env` is the Vercel env, not a `{remoteAddr}` object), we return
// 'unknown' — but rate-limit callers MUST refuse to bucket on 'unknown' to
// avoid a single global bucket DoSing all anonymous users (SEC-004).

const TRUSTED_PROXY_CIDRS: readonly string[] = (() => {
  const raw = process.env.TRUSTED_PROXIES ?? '';
  return raw.split(',').map(s => s.trim()).filter(Boolean);
})();

/** Returns true if `ip` is within `cidr` (IPv4 only; IPv6 always returns false). */
function ipInCidr(ip: string, cidr: string): boolean {
  const [netRaw, prefixStr] = cidr.split('/');
  if (!netRaw) return false;
  const prefix = prefixStr ? parseInt(prefixStr, 10) : 32;
  if (Number.isNaN(prefix) || prefix < 0 || prefix > 32) return false;
  const parts = netRaw.split('.').map(p => parseInt(p, 10));
  const ipParts = ip.split('.').map(p => parseInt(p, 10));
  if (parts.length !== 4 || ipParts.length !== 4) return false;
  if (parts.some(p => Number.isNaN(p) || p < 0 || p > 255)) return false;
  if (ipParts.some(p => Number.isNaN(p) || p < 0 || p > 255)) return false;
  const netNum = (parts[0]! << 24) | (parts[1]! << 16) | (parts[2]! << 8) | parts[3]!;
  const ipNum = (ipParts[0]! << 24) | (ipParts[1]! << 16) | (ipParts[2]! << 8) | ipParts[3]!;
  const mask = prefix === 0 ? 0 : (0xFFFFFFFF << (32 - prefix)) >>> 0;
  return (netNum & mask) === (ipNum & mask);
}

function isTrustedProxy(ip: string): boolean {
  if (!TRUSTED_PROXY_CIDRS.length) return false;
  return TRUSTED_PROXY_CIDRS.some(cidr => ipInCidr(ip, cidr));
}

export function clientIp(c: { req: { header: (name: string) => string | undefined }; env?: any }): string {
  const remote = c.env?.remoteAddr?.address ?? c.env?.remoteAddr?.address;
  const xff = c.req.header('x-forwarded-for');

  // If we have a TCP peer address and it's NOT a trusted proxy, ignore XFF
  // entirely — the connection is direct from an untrusted source, so XFF is
  // attacker-controlled.
  if (remote && !isTrustedProxy(remote)) {
    return remote;
  }

  // Either there's no TCP peer (Edge runtime) or the peer is a trusted proxy.
  // Take the LEFTMOST XFF entry — that's the original client per RFC 7239.
  if (xff) {
    const parts = xff.split(',').map(s => s.trim()).filter(Boolean);
    if (parts.length > 0) {
      return parts[0]!;
    }
  }

  // Fall back to the TCP peer if available (e.g. trusted-proxy case where XFF
  // was stripped by the proxy).
  if (remote) return remote;

  // SEC-004: no IP determinable — callers MUST NOT bucket rate limits on this.
  return 'unknown';
}

/** Sentinel for "no IP could be determined". Rate-limit callers should refuse
 *  to bucket on this value to avoid a single global bucket DoSing all anon
 *  users. */
export const UNKNOWN_IP = 'unknown';

import { OpenAPIHono } from '@hono/zod-openapi';
import { requestContext } from './middleware/context';
import { errorHandler } from './middleware/error';
import { authMiddleware } from './middleware/auth';
import { idempotencyMiddleware } from './middleware/idempotency';
import { rateLimitMiddleware } from './middleware/rate-limit';
import { tosGateMiddleware } from './middleware/tos-gate';

import { csrfProtection } from './middleware/csrf';

import { httpRequestDuration } from '../modules/health/metrics';

import { catalogRoutes } from '../modules/catalog/routes';
import { identityRoutes } from '../modules/identity/routes';
import { subscriptionRoutes } from '../modules/subscription/routes';
import { marketplaceRoutes } from '../modules/marketplace/routes';
import { operationsRoutes } from '../modules/operations/routes';
import { supportRoutes } from '../modules/support/routes';
import { corporateRoutes } from '../modules/corporate/routes';
import { adminRoutes } from '../modules/admin/routes';
import { cronRoutes } from '../modules/cron/routes';
import { webhookRoutes } from '../modules/webhooks/routes';
import { engagementRoutes } from '../modules/engagement/routes';
import { healthRoutes } from '../modules/health/routes';
import { metricsRoutes } from '../modules/health/metrics';
import { accountRoutes } from '../modules/account/routes';
import { dashboardRoutes } from '../modules/dashboard/routes';
import { tosRoutes } from '../modules/tos/routes';

export const app = new OpenAPIHono();

app.use('*', requestContext);
app.use('*', authMiddleware);
app.use('*', csrfProtection);
app.use('*', rateLimitMiddleware);
app.use('*', tosGateMiddleware);
app.use('/api/v1/*', idempotencyMiddleware);

app.use('*', async (c, next) => {
  const start = Date.now();
  await next();
  const durationSec = (Date.now() - start) / 1000;
  const route = c.req.path
    .replace(/\/[a-z0-9]{24}/g, '/:id')
    .replace(/\/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/gi, '/:id');
  try {
    httpRequestDuration.labels(c.req.method, route, String(c.res.status)).observe(durationSec);
  } catch {}
});

app.route('/api/v1', catalogRoutes);
app.route('/api/v1/auth', identityRoutes);
app.route('/api/v1/subscriptions', subscriptionRoutes);
app.route('/api/v1', marketplaceRoutes);
app.route('/api/v1', operationsRoutes);
app.route('/api/v1', supportRoutes);
app.route('/api/v1', engagementRoutes);
app.route('/api/v1/corporate', corporateRoutes);
app.route('/api/v1/admin', adminRoutes);
app.route('/api/v1/cron', cronRoutes);
app.route('/api/v1/webhooks', webhookRoutes);
app.route('/api/v1', healthRoutes);
app.route('/api/v1', metricsRoutes);
app.route('/api/v1/account', accountRoutes);
app.route('/api/v1/dashboard', dashboardRoutes);
app.route('/api/v1/tos', tosRoutes);

app.onError(errorHandler);

app.doc('/api/v1/openapi.json', { openapi: '3.1.0', info: { title: 'Addis Ride API', version: '1.0.0' } });

export type App = typeof app;

import type { ErrorHandler } from 'hono';
import { toErrorEnvelope } from '@addis/shared';

export const errorHandler: ErrorHandler = (err, c) => {
  const requestId = c.get('requestId') ?? crypto.randomUUID();
  const { status, body } = toErrorEnvelope(err, requestId);
  if (status >= 500) c.get('logger')?.error({ err, requestId }, 'unhandled error');
  return c.json(body, status as any);
};

import type { MiddlewareHandler } from 'hono';
import { childLogger } from '../../infra/logger';

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

export const requestContext: MiddlewareHandler = async (c, next) => {

  const clientRequestId = c.req.header('x-request-id');
  const requestId = clientRequestId && UUID_RE.test(clientRequestId) ? clientRequestId : crypto.randomUUID();
  const start = Date.now();
  c.set('requestId', requestId);
  c.set('logger', childLogger(requestId, { route: c.req.path, method: c.req.method }));
  c.header('X-Request-Id', requestId);
  await next();
  c.get('logger').info({ statusCode: c.res.status, durationMs: Date.now() - start }, 'request completed');
};

import type { MiddlewareHandler } from 'hono';
import { getCookie, setCookie } from 'hono/cookie';
import { createHash, randomBytes, timingSafeEqual } from 'node:crypto';
import { ForbiddenError } from '@addis/shared';

const CSRF_COOKIE = '__Host-csrf-token';
const CSRF_HEADER = 'x-csrf-token';
const SAFE_METHODS = new Set(['GET', 'HEAD', 'OPTIONS']);

export const csrfProtection: MiddlewareHandler = async (c, next) => {
  if (SAFE_METHODS.has(c.req.method)) {

    if (!getCookie(c, CSRF_COOKIE)) {
      const token = randomBytes(32).toString('hex');
      setCookie(c, CSRF_COOKIE, token, {
        path: '/', secure: true, httpOnly: false, sameSite: 'Strict',
        maxAge: 86400,
      });
    }
    await next();
    return;
  }

  const sessionToken = getCookie(c, '__Secure-session-token');
  const bearer = c.req.header('Authorization');

  // SEC-005: only skip CSRF when the request uses bearer auth AND no session
  // cookie is present. If both are present (e.g. a browser session that also
  // sets a Bearer header via the SDK), the request is browser-like and CSRF
  // must be enforced — otherwise an XSS or cross-site navigation could
  // mutate state with the cookie-authenticated session while the bearer
  // bypasses CSRF.
  if (!sessionToken && bearer) {
    await next();
    return;
  }
  // If neither session cookie nor bearer is present, the request is anonymous
  // — CSRF doesn't apply (no session to abuse). State-changing routes are
  // gated by requireAuth, which will 401.
  if (!sessionToken && !bearer) {
    await next();
    return;
  }

  const cookieToken = getCookie(c, CSRF_COOKIE);
  const headerToken = c.req.header(CSRF_HEADER);

  if (!cookieToken || !headerToken) {
    throw new ForbiddenError('CSRF token missing');
  }

  const a = createHash('sha256').update(cookieToken).digest();
  const b = createHash('sha256').update(headerToken).digest();
  if (a.length !== b.length || !timingSafeEqual(a, b)) {
    throw new ForbiddenError('CSRF token mismatch');
  }

  await next();
};

import type { MiddlewareHandler } from 'hono';
import { getCookie } from 'hono/cookie';
import { identityService } from '../../modules/identity/service';
import { UnauthorizedError, ForbiddenError, TWO_FA_REQUIRED_ROLES, AppError } from '@addis/shared';

const TWO_FACTOR_CHECKED = Symbol('twoFactorChecked');
const PHONE_VERIFIED_CHECKED = Symbol('phoneVerifiedChecked');

async function assertTwoFactor(c: { get: (k: symbol) => unknown; set: (k: symbol, v: unknown) => void }, userId: string, role: string): Promise<void> {
  if (!TWO_FA_REQUIRED_ROLES.includes(role as any)) return;
  if (c.get(TWO_FACTOR_CHECKED)) return;
  const { db, schema } = await import('@addis/db');
  const { eq } = await import('drizzle-orm');
  const [user] = await db.select({ twoFactorEnabled: schema.users.twoFactorEnabled })
    .from(schema.users).where(eq(schema.users.id, userId));
  if (!user?.twoFactorEnabled) {
    throw new ForbiddenError('Two-factor authentication is required for this role. Enable it at /api/v1/auth/2fa/setup.');
  }
  c.set(TWO_FACTOR_CHECKED, true);
}

// SEC-009: privileged roles (corporate_admin, platform_admin) must have a
// verified phone before they can use session-gated routes. This prevents
// someone from creating a corporate_admin account with someone else's phone
// number and immediately accessing admin endpoints.
async function assertPhoneVerified(c: { get: (k: symbol) => unknown; set: (k: symbol, v: unknown) => void }, userId: string, role: string): Promise<void> {
  if (!TWO_FA_REQUIRED_ROLES.includes(role as any)) return;
  if (c.get(PHONE_VERIFIED_CHECKED)) return;
  const { db, schema } = await import('@addis/db');
  const { eq } = await import('drizzle-orm');
  const [user] = await db.select({ phoneVerified: schema.users.phoneVerified })
    .from(schema.users).where(eq(schema.users.id, userId));
  if (!user?.phoneVerified) {
    throw new ForbiddenError('Phone verification is required for this role. Verify your phone at /api/v1/auth/otp/send (purpose=signup_verification).');
  }
  c.set(PHONE_VERIFIED_CHECKED, true);
}

export const authMiddleware: MiddlewareHandler = async (c, next) => {
  const bearer = c.req.header('Authorization')?.replace(/^Bearer\s+/i, '');
  const cookieToken = getCookie(c, '__Secure-session-token');
  const token = bearer ?? cookieToken;

  // SEC-001: If a credential (bearer or session cookie) is present, a verification
  // failure must propagate as 401 — never silently downgrade to anonymous. Silent
  // downgrade allows:
  //   - revoked/expired tokens to bypass route guards on optional-auth routes
  //   - cross-site requests with a stolen/expired bearer to skip CSRF (since
  //     csrf.ts skips CSRF when a bearer is present)
  // Only swallow truly unexpected (non-AppError) throws, and even then log at
  // error level so ops can detect bugs.
  if (token) {
    try {
      const { user, jti, impersonatedBy } = await identityService.verifySession(token);
      c.set('session', {
        userId: user.id, role: user.role, phone: user.phone,
        tosVersion: user.tosVersion, jti, impersonatedBy,
      });
    } catch (err) {
      if (err instanceof AppError) {
        // Unauthorized / Forbidden — propagate so the route handler (or
        // requireAuth/requireRole) returns the correct status. Optional-auth
        // routes that don't call requireAuth will still see no session set,
        // but the explicit throw ensures the client knows their credential
        // is invalid.
        throw err;
      }
      // Non-AppError throws indicate a bug (DB connection, JWT lib, etc.).
      // Log and continue anonymous — better to serve the request degraded
      // than to 500 on a public route.
      const logger = c.get('logger');
      logger?.error({ err: (err as Error).message }, 'verifySession threw non-AppError; session left unset');
    }
  }
  await next();
};

export function requireRole(...roles: string[]): MiddlewareHandler {
  return async (c, next) => {
    const session = c.get('session');
    if (!session) throw new UnauthorizedError();
    if (!roles.includes(session.role)) {
      throw new ForbiddenError('Insufficient role');
    }
    await assertPhoneVerified(c, session.userId, session.role);
    await assertTwoFactor(c, session.userId, session.role);
    await next();
  };
}

export const requireAuth: MiddlewareHandler = async (c, next) => {
  if (!c.get('session')) throw new UnauthorizedError();
  await next();
};

import type { MiddlewareHandler } from 'hono';
import { createHash } from 'node:crypto';
import { eq } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { ConflictError } from '@addis/shared';

const PROCESSING_STATUS = 0;

const EXEMPT_PATHS = [
  /^\/api\/v1\/auth\//,
  /^\/api\/v1\/webhooks\//,
  /^\/api\/v1\/cron\//,
];

function isExempt(path: string): boolean {
  return EXEMPT_PATHS.some(re => re.test(path));
}

export const idempotencyMiddleware: MiddlewareHandler = async (c, next) => {
  if (c.req.method !== 'POST') return next();
  if (isExempt(c.req.path)) return next();
  const key = c.req.header('Idempotency-Key');
  if (!key) return next();

  if (key.length > 256) {
    return c.json({ error: { code: 'BAD_REQUEST', message: 'Idempotency-Key too long (max 256 chars)', requestId: c.get('requestId') } }, 400);
  }

  const session = c.get('session');

  // SEC-011: ignore Idempotency-Key for unauthenticated requests. The previous
  // code scoped anon keys to `anon:<requestId>:<key>` — since requestId is
  // per-request, this never deduplicated anything (each retry got a fresh
  // scope). Worse, it allowed an attacker to mint arbitrary idempotency
  // records by sending many requests with the same key. Now we just skip
  // idempotency for anon requests entirely — every non-exempt POST endpoint
  // requires auth, so this branch should rarely hit in practice.
  if (!session) {
    return next();
  }

  const scope = session.userId;
  const scopedKey = `${scope}:${key}`;

  const bodyText = await c.req.raw.clone().text();
  if (bodyText.length > 1_000_000) {
    return c.json({ error: { code: 'BAD_REQUEST', message: 'Request body too large for idempotency', requestId: c.get('requestId') } }, 413);
  }
  const bodyHash = createHash('sha256').update(bodyText).digest('hex');

  const claimed = await db.insert(schema.idempotencyRecords).values({
    key: scopedKey, userId: session.userId, method: c.req.method, path: c.req.path,
    requestBodyHash: bodyHash, responseStatus: PROCESSING_STATUS, responseBody: {},
    expiresAt: new Date(Date.now() + 24 * 3600_000),
  }).onConflictDoNothing().returning();

  if (claimed.length === 0) {
    const [existing] = await db.select().from(schema.idempotencyRecords).where(eq(schema.idempotencyRecords.key, scopedKey));
    if (!existing || existing.requestBodyHash !== bodyHash) {
      throw new ConflictError('Idempotency-Key reused with a different request body');
    }
    if (existing.responseStatus === PROCESSING_STATUS) {
      throw new ConflictError('A request with this Idempotency-Key is still being processed; retry shortly');
    }

    if (existing.responseStatus >= 200 && existing.responseStatus < 300) {
      return c.json(existing.responseBody as any, existing.responseStatus as any);
    }
    if (existing.responseStatus === 409) {
      return c.json(existing.responseBody as any, existing.responseStatus as any);
    }

    await db.delete(schema.idempotencyRecords).where(eq(schema.idempotencyRecords.key, scopedKey));
    throw new ConflictError('Previous request with this Idempotency-Key failed; retry now');
  }

  try {
    await next();
  } catch (err) {

    await db.transaction(async (tx) => {
      await tx.delete(schema.idempotencyRecords).where(eq(schema.idempotencyRecords.key, scopedKey));
    }).catch(() => {  });
    throw err;
  }

  const res = c.res.clone();
  if (res.status >= 200 && res.status < 300) {
    const responseBody = await res.json().catch(() => ({}));
    await db.update(schema.idempotencyRecords)
      .set({ responseStatus: res.status, responseBody })
      .where(eq(schema.idempotencyRecords.key, scopedKey));
  } else if (res.status === 409) {

    const responseBody = await res.json().catch(() => ({}));
    await db.update(schema.idempotencyRecords)
      .set({ responseStatus: res.status, responseBody })
      .where(eq(schema.idempotencyRecords.key, scopedKey));
  } else {

    await db.delete(schema.idempotencyRecords).where(eq(schema.idempotencyRecords.key, scopedKey));
  }
};

import type { MiddlewareHandler } from 'hono';
import { RateLimitError } from '@addis/shared';
import { redis } from '../../infra/redis';
import { clientIp, UNKNOWN_IP } from '../ip';

const RULES: { pattern: RegExp; limit: number; windowSec: number; keyFn: (c: any) => Promise<string> | string }[] = [

  { pattern: /\/auth\/token$/, limit: 10, windowSec: 60, keyFn: c => `ip:${clientIp(c)}` },
  { pattern: /\/auth\/register$/, limit: 5, windowSec: 3600, keyFn: c => `ip:${clientIp(c)}` },

  { pattern: /\/auth\/otp\/send$/, limit: 3, windowSec: 600, keyFn: c => `ip:${clientIp(c)}` },
  { pattern: /\/auth\/otp\/send$/, limit: 3, windowSec: 600, keyFn: c => bodyPhone(c) },
  { pattern: /\/auth\/otp\/verify$/, limit: 10, windowSec: 600, keyFn: c => bodyPhone(c) },

  { pattern: /\/auth\/password\/reset$/, limit: 3, windowSec: 600, keyFn: c => bodyPhone(c) },
  { pattern: /\/auth\/password\/reset\/confirm$/, limit: 5, windowSec: 600, keyFn: c => bodyPhone(c) },

  { pattern: /\/corporate\/onboard$/, limit: 5, windowSec: 3600, keyFn: c => `user:${c.get('session')?.userId ?? 'anon'}` },
  // SEC-012: rate-limit corporate invite generation to prevent an admin
  // (or attacker with a compromised admin session) from minting unlimited
  // invites.
  { pattern: /\/corporate\/invites$/, limit: 10, windowSec: 3600, keyFn: c => `user:${c.get('session')?.userId ?? 'anon'}` },

  { pattern: /\/corporate\/signup$/, limit: 3, windowSec: 3600, keyFn: c => `ip:${clientIp(c)}` },
  { pattern: /^\/api\/v1\/subscriptions$/, limit: 10, windowSec: 3600, keyFn: c => `user:${c.get('session')?.userId ?? 'anon'}` },
  { pattern: /\/refunds$/, limit: 5, windowSec: 3600, keyFn: c => `user:${c.get('session')?.userId ?? 'anon'}` },

  { pattern: /\/account\/export$/, limit: 3, windowSec: 600, keyFn: c => `user:${c.get('session')?.userId ?? 'anon'}` },
];
const DEFAULT_AUTHED = { limit: 100, windowSec: 60 };
const DEFAULT_ANON = { limit: 60, windowSec: 60 };

async function bodyPhone(c: any): Promise<string> {
  try {

    const contentLength = Number(c.req.header('content-length') ?? 0);
    if (contentLength > 100_000) return 'phone:unknown';
    const body = await c.req.raw.clone().json();
    return `phone:${body?.phone ?? 'unknown'}`;
  } catch {
    return 'phone:unknown';
  }
}

export const rateLimitMiddleware: MiddlewareHandler = async (c, next) => {
  const path = c.req.path;

  const matchingRules = RULES.filter(r => r.pattern.test(path));
  const session = c.get('session');

  // SEC-004: if a rule keys on IP and the IP is 'unknown' (e.g. direct-to-origin
  // on Vercel Edge with no XFF), refuse to bucket — a single global bucket would
  // let one attacker DoS all anonymous users. Authenticated requests are keyed on
  // userId and are unaffected.
  const ip = clientIp(c);
  const ipUnknown = ip === UNKNOWN_IP;

  let maxRetryAfter = 0;
  for (const rule of matchingRules) {
    let key: string;
    try {
      const rawKey = await rule.keyFn(c);
      // If the resolved key references the unknown IP, refuse to bucket.
      if (ipUnknown && rawKey.startsWith('ip:unknown')) {
        c.header('Retry-After', '60');
        throw new RateLimitError(60);
      }
      key = `rl:${path}:${rule.pattern.source}:${rawKey}`;
    } catch (err) {
      if (err instanceof RateLimitError) throw err;
      key = `rl:${path}:${rule.pattern.source}:unknown`;
    }
    const count = await redis.incr(key).catch(() => 1);
    if (count === 1) {

      await redis.expire(key, rule.windowSec).catch(() => {});
    }
    if (count > rule.limit) {
      const ttl = await redis.ttl(key).catch(() => rule.windowSec);
      if (ttl > maxRetryAfter) maxRetryAfter = ttl;
    }
  }
  if (maxRetryAfter > 0) {
    c.header('Retry-After', String(maxRetryAfter));
    throw new RateLimitError(maxRetryAfter);
  }

  if (matchingRules.length === 0) {
    const { limit, windowSec, keyFn } = session
      ? { ...DEFAULT_AUTHED, keyFn: (_c: any) => `user:${session.userId}` }
      : { ...DEFAULT_ANON, keyFn: (c: any) => `ip:${clientIp(c)}` };
    let key: string;
    try {
      const rawKey = await keyFn(c);
      if (ipUnknown && rawKey.startsWith('ip:unknown')) {
        // For the default anon bucket, also refuse to bucket on unknown IP —
        // return 429 rather than creating a global bucket.
        c.header('Retry-After', '60');
        throw new RateLimitError(60);
      }
      key = `rl:${path}:${rawKey}`;
    } catch (err) {
      if (err instanceof RateLimitError) throw err;
      key = `rl:${path}:unknown`;
    }
    const count = await redis.incr(key).catch(() => 1);
    if (count === 1) await redis.expire(key, windowSec).catch(() => {});
    const ttl = await redis.ttl(key).catch(() => windowSec);
    c.header('X-RateLimit-Reset', String(ttl));
    if (count > limit) {
      c.header('Retry-After', String(ttl));
      throw new RateLimitError(ttl);
    }
  }
  await next();
};

import type { MiddlewareHandler } from 'hono';
import { CURRENT_TOS_VERSION } from '@addis/shared';

const EXEMPT = [
  /^\/api\/v1\/tos/,
  /^\/api\/v1\/auth\/(login|token|logout|refresh|password|2fa|sessions|me)/,
  /^\/api\/v1\/account\/delete/,
  /^\/api\/v1\/health/,
  /^\/api\/v1\/webhooks/,
  /^\/api\/v1\/cron/,
];

export const tosGateMiddleware: MiddlewareHandler = async (c, next) => {
  const session = c.get('session');
  if (session && !EXEMPT.some(re => re.test(c.req.path))) {
    if (session.tosVersion !== CURRENT_TOS_VERSION) {
      c.header('Location', '/tos/accept');
      return c.json({ error: { code: 'TOS_UPDATE_REQUIRED', message: 'Please accept the updated Terms of Service', requestId: c.get('requestId') } }, 409);
    }
  }
  return await next();
};

import { eq } from 'drizzle-orm';
import { db, schema } from '@addis/db';
import { redis } from '../infra/redis';

// FE-006: profile-ID resolution cache. Every contractor/rider route resolves
// the profile ID from the user ID via a DB query — for a contractor reporting
// GPS every 10 seconds, that's 6 extra queries per minute per contractor.
// Cache the mapping in Redis for 5 minutes. Writes are rare (only on signup
// and role-change), so the cache can be invalidated lazily — a stale entry
// just means one extra DB query on the next miss after the profile is
// deleted, which falls through to the NotFoundError.

const TTL_SEC = 300;
const riderKey = (userId: string) => `profile:rider:${userId}`;
const contractorKey = (userId: string) => `profile:contractor:${userId}`;

export async function riderProfileIdFor(userId: string): Promise<string> {
  const key = riderKey(userId);
  const cached = await redis.get(key).catch(() => null);
  if (cached && typeof cached === 'string') return cached;
  const [profile] = await db.select({ id: schema.riderProfiles.id })
    .from(schema.riderProfiles).where(eq(schema.riderProfiles.userId, userId));
  if (!profile) throw new (await import('@addis/shared')).NotFoundError('Rider profile not found');
  await redis.set(key, profile.id, { ex: TTL_SEC }).catch(() => {});
  return profile.id;
}

export async function contractorProfileIdFor(userId: string): Promise<string> {
  const key = contractorKey(userId);
  const cached = await redis.get(key).catch(() => null);
  if (cached && typeof cached === 'string') return cached;
  const [profile] = await db.select({ id: schema.contractorProfiles.id })
    .from(schema.contractorProfiles).where(eq(schema.contractorProfiles.userId, userId));
  if (!profile) throw new (await import('@addis/shared')).NotFoundError('Contractor profile not found');
  await redis.set(key, profile.id, { ex: TTL_SEC }).catch(() => {});
  return profile.id;
}

// Invalidate on profile deletion / role change. Called from admin suspend,
// role change, and account deletion flows.
export async function invalidateProfileIdCache(opts: { userId?: string; rider?: boolean; contractor?: boolean }): Promise<void> {
  if (!opts.userId) return;
  const keys: string[] = [];
  if (opts.rider !== false) keys.push(riderKey(opts.userId));
  if (opts.contractor !== false) keys.push(contractorKey(opts.userId));
  await Promise.all(keys.map(k => redis.del(k).catch(() => {})));
}

